class WorkflowService:
    _ALERT_PRESET_ID_RE = re.compile(r"^[a-z0-9][a-z0-9_-]{1,63}$")
    _PROMPT_ID_RE = re.compile(r"^[a-z0-9][a-z0-9._-]{1,95}$")
    _ALERT_PRESET_ALLOWED_CATEGORIES = {
        "auth",
        "config",
        "permission",
        "network",
        "rate_limit",
        "validation",
        "unavailable",
        "other",
    }
    _ALERT_PRESET_ALLOWED_SEVERITIES = {"critical", "warning", "info"}

    def __init__(
        self,
        settings: Optional[Settings] = None,
        database: Optional[Database] = None,
        registry: Optional[SkillRegistry] = None,
    ):
        self.settings = settings or get_settings()
        self.database = database or Database(self.settings)
        self.registry = registry or get_skill_registry()
        self.coordinator = Coordinator(self.registry)
        self.connectors = ConnectorGateway(self.settings)
        self.job_queue: BaseJobQueue = build_job_queue(self.settings.queue_backend, self.database, self.settings.redis_url)

    def _default_alert_presets(self) -> list[AlertPreset]:
        now = utcnow()
        return [
            AlertPreset(
                preset_id="blocking_critical",
                name="blocking_critical",
                description="Critical blocking alerts only.",
                severities=["critical"],
                blocking=True,
                updated_at=now,
            ),
            AlertPreset(
                preset_id="auth_config",
                name="auth_config",
                description="Auth/config blockers.",
                categories=["auth", "config"],
                blocking=True,
                updated_at=now,
            ),
            AlertPreset(
                preset_id="network_recoverable",
                name="network_recoverable",
                description="Recoverable network/rate-limit alerts.",
                categories=["network", "rate_limit"],
                blocking=False,
                updated_at=now,
            ),
        ]

    def _alert_presets_path(self) -> Path:
        self.settings.state_dir.mkdir(parents=True, exist_ok=True)
        return self.settings.state_dir / "alert-presets.json"

    def _default_alert_rules(self) -> list[AlertRule]:
        now = utcnow()
        return [
            AlertRule(
                rule_id="default_auth_config_blocking",
                enabled=True,
                description="Auth/config/permission issues are always blocking and critical.",
                categories=["auth", "config", "permission"],
                set_blocking=True,
                set_severity="critical",
                priority=10,
                updated_at=now,
            ),
            AlertRule(
                rule_id="default_network_recoverable",
                enabled=True,
                description="Network and rate-limit failures are recoverable warnings.",
                categories=["network", "rate_limit"],
                set_blocking=False,
                set_severity="warning",
                priority=20,
                updated_at=now,
            ),
            AlertRule(
                rule_id="default_validation_warning",
                enabled=True,
                description="Validation failures are warnings by default.",
                categories=["validation"],
                set_blocking=False,
                set_severity="warning",
                priority=30,
                updated_at=now,
            ),
        ]

    def _alert_rules_path(self) -> Path:
        self.settings.state_dir.mkdir(parents=True, exist_ok=True)
        return self.settings.state_dir / "alert-rules.json"

    def _default_oncall_routes(self) -> list[OnCallRoute]:
        now = utcnow()
        blocking_targets = self._split_webhook_targets(self.settings.alert_blocking_webhook_urls)
        recoverable_targets = self._split_webhook_targets(self.settings.alert_recoverable_webhook_urls)
        common_targets = self._split_webhook_targets(self.settings.alert_webhook_urls)
        if not blocking_targets:
            blocking_targets = list(common_targets)
        if not recoverable_targets:
            recoverable_targets = list(common_targets)
        return [
            OnCallRoute(
                route_id="blocking_primary",
                enabled=True,
                description="Blocking alerts are routed to the primary on-call channel.",
                severities=["critical"],
                blocking=True,
                primary_channels=blocking_targets,
                escalation_channels=blocking_targets,
                escalation_after_minutes=15,
                rotation_members=[],
                rotation_timezone="UTC",
                rotation_handoff_hour=9,
                updated_at=now,
            ),
            OnCallRoute(
                route_id="recoverable_primary",
                enabled=True,
                description="Recoverable alerts go to a lower-noise operations channel.",
                severities=["warning", "info"],
                blocking=False,
                primary_channels=recoverable_targets,
                escalation_channels=[],
                escalation_after_minutes=30,
                rotation_members=[],
                rotation_timezone="UTC",
                rotation_handoff_hour=9,
                updated_at=now,
            ),
        ]

    def _oncall_policy_path(self) -> Path:
        self.settings.state_dir.mkdir(parents=True, exist_ok=True)
        return self.settings.state_dir / "alert-oncall-policy.json"

    def get_alert_presets(self, project_id: Optional[str] = None) -> AlertPresetCollection:
        defaults = self._default_alert_presets()
        normalized_project_id = str(project_id or "").strip() or None
        path = self._alert_presets_path()
        if not path.exists():
            presets = defaults
        else:
            try:
                payload = json.loads(path.read_text(encoding="utf-8"))
                collection = AlertPresetCollection.model_validate(payload)
                merged: dict[str, AlertPreset] = {item.preset_id: item for item in defaults}
                for preset in collection.presets:
                    merged[preset.preset_id] = preset
                presets = list(merged.values())
            except Exception:
                presets = defaults
        if normalized_project_id:
            presets = [preset for preset in presets if normalized_project_id in preset.project_ids]
        return AlertPresetCollection(project_id=normalized_project_id, presets=presets)

    def get_alert_rules(self) -> AlertRuleCollection:
        defaults = self._default_alert_rules()
        path = self._alert_rules_path()
        if not path.exists():
            return AlertRuleCollection(rules=defaults)
        try:
            payload = json.loads(path.read_text(encoding="utf-8"))
            collection = AlertRuleCollection.model_validate(payload)
            merged: dict[str, AlertRule] = {item.rule_id: item for item in defaults}
            for rule in collection.rules:
                merged[rule.rule_id] = rule
            return AlertRuleCollection(rules=sorted(merged.values(), key=lambda item: (item.priority, item.rule_id)))
        except Exception:
            return AlertRuleCollection(rules=defaults)

    def get_oncall_policy(self) -> OnCallPolicyCollection:
        defaults = self._default_oncall_routes()
        path = self._oncall_policy_path()
        if not path.exists():
            return OnCallPolicyCollection(routes=defaults, notes=["Default on-call routing is active."])
        try:
            payload = json.loads(path.read_text(encoding="utf-8"))
            collection = OnCallPolicyCollection.model_validate(payload)
            merged: dict[str, OnCallRoute] = {item.route_id: item for item in defaults}
            for route in collection.routes:
                merged[route.route_id] = route
            return OnCallPolicyCollection(routes=list(merged.values()), notes=list(collection.notes))
        except Exception:
            return OnCallPolicyCollection(routes=defaults, notes=["Default on-call routing is active due to policy parse failure."])

    def update_alert_presets(self, request: AlertPresetUpdateRequest) -> AlertPresetCollection:
        if len(request.presets) > 100:
            raise ValueError("Too many presets; maximum is 100")
        presets: list[AlertPreset] = []
        seen_ids: set[str] = set()
        seen_names: set[str] = set()
        for preset in request.presets:
            preset_id = (preset.preset_id or "").strip()
            if not preset_id:
                raise ValueError("presetId is required")
            if not self._ALERT_PRESET_ID_RE.match(preset_id):
                raise ValueError(
                    f"Invalid presetId '{preset_id}'; expected ^[a-z0-9][a-z0-9_-]{{1,63}}$"
                )
            if preset_id in seen_ids:
                raise ValueError(f"Duplicate presetId: {preset_id}")

            name = (preset.name or "").strip()
            if not name:
                raise ValueError(f"Preset '{preset_id}' name is required")
            if len(name) > 80:
                raise ValueError(f"Preset '{preset_id}' name exceeds 80 characters")
            normalized_name = name.casefold()
            if normalized_name in seen_names:
                raise ValueError(f"Duplicate preset name: {name}")

            description = (preset.description or "").strip()
            if len(description) > 280:
                raise ValueError(f"Preset '{preset_id}' description exceeds 280 characters")

            if len(preset.project_ids) > 200:
                raise ValueError(f"Preset '{preset_id}' has too many projectIds; maximum is 200")
            project_ids: list[str] = []
            for project_id in preset.project_ids:
                pid = (project_id or "").strip()
                if not pid:
                    raise ValueError(f"Preset '{preset_id}' contains empty projectId")
                if len(pid) > 128:
                    raise ValueError(f"Preset '{preset_id}' contains an overlong projectId")
                project_ids.append(pid)

            categories: list[str] = []
            category_seen: set[str] = set()
            for category in preset.categories:
                value = (category or "").strip()
                if not value:
                    continue
                if value not in self._ALERT_PRESET_ALLOWED_CATEGORIES:
                    raise ValueError(f"Preset '{preset_id}' contains unsupported category '{value}'")
                if value not in category_seen:
                    category_seen.add(value)
                    categories.append(value)

            severities: list[str] = []
            severity_seen: set[str] = set()
            for severity in preset.severities:
                value = (severity or "").strip()
                if not value:
                    continue
                if value not in self._ALERT_PRESET_ALLOWED_SEVERITIES:
                    raise ValueError(f"Preset '{preset_id}' contains unsupported severity '{value}'")
                if value not in severity_seen:
                    severity_seen.add(value)
                    severities.append(value)

            providers: list[str] = []
            provider_seen: set[str] = set()
            for provider in preset.providers:
                value = (provider or "").strip()
                if not value:
                    continue
                if len(value) > 64:
                    raise ValueError(f"Preset '{preset_id}' contains an overlong provider")
                if value not in provider_seen:
                    provider_seen.add(value)
                    providers.append(value)

            seen_ids.add(preset_id)
            seen_names.add(normalized_name)
            presets.append(
                preset.model_copy(
                    update={
                        "preset_id": preset_id,
                        "name": name,
                        "description": description,
                        "project_ids": project_ids,
                        "categories": categories,
                        "severities": severities,
                        "providers": providers,
                        "updated_at": utcnow(),
                    }
                )
            )
        collection = AlertPresetCollection(presets=presets)
        path = self._alert_presets_path()
        path.write_text(json.dumps(collection.model_dump(mode="json", by_alias=True), ensure_ascii=True, indent=2), encoding="utf-8")
        self._audit("workspace", "", "alerts.presets.updated", {"count": len(collection.presets)})
        return self.get_alert_presets()

    def update_alert_rules(self, request: AlertRuleUpdateRequest) -> AlertRuleCollection:
        rules: list[AlertRule] = []
        seen: set[str] = set()
        for item in request.rules:
            rule_id = (item.rule_id or "").strip()
            if not rule_id:
                raise ValueError("ruleId is required")
            if rule_id in seen:
                raise ValueError(f"Duplicate ruleId: {rule_id}")
            seen.add(rule_id)
            categories = [entry.strip() for entry in item.categories if str(entry).strip()]
            failure_codes = [entry.strip() for entry in item.failure_codes if str(entry).strip()]
            providers = [entry.strip() for entry in item.providers if str(entry).strip()]
            if not categories and not failure_codes and not providers:
                raise ValueError(f"Alert rule '{rule_id}' must include at least one matcher")
            rule = item.model_copy(
                update={
                    "rule_id": rule_id,
                    "categories": categories,
                    "failure_codes": failure_codes,
                    "providers": providers,
                    "priority": max(0, int(item.priority)),
                    "updated_at": utcnow(),
                }
            )
            rules.append(rule)
        collection = AlertRuleCollection(rules=sorted(rules, key=lambda current: (current.priority, current.rule_id)))
        path = self._alert_rules_path()
        path.write_text(json.dumps(collection.model_dump(mode="json", by_alias=True), ensure_ascii=True, indent=2), encoding="utf-8")
        self._audit("workspace", "", "alerts.rules.updated", {"count": len(collection.rules)})
        return self.get_alert_rules()

    def update_oncall_policy(self, request: OnCallPolicyUpdateRequest) -> OnCallPolicyCollection:
        routes: list[OnCallRoute] = []
        seen: set[str] = set()
        for item in request.routes:
            route_id = (item.route_id or "").strip()
            if not route_id:
                raise ValueError("routeId is required")
            if route_id in seen:
                raise ValueError(f"Duplicate routeId: {route_id}")
            seen.add(route_id)
            if len(route_id) > 64:
                raise ValueError(f"routeId '{route_id}' exceeds 64 characters")
            categories = [entry.strip() for entry in item.categories if str(entry).strip()]
            severities = [entry.strip() for entry in item.severities if str(entry).strip()]
            providers = [entry.strip() for entry in item.providers if str(entry).strip()]
            primary_channels = self._split_webhook_targets(",".join(item.primary_channels))
            escalation_channels = self._split_webhook_targets(",".join(item.escalation_channels))
            rotation_members = [entry.strip() for entry in item.rotation_members if str(entry).strip()]
            rotation_timezone = (item.rotation_timezone or "UTC").strip() or "UTC"
            try:
                ZoneInfo(rotation_timezone)
            except Exception:
                raise ValueError(f"Invalid rotationTimezone '{rotation_timezone}' for route '{route_id}'")
            rotation_handoff_hour = max(0, min(23, int(item.rotation_handoff_hour)))
            if not primary_channels:
                raise ValueError(f"On-call route '{route_id}' requires at least one primary channel")
            route = item.model_copy(
                update={
                    "route_id": route_id,
                    "description": (item.description or "").strip(),
                    "categories": categories,
                    "severities": severities,
                    "providers": providers,
                    "primary_channels": primary_channels,
                    "escalation_channels": escalation_channels,
                    "escalation_after_minutes": max(1, int(item.escalation_after_minutes)),
                    "rotation_members": rotation_members,
                    "rotation_timezone": rotation_timezone,
                    "rotation_handoff_hour": rotation_handoff_hour,
                    "updated_at": utcnow(),
                }
            )
            routes.append(route)
        collection = OnCallPolicyCollection(routes=sorted(routes, key=lambda current: current.route_id))
        path = self._oncall_policy_path()
        path.write_text(json.dumps(collection.model_dump(mode="json", by_alias=True), ensure_ascii=True, indent=2), encoding="utf-8")
        self._audit("workspace", "", "alerts.oncall.updated", {"count": len(collection.routes)})
        return self.get_oncall_policy()

    def _oncall_member_for_time(self, route: OnCallRoute, at_utc: datetime) -> Optional[str]:
        members = [item for item in route.rotation_members if item]
        if not members:
            return None
        try:
            tz = ZoneInfo(route.rotation_timezone or "UTC")
        except Exception:
            tz = ZoneInfo("UTC")
        local_now = at_utc.astimezone(tz)
        handoff_hour = max(0, min(23, int(route.rotation_handoff_hour)))
        anchor_date = local_now.date()
        if local_now.hour < handoff_hour:
            anchor_date = anchor_date - timedelta(days=1)
        member_index = anchor_date.toordinal() % len(members)
        return members[member_index]

    def _next_handoff_utc(self, route: OnCallRoute, at_utc: datetime) -> datetime:
        try:
            tz = ZoneInfo(route.rotation_timezone or "UTC")
        except Exception:
            tz = ZoneInfo("UTC")
        local_now = at_utc.astimezone(tz)
        handoff_hour = max(0, min(23, int(route.rotation_handoff_hour)))
        local_target = local_now.replace(hour=handoff_hour, minute=0, second=0, microsecond=0)
        if local_now >= local_target:
            local_target = local_target + timedelta(days=1)
        return local_target.astimezone(ZoneInfo("UTC"))

    def build_oncall_coverage_report(self, project_id: Optional[str] = None) -> OnCallCoverageReport:
        policy = self.get_oncall_policy()
        now = utcnow()
        normalized_project_id = str(project_id or "").strip() or None
        items: list[OnCallCoverageItem] = []
        rotating = 0
        for route in policy.routes:
            members = [item for item in route.rotation_members if item]
            rotation_enabled = len(members) > 0
            if rotation_enabled:
                rotating += 1
            current_member = self._oncall_member_for_time(route, now) if rotation_enabled else None
            next_handoff_at = self._next_handoff_utc(route, now) if rotation_enabled else None
            next_member = self._oncall_member_for_time(route, next_handoff_at + timedelta(minutes=1)) if next_handoff_at else None
            items.append(
                OnCallCoverageItem(
                    route_id=route.route_id,
                    enabled=route.enabled,
                    rotation_enabled=rotation_enabled,
                    rotation_timezone=route.rotation_timezone or "UTC",
                    rotation_handoff_hour=max(0, min(23, int(route.rotation_handoff_hour))),
                    member_count=len(members),
                    current_member=current_member,
                    next_member=next_member,
                    next_handoff_at=next_handoff_at,
                )
            )
        return OnCallCoverageReport(
            generated_at=now,
            project_id=normalized_project_id,
            route_count=len(items),
            rotating_route_count=rotating,
            items=items,
        )

    def _apply_alert_rule(self, item: ConnectorRemediationItem) -> tuple[bool, Literal["critical", "warning", "info"], Optional[str]]:
        blocking = item.blocking
        severity = item.alert_severity
        matched_rule: Optional[str] = None
        for rule in self.get_alert_rules().rules:
            if not rule.enabled:
                continue
            category_match = not rule.categories or item.category in set(rule.categories)
            code_match = not rule.failure_codes or item.failure_code in set(rule.failure_codes)
            provider_match = not rule.providers or bool(set(item.providers).intersection(set(rule.providers)))
            if category_match and code_match and provider_match:
                if rule.set_blocking is not None:
                    blocking = rule.set_blocking
                if rule.set_severity is not None:
                    severity = rule.set_severity
                matched_rule = rule.rule_id
                break
        return blocking, severity, matched_rule

    def bootstrap(self) -> None:
        self.database.create_all()
        if self.database.count_projects() == 0:
            self.seed_demo_workspace()

    def seed_demo_workspace(self) -> None:
        from .seed import DEMO_SITES

        for seed in DEMO_SITES:
            project = self.create_project(ProjectCreateRequest(name=seed.name, intake=seed.intake))
            bundle = self.run_analysis(project.project_id, seed.intake)
            if seed.auto_run and bundle.plan.auto_deploy_allowed:
                self.approve_task(bundle.task.task_id, ApprovalDecisionRequest(decision=ApprovalStatus.approved, actor="seed"))

    def create_project(self, request: ProjectCreateRequest) -> ProjectSummary:
        summary = self._project_summary_for_intake(request.name, request.intake, new_id("site"))
        with self.database.session() as session:
            row = ProjectRow(
                id=summary.project_id,
                name=summary.name,
                url=summary.url,
                site_class=summary.site_class.value,
                workspace=self.settings.default_workspace,
                input_json=json_dump(request.intake),
            )
            session.merge(row)
            self._seed_project_runtime_rows(session, summary.project_id, request.intake)
        self._audit(summary.project_id, "", "project.created", {"name": summary.name, "url": summary.url})
        return summary

    def list_projects(self) -> list[ProjectSummary]:
        with self.database.session() as session:
            project_rows = session.scalars(select(ProjectRow).order_by(ProjectRow.updated_at.desc())).all()
            return [self._project_summary_from_row(session, row) for row in project_rows]

    def list_tasks(self) -> list[TaskSummary]:
        with self.database.session() as session:
            rows = session.scalars(select(TaskRow).order_by(TaskRow.updated_at.desc())).all()
            return [self._task_summary_from_row(row) for row in rows]

    def list_project_runs(
        self,
        project_id: str,
        *,
        trigger: Optional[RunTrigger] = None,
        status: Optional[RunStatus] = None,
        limit: int = 0,
    ) -> list[ProjectRun]:
        with self.database.session() as session:
            query = select(ProjectRunRow).where(ProjectRunRow.project_id == project_id)
            if trigger is not None:
                query = query.where(ProjectRunRow.trigger == trigger.value)
            if status is not None:
                query = query.where(ProjectRunRow.status == status.value)
            query = query.order_by(ProjectRunRow.started_at.desc())
            if limit > 0:
                query = query.limit(max(1, min(int(limit), 500)))
            rows = session.scalars(query).all()
            task_rows = {
                row.id: row
                for row in session.scalars(select(TaskRow).where(TaskRow.id.in_([run.task_id for run in rows if run.task_id is not None]))).all()
                }
            return [self._run_from_row(row, task_rows.get(row.task_id)) for row in rows]

    def build_crawl_diagnostics_report(
        self,
        project_id: str,
        *,
        url: Optional[str] = None,
        fallback_title: Optional[str] = None,
        fallback_description: Optional[str] = None,
    ) -> CrawlDiagnosticsReport:
        with self.database.session() as session:
            project = session.get(ProjectRow, project_id)
            if project is None:
                raise ValueError(f"Unknown project: {project_id}")
            intake = self._project_intake(project)
            project_name = str(project.name or "").strip()
            project_url = str(project.url or "").strip()
        crawl_url = str(url or intake.url or project_url or "").strip()
        if not crawl_url:
            raise ValueError("crawl url is required")
        title = str(fallback_title or project_name or intake.site_name or crawl_url).strip() or crawl_url
        description = str(fallback_description or f"Diagnostics crawl for {project_name or title}").strip()
        snapshot, diagnostics = crawl_page_with_diagnostics(crawl_url, title, description)
        artifact_store = get_artifact_store()
        html_content = str(diagnostics.pop("_htmlContent", "") or "")
        screenshot_b64 = str(diagnostics.pop("_screenshotB64", "") or "")
        html_artifact_ref: Optional[str] = None
        html_artifact_path: Optional[str] = None
        screenshot_artifact_ref: Optional[str] = None
        screenshot_artifact_path: Optional[str] = None
        artifact_key = hashlib.sha1(crawl_url.encode("utf-8")).hexdigest()[:12]
        if html_content:
            html_artifact = artifact_store.write_text(
                f"crawl-diagnostics/{project_id}-{artifact_key}.html",
                html_content,
            )
            html_artifact_ref = html_artifact.artifact_ref
            html_artifact_path = html_artifact.path
        if screenshot_b64:
            screenshot_artifact = artifact_store.write_bytes(
                f"crawl-diagnostics/{project_id}-{artifact_key}.png",
                base64.b64decode(screenshot_b64),
            )
            screenshot_artifact_ref = screenshot_artifact.artifact_ref
            screenshot_artifact_path = screenshot_artifact.path
        notes: list[str] = []
        if snapshot is None:
            notes.append("No live snapshot returned; diagnostics reflect fallback or failure state.")
        if diagnostics.get("manualInterventionRequired"):
            notes.append("Manual intervention required because anti-bot escalation was detected.")
        if diagnostics.get("failureCode"):
            notes.append(f"failureCode={diagnostics['failureCode']}")
        report = CrawlDiagnosticsReport(
            generated_at=utcnow(),
            project_id=project_id,
            url=crawl_url,
            fallback_title=title,
            fallback_description=description,
            snapshot=snapshot,
            html_artifact_ref=html_artifact_ref,
            html_artifact_path=html_artifact_path,
            screenshot_artifact_ref=screenshot_artifact_ref,
            screenshot_artifact_path=screenshot_artifact_path,
            diagnostics=diagnostics,
            notes=notes,
        )
        self._audit(
            project_id,
            "",
            "crawl.diagnostics",
            {
                "url": crawl_url,
                "snapshot": bool(snapshot),
                "failureCode": diagnostics.get("failureCode"),
                "manualInterventionRequired": diagnostics.get("manualInterventionRequired"),
                "htmlArtifactRef": html_artifact_ref,
                "screenshotArtifactRef": screenshot_artifact_ref,
            },
        )
        return report

    def build_crawl_diagnostics_history_report(
        self,
        project_id: Optional[str] = None,
        *,
        limit: int = 10,
    ) -> CrawlDiagnosticsHistoryReport:
        bounded_limit = max(1, min(int(limit), 100))
        normalized_project_id = str(project_id or "").strip() or None
        with self.database.session() as session:
            query = select(AuditRow).where(AuditRow.action == "crawl.diagnostics")
            if normalized_project_id:
                query = query.where(AuditRow.project_id == normalized_project_id)
            rows = session.scalars(query.order_by(AuditRow.created_at.desc()).limit(bounded_limit)).all()
        entries: list[CrawlDiagnosticsHistoryEntry] = []
        for row in rows:
            payload = dict(row.payload_json or {})
            created_at = row.created_at
            if created_at.tzinfo is None:
                created_at = created_at.replace(tzinfo=timezone.utc)
            entries.append(
                CrawlDiagnosticsHistoryEntry(
                    audit_id=row.id,
                    project_id=row.project_id,
                    url=str(payload.get("url") or ""),
                    snapshot_available=bool(payload.get("snapshot")),
                    failure_code=str(payload.get("failureCode") or "") or None,
                    manual_intervention_required=bool(payload.get("manualInterventionRequired")),
                    html_artifact_ref=str(payload.get("htmlArtifactRef") or "") or None,
                    screenshot_artifact_ref=str(payload.get("screenshotArtifactRef") or "") or None,
                    created_at=created_at,
                    actor=str(row.actor or "") or None,
                )
            )
        return CrawlDiagnosticsHistoryReport(project_id=normalized_project_id, total=len(entries), entries=entries)

    def list_project_runtime_route_history(
        self,
        project_id: str,
        *,
        limit: int = 20,
    ) -> ProjectRuntimeRouteHistoryReport:
        route_limit = max(1, min(int(limit), 100))
        runs = self.list_project_runs(project_id, limit=route_limit)
        route_runs = [
            run
            for run in runs
            if run.runtime_route_request_path or run.runtime_route_request_method or run.runtime_route_ready or run.runtime_route_summary
        ]
        runtime_ready_count = sum(1 for run in route_runs if run.runtime_route_ready)
        preview_only_count = max(0, len(route_runs) - runtime_ready_count)
        return ProjectRuntimeRouteHistoryReport(
            project_id=project_id,
            total=len(route_runs),
            runtime_ready_count=runtime_ready_count,
            preview_only_count=preview_only_count,
            entries=route_runs[:route_limit],
        )

    def list_workspace_runtime_route_history(self, *, limit: int = 20, project_id: Optional[str] = None) -> WorkspaceRuntimeRouteHistoryReport:
        history_limit = max(1, min(int(limit), 100))
        normalized_project_id = str(project_id or "").strip() or None
        items: list[WorkspaceRuntimeRouteHistoryItem] = []

        def parse_summary(value: Optional[str]) -> dict[str, str]:
            parsed: dict[str, str] = {}
            if not value:
                return parsed
            for segment in str(value).split("|"):
                if "=" not in segment:
                    continue
                key, raw_value = segment.split("=", 1)
                key = key.strip()
                raw_value = raw_value.strip()
                if key:
                    parsed[key] = raw_value
            return parsed

        with self.database.session() as session:
            project_query = select(ProjectRow).order_by(ProjectRow.updated_at.desc())
            if normalized_project_id:
                project_query = project_query.where(ProjectRow.id == normalized_project_id)
            project_rows = session.scalars(project_query).all()
            project_names = {row.id: row.name for row in project_rows}
        for project_row in project_rows:
            recent_runs = self.list_project_runs(project_row.id, limit=history_limit)
            for run in recent_runs:
                if not (run.runtime_route_request_path or run.runtime_route_request_method or run.runtime_route_ready or run.runtime_route_summary):
                    continue
                summary_fields = parse_summary(run.runtime_route_summary)
                execution_mode = run.runtime_route_execution_mode or summary_fields.get("executionMode")
                execution_action = run.runtime_route_execution_action or summary_fields.get("executionAction")
                execution_reason = run.runtime_route_execution_reason or summary_fields.get("executionReason")
                execution_entrypoint = run.runtime_route_execution_entrypoint or summary_fields.get("executionEntrypoint") or run.runtime_route_request_path
                items.append(
                    WorkspaceRuntimeRouteHistoryItem(
                        project_id=run.project_id,
                        project_name=project_names.get(run.project_id, run.project_id),
                        run_id=run.run_id,
                        task_id=run.task_id,
                        trigger=run.trigger.value,
                        status=run.status.value,
                        started_at=run.started_at,
                        runtime_ready=run.runtime_route_ready,
                        runtime_summary=run.runtime_route_summary,
                        request_path=run.runtime_route_request_path,
                        request_method=run.runtime_route_request_method,
                        experiment_variant=summary_fields.get("experimentVariant", "unassigned"),
                        localization_cluster=summary_fields.get("localizationCluster", "unassigned"),
                        gateway_provider_name=summary_fields.get("gateway", "local"),
                        gateway_route_provider_name=run.gateway_route_provider_name or summary_fields.get("gatewayRouteProvider"),
                        gateway_route_fallback_provider_name=run.gateway_route_fallback_provider_name or summary_fields.get("gatewayRouteFallbackProvider"),
                        gateway_route_priority=(
                            int(run.gateway_route_priority)
                            if run.gateway_route_priority is not None
                            else (
                                int(summary_fields["gatewayRoutePriority"])
                                if summary_fields.get("gatewayRoutePriority") not in {None, "", "n/a"}
                                else None
                            )
                        ),
                        gateway_ready=bool(run.runtime_route_ready),
                        execution_mode=execution_mode if execution_mode in {"runtime", "preview", "blocked"} else None,
                        execution_action=execution_action if execution_action in {"serve_runtime", "serve_preview", "block"} else None,
                        execution_reason=execution_reason,
                        execution_entrypoint=execution_entrypoint,
                    )
                )
        items.sort(key=lambda item: item.started_at, reverse=True)
        items = items[:history_limit]
        runtime_ready_count = sum(1 for item in items if item.runtime_ready)
        preview_only_count = max(0, len(items) - runtime_ready_count)
        return WorkspaceRuntimeRouteHistoryReport(
            project_id=normalized_project_id,
            total=len(items),
            runtime_ready_count=runtime_ready_count,
            preview_only_count=preview_only_count,
            items=items,
        )

    def list_project_metrics(self, project_id: str, *, limit: int = 20, offset: int = 0) -> MetricHistoryReport:
        page_limit = max(1, min(100, int(limit)))
        page_offset = max(0, int(offset))
        with self.database.session() as session:
            project = session.get(ProjectRow, project_id)
            if project is None:
                raise ValueError(f"Unknown project: {project_id}")
            query = select(MetricSnapshotRow).where(MetricSnapshotRow.project_id == project_id).order_by(MetricSnapshotRow.created_at.desc())
            rows = session.scalars(query.offset(page_offset).limit(page_limit)).all()
            total = session.query(MetricSnapshotRow).filter(MetricSnapshotRow.project_id == project_id).count()
            snapshots: list[MetricSnapshot] = []
            for row in rows:
                payload = dict(row.snapshot_json or {})
                payload.setdefault("projectId", row.project_id)
                payload.setdefault("taskId", row.task_id)
                payload.setdefault("sourceStatus", row.source_status_json or {})
                payload.setdefault("externalMetrics", row.external_metrics_json or {})
                payload.setdefault("createdAt", row.created_at)
                snapshots.append(MetricSnapshot.model_validate(payload))
            return MetricHistoryReport(
                project_id=project_id,
                total=total,
                limit=page_limit,
                offset=page_offset,
                snapshots=snapshots,
            )

    def get_project_connections(self, project_id: str) -> ProjectConnections:
        with self.database.session() as session:
            project = session.get(ProjectRow, project_id)
            if project is None:
                raise ValueError(f"Unknown project: {project_id}")
            intake = self._project_intake(project)
            connections = self._load_project_connections(session, project_id, intake)
            state = self._load_project_state(session, project_id, intake)
            return ProjectConnections(project_id=project_id, state=state, connections=connections)

    def get_project_connection_evidence(self, project_id: str) -> ProjectConnectionEvidenceReport:
        with self.database.session() as session:
            project = session.get(ProjectRow, project_id)
            if project is None:
                raise ValueError(f"Unknown project: {project_id}")
            intake = self._project_intake(project)
            connections = self._load_project_connections(session, project_id, intake)
            entries: list[ProjectConnectionEvidenceEntry] = []
            real_count = 0
            fallback_count = 0
            unconfigured_count = 0
            for connection in connections:
                normalized = self._apply_connection_runtime_semantics(connection.model_copy())
                details = dict(normalized.details or {})
                auth_source = str(details.get("authSource") or "").strip() or None
                fallback_reason = str(details.get("fallbackReason") or "").strip() or None
                latency_ms = details.get("latencyMs") if isinstance(details.get("latencyMs"), (int, float)) else None
                if normalized.provider_mode == "real":
                    real_count += 1
                elif normalized.provider_mode == "fallback":
                    fallback_count += 1
                else:
                    unconfigured_count += 1
                entries.append(
                    ProjectConnectionEvidenceEntry(
                        provider=normalized.provider,
                        label=normalized.label,
                        status=normalized.status,
                        provider_mode=normalized.provider_mode,
                        strict_eligible=normalized.strict_eligible,
                        auth_source=auth_source,
                        fallback_reason=fallback_reason,
                        latency_ms=int(latency_ms) if latency_ms is not None else None,
                        recent_evidence_label=normalized.recent_evidence_label,
                        recent_evidence_ref=normalized.recent_evidence_ref,
                        recent_evidence_at=normalized.recent_evidence_at,
                        last_success_at=normalized.last_success_at,
                        last_error_at=normalized.last_error_at,
                    )
                )
            return ProjectConnectionEvidenceReport(
                project_id=project_id,
                total=len(entries),
                real_count=real_count,
                fallback_count=fallback_count,
                unconfigured_count=unconfigured_count,
                entries=entries,
            )

    def get_workspace_connection_evidence(
        self,
        *,
        provider: Optional[ConnectorKind] = None,
        mode: Optional[Literal["real", "fallback", "unconfigured"]] = None,
        strict_only: bool = False,
        limit: int = 500,
        project_id: Optional[str] = None,
    ) -> WorkspaceConnectionEvidenceReport:
        normalized_project_id = str(project_id or "").strip() or None
        with self.database.session() as session:
            project_query = select(ProjectRow).order_by(ProjectRow.created_at.desc())
            if normalized_project_id:
                project_query = project_query.where(ProjectRow.id == normalized_project_id)
            projects = session.scalars(project_query).all()
            entries: list[WorkspaceConnectionEvidenceEntry] = []
            provider_buckets: dict[ConnectorKind, dict[str, Any]] = {}
            real_count = 0
            fallback_count = 0
            unconfigured_count = 0
            for project in projects:
                intake = self._project_intake(project)
                connections = self._load_project_connections(session, project.id, intake)
                for connection in connections:
                    normalized = self._apply_connection_runtime_semantics(connection.model_copy())
                    if provider is not None and normalized.provider != provider:
                        continue
                    if mode is not None and normalized.provider_mode != mode:
                        continue
                    if strict_only and not normalized.strict_eligible:
                        continue
                    details = dict(normalized.details or {})
                    auth_source = str(details.get("authSource") or "").strip() or None
                    fallback_reason = str(details.get("fallbackReason") or "").strip() or None
                    latency_ms = details.get("latencyMs") if isinstance(details.get("latencyMs"), (int, float)) else None
                    if normalized.provider_mode == "real":
                        real_count += 1
                    elif normalized.provider_mode == "fallback":
                        fallback_count += 1
                    else:
                        unconfigured_count += 1
                    bucket = provider_buckets.setdefault(
                        normalized.provider,
                        {
                            "total": 0,
                            "real": 0,
                            "fallback": 0,
                            "unconfigured": 0,
                            "projects": set(),
                            "recentEvidenceLabel": None,
                            "recentEvidenceRef": None,
                            "recentEvidenceAt": None,
                        },
                    )
                    bucket["total"] += 1
                    if normalized.provider_mode == "real":
                        bucket["real"] += 1
                    elif normalized.provider_mode == "fallback":
                        bucket["fallback"] += 1
                    else:
                        bucket["unconfigured"] += 1
                    bucket["projects"].add(project.id)
                    if normalized.recent_evidence_at and (
                        bucket["recentEvidenceAt"] is None or normalized.recent_evidence_at > bucket["recentEvidenceAt"]
                    ):
                        bucket["recentEvidenceAt"] = normalized.recent_evidence_at
                        bucket["recentEvidenceLabel"] = normalized.recent_evidence_label
                        bucket["recentEvidenceRef"] = normalized.recent_evidence_ref
                    entries.append(
                        WorkspaceConnectionEvidenceEntry(
                            project_id=project.id,
                            project_name=project.name,
                            project_url=project.url,
                            provider=normalized.provider,
                            label=normalized.label,
                            status=normalized.status,
                            provider_mode=normalized.provider_mode,
                            strict_eligible=normalized.strict_eligible,
                            auth_source=auth_source,
                            fallback_reason=fallback_reason,
                            latency_ms=int(latency_ms) if latency_ms is not None else None,
                            recent_evidence_label=normalized.recent_evidence_label,
                            recent_evidence_ref=normalized.recent_evidence_ref,
                            recent_evidence_at=normalized.recent_evidence_at,
                            last_success_at=normalized.last_success_at,
                            last_error_at=normalized.last_error_at,
                        )
                    )
                    if len(entries) >= max(1, limit):
                        break
                if len(entries) >= max(1, limit):
                    break
            provider_summaries = [
                WorkspaceConnectionEvidenceProviderSummary(
                    provider=provider,
                    total=bucket["total"],
                    real_count=bucket["real"],
                    fallback_count=bucket["fallback"],
                    unconfigured_count=bucket["unconfigured"],
                    project_count=len(bucket["projects"]),
                    recent_evidence_label=bucket["recentEvidenceLabel"],
                    recent_evidence_ref=bucket["recentEvidenceRef"],
                    recent_evidence_at=bucket["recentEvidenceAt"],
                )
                for provider, bucket in sorted(provider_buckets.items(), key=lambda item: item[0].value)
            ]
            return WorkspaceConnectionEvidenceReport(
                project_id=normalized_project_id,
                total=len(entries),
                real_count=real_count,
                fallback_count=fallback_count,
                unconfigured_count=unconfigured_count,
                entries=entries,
                provider_summaries=provider_summaries,
            )

    def get_project_connectors_health(self, project_id: str) -> ConnectorsHealthResult:
        with self.database.session() as session:
            project = session.get(ProjectRow, project_id)
            if project is None:
                raise ValueError(f"Unknown project: {project_id}")
            intake = self._project_intake(project)
            connections = self._load_project_connections(session, project_id, intake)
            return self._build_project_connectors_health(project_id, intake, connections)

    def get_workspace_connectors_health(self, project_id: Optional[str] = None) -> WorkspaceConnectorsHealthReport:
        normalized_project_id = str(project_id or "").strip() or None
        with self.database.session() as session:
            project_query = select(ProjectRow).order_by(ProjectRow.created_at.desc())
            if normalized_project_id:
                project_query = project_query.where(ProjectRow.id == normalized_project_id)
            projects = session.scalars(project_query).all()
            items: list[ConnectorProjectHealthItem] = []
            degraded = 0
            unavailable = 0
            total_connections = 0
            real_connections = 0
            fallback_connections = 0
            unconfigured_connections = 0
            strict_eligible_connections = 0
            strict_gap_connections = 0
            anti_bot_blocked_connection_count = 0
            anti_bot_manual_intervention_count = 0
            read_provider_set = {
                ConnectorKind.search_console,
                ConnectorKind.ga4,
                ConnectorKind.ad_network,
                ConnectorKind.sitemap,
                ConnectorKind.playwright,
                ConnectorKind.trend,
                ConnectorKind.news,
                ConnectorKind.qa,
            }
            write_provider_set = {
                ConnectorKind.github,
                ConnectorKind.cms,
                ConnectorKind.script_api,
            }
            read_connection_count = 0
            read_real_connection_count = 0
            read_strict_eligible_count = 0
            read_real_last_evidence_at: Optional[datetime] = None
            write_connection_count = 0
            write_real_connection_count = 0
            write_strict_eligible_count = 0
            write_real_last_evidence_at: Optional[datetime] = None
            provider_counts: dict[ConnectorKind, dict[str, int]] = {}
            for project in projects:
                intake = self._project_intake(project)
                connections = self._load_project_connections(session, project.id, intake)
                health = self._build_project_connectors_health(project.id, intake, connections)
                if health.connection_health == ConnectionHealth.degraded:
                    degraded += 1
                elif health.connection_health == ConnectionHealth.unavailable:
                    unavailable += 1
                total_connections += health.total_connection_count
                real_connections += health.real_connection_count
                fallback_connections += health.fallback_connection_count
                unconfigured_connections += health.unconfigured_connection_count
                strict_eligible_connections += health.strict_eligible_count
                strict_gap_connections += max(health.total_connection_count - health.strict_eligible_count, 0)
                for connection in health.connections:
                    normalized = self._apply_connection_runtime_semantics(connection)
                    bucket = provider_counts.setdefault(
                        normalized.provider,
                        {
                            "total": 0,
                            "affectedProjects": set(),
                            "strictReadyProjects": set(),
                            "blockingProjects": set(),
                            "affectedSamples": [],
                            "strictReadySamples": [],
                            "blockingSamples": [],
                            "failureCodes": [],
                            "blockingReasons": [],
                            "real": 0,
                            "fallback": 0,
                            "unconfigured": 0,
                            "strictEligible": 0,
                            "antiBotBlocked": 0,
                            "manualInterventionRequired": 0,
                        },
                    )
                    bucket["total"] += 1
                    bucket["affectedProjects"].add(project.id)
                    if len(bucket["affectedSamples"]) < 5 and not any(sample["projectId"] == project.id for sample in bucket["affectedSamples"]):
                        bucket["affectedSamples"].append({"projectId": project.id, "name": project.name, "url": project.url})
                    if normalized.provider_mode == "real":
                        bucket["real"] += 1
                    elif normalized.provider_mode == "fallback":
                        bucket["fallback"] += 1
                    else:
                        bucket["unconfigured"] += 1
                    if bool(normalized.details.get("antiBotBlocked")):
                        anti_bot_blocked_connection_count += 1
                        bucket["antiBotBlocked"] += 1
                    if bool(normalized.details.get("manualInterventionRequired")):
                        anti_bot_manual_intervention_count += 1
                        bucket["manualInterventionRequired"] += 1
                    if normalized.provider in read_provider_set:
                        read_connection_count += 1
                        if normalized.provider_mode == "real":
                            read_real_connection_count += 1
                            if normalized.recent_evidence_at and (
                                read_real_last_evidence_at is None or normalized.recent_evidence_at > read_real_last_evidence_at
                            ):
                                read_real_last_evidence_at = normalized.recent_evidence_at
                    elif normalized.provider in write_provider_set:
                        write_connection_count += 1
                        if normalized.provider_mode == "real":
                            write_real_connection_count += 1
                            if normalized.recent_evidence_at and (
                                write_real_last_evidence_at is None or normalized.recent_evidence_at > write_real_last_evidence_at
                            ):
                                write_real_last_evidence_at = normalized.recent_evidence_at
                    if normalized.strict_eligible:
                        bucket["strictEligible"] += 1
                        if normalized.provider in read_provider_set:
                            read_strict_eligible_count += 1
                        elif normalized.provider in write_provider_set:
                            write_strict_eligible_count += 1
                        bucket["strictReadyProjects"].add(project.id)
                        if len(bucket["strictReadySamples"]) < 5 and not any(sample["projectId"] == project.id for sample in bucket["strictReadySamples"]):
                            bucket["strictReadySamples"].append({"projectId": project.id, "name": project.name, "url": project.url})
                    else:
                        bucket["blockingProjects"].add(project.id)
                        if len(bucket["blockingSamples"]) < 5 and not any(sample["projectId"] == project.id for sample in bucket["blockingSamples"]):
                            bucket["blockingSamples"].append({"projectId": project.id, "name": project.name, "url": project.url})
                        failure_code = str(normalized.details.get("errorCode") or "").strip()
                        blocking_reason = str(normalized.blocking_reason or normalized.details.get("fallbackReason") or "").strip()
                        if failure_code:
                            bucket["failureCodes"].append(failure_code)
                        if blocking_reason:
                            bucket["blockingReasons"].append(blocking_reason)
                items.append(
                    ConnectorProjectHealthItem(
                        project_id=project.id,
                        name=project.name,
                        url=project.url,
                        checked_at=health.checked_at,
                        connection_health=health.connection_health,
                        total_connection_count=health.total_connection_count,
                        real_connection_count=health.real_connection_count,
                        fallback_connection_count=health.fallback_connection_count,
                        unconfigured_connection_count=health.unconfigured_connection_count,
                        strict_eligible_count=health.strict_eligible_count,
                        issue_count=len(health.issues),
                        issues=health.issues,
                    )
                )
            provider_coverage = []
            for provider, counts in sorted(provider_counts.items(), key=lambda item: item[0].value):
                primary_failure_code = Counter(counts["failureCodes"]).most_common(1)[0][0] if counts["failureCodes"] else None
                primary_failure_category = self._failure_category(primary_failure_code) if primary_failure_code else None
                suggested_action_path, suggested_action_label = self._provider_suggested_action(
                    primary_failure_category,
                    primary_failure_code,
                    provider,
                )
                provider_coverage.append(
                    ConnectorProviderCoverageItem(
                        provider=provider,
                        total_connection_count=counts["total"],
                        affected_project_count=len(counts["affectedProjects"]),
                        strict_ready_project_count=len(counts["strictReadyProjects"]),
                        strict_ready_project_rate_percent=round(
                            (len(counts["strictReadyProjects"]) / len(counts["affectedProjects"]) * 100.0),
                            1,
                        )
                        if counts["affectedProjects"]
                        else 0.0,
                        blocking_project_count=len(counts["blockingProjects"]),
                        blocking_project_rate_percent=round(
                            (len(counts["blockingProjects"]) / len(counts["affectedProjects"]) * 100.0),
                            1,
                        )
                        if counts["affectedProjects"]
                        else 0.0,
                        strict_gap_count=max(counts["total"] - counts["strictEligible"], 0),
                        real_coverage_percent=round((counts["real"] / counts["total"] * 100.0), 1) if counts["total"] else 0.0,
                        strict_coverage_percent=round((counts["strictEligible"] / counts["total"] * 100.0), 1)
                        if counts["total"]
                        else 0.0,
                        blocking_rate_percent=round((len(counts["blockingProjects"]) / len(counts["affectedProjects"]) * 100.0), 1)
                        if counts["affectedProjects"]
                        else 0.0,
                        affected_project_ids=sorted(counts["affectedProjects"])[:5],
                        strict_ready_project_ids=sorted(counts["strictReadyProjects"])[:5],
                        blocking_project_ids=sorted(counts["blockingProjects"])[:5],
                        affected_projects=list(counts["affectedSamples"]),
                        strict_ready_projects=list(counts["strictReadySamples"]),
                        blocking_projects=list(counts["blockingSamples"]),
                        primary_failure_category=primary_failure_category,
                        primary_failure_code=primary_failure_code,
                        primary_blocking_reason=(Counter(counts["blockingReasons"]).most_common(1)[0][0] if counts["blockingReasons"] else None),
                        suggested_action_path=suggested_action_path,
                        suggested_action_label=suggested_action_label,
                        real_connection_count=counts["real"],
                        fallback_connection_count=counts["fallback"],
                        unconfigured_connection_count=counts["unconfigured"],
                        strict_eligible_count=counts["strictEligible"],
                        anti_bot_blocked_count=counts["antiBotBlocked"],
                        manual_intervention_required_count=counts["manualInterventionRequired"],
                    )
                )
            top_blocking_providers = sorted(
                provider_coverage,
                key=lambda item: (-item.blocking_project_count, -item.unconfigured_connection_count, item.provider.value),
            )[:5]
            top_strict_gap_providers = sorted(
                provider_coverage,
                key=lambda item: (-item.strict_gap_count, -item.blocking_project_count, item.provider.value),
            )[:5]
            top_strict_ready_providers = sorted(
                provider_coverage,
                key=lambda item: (-item.strict_coverage_percent, -item.strict_eligible_count, item.provider.value),
            )[:5]
            zero_real_providers = [item.provider for item in provider_coverage if item.real_connection_count == 0]
            real_providers = [item.provider for item in provider_coverage if item.real_connection_count > 0]
            zero_strict_providers = [item.provider for item in provider_coverage if item.strict_eligible_count == 0]
            strict_ready_providers = [item.provider for item in provider_coverage if item.strict_ready_project_count > 0]
            partial_strict_providers = [
                item.provider
                for item in provider_coverage
                if item.strict_ready_project_count > 0 and not (item.total_connection_count > 0 and item.strict_eligible_count == item.total_connection_count)
            ]
            fully_strict_providers = [
                item.provider for item in provider_coverage if item.total_connection_count > 0 and item.strict_eligible_count == item.total_connection_count
            ]
            return WorkspaceConnectorsHealthReport(
                generated_at=utcnow(),
                project_id=normalized_project_id,
                project_count=len(items),
                degraded_project_count=degraded,
                unavailable_project_count=unavailable,
                total_connection_count=total_connections,
                real_connection_count=real_connections,
                fallback_connection_count=fallback_connections,
                unconfigured_connection_count=unconfigured_connections,
                strict_eligible_count=strict_eligible_connections,
                strict_gap_count=strict_gap_connections,
                anti_bot_blocked_connection_count=anti_bot_blocked_connection_count,
                anti_bot_manual_intervention_count=anti_bot_manual_intervention_count,
                read_connection_count=read_connection_count,
                read_real_connection_count=read_real_connection_count,
                read_strict_eligible_count=read_strict_eligible_count,
                read_real_coverage_percent=round((read_real_connection_count / read_connection_count * 100.0), 1)
                if read_connection_count
                else 0.0,
                read_strict_coverage_percent=round((read_strict_eligible_count / read_connection_count * 100.0), 1)
                if read_connection_count
                else 0.0,
                read_real_last_evidence_at=read_real_last_evidence_at,
                write_connection_count=write_connection_count,
                write_real_connection_count=write_real_connection_count,
                write_strict_eligible_count=write_strict_eligible_count,
                write_real_coverage_percent=round((write_real_connection_count / write_connection_count * 100.0), 1)
                if write_connection_count
                else 0.0,
                write_strict_coverage_percent=round((write_strict_eligible_count / write_connection_count * 100.0), 1)
                if write_connection_count
                else 0.0,
                write_real_last_evidence_at=write_real_last_evidence_at,
                real_provider_count=len(real_providers),
                real_provider_rate_percent=round((len(real_providers) / len(provider_coverage) * 100.0), 1) if provider_coverage else 0.0,
                zero_real_provider_count=len(zero_real_providers),
                zero_real_provider_rate_percent=round((len(zero_real_providers) / len(provider_coverage) * 100.0), 1) if provider_coverage else 0.0,
                zero_real_providers=zero_real_providers,
                zero_strict_provider_count=len(zero_strict_providers),
                zero_strict_provider_rate_percent=round((len(zero_strict_providers) / len(provider_coverage) * 100.0), 1) if provider_coverage else 0.0,
                zero_strict_providers=zero_strict_providers,
                strict_ready_provider_count=len(strict_ready_providers),
                strict_ready_provider_rate_percent=round((len(strict_ready_providers) / len(provider_coverage) * 100.0), 1) if provider_coverage else 0.0,
                strict_ready_providers=strict_ready_providers,
                partial_strict_provider_count=len(partial_strict_providers),
                partial_strict_provider_rate_percent=round((len(partial_strict_providers) / len(provider_coverage) * 100.0), 1) if provider_coverage else 0.0,
                partial_strict_providers=partial_strict_providers,
                fully_strict_provider_count=len(fully_strict_providers),
                fully_strict_provider_rate_percent=round((len(fully_strict_providers) / len(provider_coverage) * 100.0), 1) if provider_coverage else 0.0,
                fully_strict_providers=fully_strict_providers,
                provider_coverage=provider_coverage,
                top_blocking_providers=top_blocking_providers,
                top_strict_gap_providers=top_strict_gap_providers,
                top_strict_ready_providers=top_strict_ready_providers,
                projects=items,
            )

    def _build_project_connectors_health(
        self,
        project_id: str,
        intake: SiteIntake,
        connections: list[ProjectConnection],
    ) -> ConnectorsHealthResult:
        market_evidence = self._collect_market_evidence(
            intake,
            providers={ConnectorKind.trend, ConnectorKind.news, ConnectorKind.qa},
        )
        connection_map = {connection.provider: connection for connection in connections}
        for item in market_evidence:
            existing = connection_map.get(item.provider)
            if existing is None:
                connection_map[item.provider] = ProjectConnection(
                    connection_id=new_id("conn"),
                    provider=item.provider,
                    label=item.provider.value.replace("_", " ").title(),
                    enabled=True,
                    status=item.status,
                    config={"sourceType": item.source_type},
                    details=dict(item.details),
                    provenance=list(item.provenance),
                    last_checked_at=item.checked_at,
                    last_synced_at=item.checked_at,
                )
            else:
                existing.status = item.status
                existing.details = dict(item.details)
                existing.provenance = list(item.provenance)
                existing.last_checked_at = item.checked_at
                existing.last_synced_at = item.checked_at
        all_connections = [self._apply_connection_runtime_semantics(item) for item in connection_map.values()]
        health = self._connection_health_from_connections(all_connections)
        read_provider_set = {
            ConnectorKind.search_console,
            ConnectorKind.ga4,
            ConnectorKind.ad_network,
            ConnectorKind.sitemap,
            ConnectorKind.playwright,
            ConnectorKind.trend,
            ConnectorKind.news,
            ConnectorKind.qa,
        }
        write_provider_set = {
            ConnectorKind.github,
            ConnectorKind.cms,
            ConnectorKind.script_api,
        }
        read_real_last_evidence_at: Optional[datetime] = None
        write_real_last_evidence_at: Optional[datetime] = None
        for connection in all_connections:
            if connection.provider_mode != "real" or connection.recent_evidence_at is None:
                continue
            if connection.provider in read_provider_set and (
                read_real_last_evidence_at is None or connection.recent_evidence_at > read_real_last_evidence_at
            ):
                read_real_last_evidence_at = connection.recent_evidence_at
            if connection.provider in write_provider_set and (
                write_real_last_evidence_at is None or connection.recent_evidence_at > write_real_last_evidence_at
            ):
                write_real_last_evidence_at = connection.recent_evidence_at
        issues: list[str] = []
        for connection in all_connections:
            fallback_reason = str(connection.details.get("fallbackReason") or "").strip()
            error_code = str(connection.details.get("errorCode") or "").strip()
            if fallback_reason:
                if error_code:
                    issues.append(f"{connection.label}: {error_code} ({fallback_reason})")
                else:
                    issues.append(f"{connection.label}: {fallback_reason}")
            elif connection.status in {ConnectorStatus.synthetic, ConnectorStatus.missing_credentials, ConnectorStatus.unavailable, ConnectorStatus.error}:
                if error_code:
                    issues.append(f"{connection.label}: {error_code}")
                else:
                    issues.append(f"{connection.label}: {connection.status.value}")
        counts = self._connection_mode_counts(all_connections)
        anti_bot_blocked_count = sum(1 for item in all_connections if bool(item.details.get("antiBotBlocked")))
        manual_intervention_required_count = sum(
            1 for item in all_connections if bool(item.details.get("manualInterventionRequired"))
        )
        return ConnectorsHealthResult(
            project_id=project_id,
            connection_health=health,
            checked_at=utcnow(),
            total_connection_count=counts["total"],
            real_connection_count=counts["real"],
            fallback_connection_count=counts["fallback"],
            unconfigured_connection_count=counts["unconfigured"],
            strict_eligible_count=counts["strictEligible"],
            anti_bot_blocked_count=anti_bot_blocked_count,
            manual_intervention_required_count=manual_intervention_required_count,
            read_real_last_evidence_at=read_real_last_evidence_at,
            write_real_last_evidence_at=write_real_last_evidence_at,
            connections=all_connections,
            issues=issues,
        )

    def update_project_connections(self, project_id: str, request: ProjectConnectionsUpdateRequest) -> ProjectConnections:
        with self.database.session() as session:
            project = session.get(ProjectRow, project_id)
            if project is None:
                raise ValueError(f"Unknown project: {project_id}")
            intake = self._project_intake(project)
            existing = self._load_project_connections(session, project_id, intake)
            merged = self._merge_project_connections(existing, request.connections, project_id, intake)
            self._persist_project_connections(session, project_id, merged)
            state_row = self._upsert_state_row(
                session,
                project_id,
                auto_cruise_enabled=request.auto_cruise_enabled,
                sync_interval_minutes=request.sync_interval_minutes,
            )
            state_row.connection_health = self._connection_health_from_connections(merged).value
            state_row.updated_at = utcnow()
            session.add(state_row)
        self._audit(
            project_id,
            "",
            "connections.updated",
            {"autoCruiseEnabled": request.auto_cruise_enabled, "syncIntervalMinutes": request.sync_interval_minutes},
        )
        return ProjectConnections(
            project_id=project_id,
            state=self._state_from_row(state_row),
            connections=[self._apply_connection_runtime_semantics(item) for item in merged],
        )

    def test_project_connections(self, project_id: str) -> ProjectConnectionsTestResult:
        with trace_span("connector.test", {"projectId": project_id}):
            with self.database.session() as session:
                project = session.get(ProjectRow, project_id)
                if project is None:
                    raise ValueError(f"Unknown project: {project_id}")
                intake = self._project_intake(project)
                connections = self._load_project_connections(session, project_id, intake)
                updated, issues, health = self.connectors.test(project_id, intake, connections)
                self._persist_project_connections(session, project_id, updated)
                state_row = self._upsert_state_row(session, project_id)
                state_row.connection_health = health.value
                state_row.updated_at = utcnow()
                session.add(state_row)
            normalized_connections = [self._apply_connection_runtime_semantics(item) for item in updated]
            strict_mode = bool(self.settings.strict_providers)
            strict_blockers = self._collect_strict_connection_blockers(
                intake=intake,
                connections=normalized_connections,
            )
            strict_blocked = strict_mode and len(strict_blockers) > 0
            strict_gap_count = len(strict_blockers)
            effective_health = ConnectionHealth.unavailable if strict_blocked else health
            effective_issues = list(issues)
            if strict_blocked:
                effective_issues.append(
                    "strictProviders=true and connection test found non-strict providers: "
                    + ", ".join(strict_blockers[:5])
                )
            self._audit_connector_evidence(project_id, "", report_evidence=None, connections=updated)
            self._audit(
                project_id,
                "",
                "connections.tested",
                {
                    "issues": effective_issues,
                    "health": effective_health.value,
                    "strictMode": strict_mode,
                    "strictBlocked": strict_blocked,
                    "strictGapCount": strict_gap_count,
                    "strictBlockers": strict_blockers,
                },
            )
            set_span_attributes(
                {
                    "connector.health": effective_health.value,
                    "connector.count": len(updated),
                    "connector.strict_mode": strict_mode,
                    "connector.strict_blocked": strict_blocked,
                    "connector.strict_gap_count": strict_gap_count,
                }
            )
            return ProjectConnectionsTestResult(
                project_id=project_id,
                connection_health=effective_health,
                connections=normalized_connections,
                issues=effective_issues,
                strict_mode=strict_mode,
                strict_blocked=strict_blocked,
                strict_gap_count=strict_gap_count,
                strict_blockers=strict_blockers,
            )

    def _collect_strict_connection_blockers(
        self,
        *,
        intake: SiteIntake,
        connections: list[ProjectConnection],
    ) -> list[str]:
        blockers: list[str] = []
        strict_read_providers = {ConnectorKind.search_console, ConnectorKind.ga4, ConnectorKind.playwright, ConnectorKind.sitemap}
        normalized_map = {item.provider: item for item in connections}
        for item in connections:
            if not item.enabled or item.strict_eligible:
                continue
            auth_source = str(item.details.get("authSource") or "").strip().lower()
            explicitly_configured = auth_source not in {"", "missing", "fallback"}
            if item.provider in strict_read_providers and explicitly_configured:
                blockers.append(
                    f"{item.provider.value}:{item.blocking_reason or item.provider_mode or item.status.value}"
                )
        required_write_provider: Optional[ConnectorKind] = None
        if intake.repo_url:
            required_write_provider = ConnectorKind.github
        elif intake.cms_name:
            required_write_provider = ConnectorKind.cms
        elif any(
            item.provider == ConnectorKind.script_api
            and item.enabled
            and (
                item.config.get("endpoint")
                or item.config.get("scriptEndpoint")
                or item.config.get("endpoints")
                or item.config.get("scriptEndpoints")
            )
            for item in connections
        ):
            required_write_provider = ConnectorKind.script_api
        if required_write_provider is not None:
            required_connection = normalized_map.get(required_write_provider)
            if required_connection is None:
                blockers.append(f"{required_write_provider.value}:required write provider missing")
            elif not required_connection.strict_eligible:
                blockers.append(
                    f"{required_write_provider.value}:{required_connection.blocking_reason or required_connection.provider_mode or required_connection.status.value}"
                )
        return blockers

    def refresh_project_connections(
        self,
        project_id: str,
        request: Optional[ProjectConnectionsRefreshRequest] = None,
    ) -> ProjectConnectionsRefreshResult:
        request = request or ProjectConnectionsRefreshRequest()
        with self.database.session() as session:
            project = session.get(ProjectRow, project_id)
            if project is None:
                raise ValueError(f"Unknown project: {project_id}")
            intake = self._project_intake(project)
            connections = self._load_project_connections(session, project_id, intake)
        enabled_providers = [item.provider for item in connections if item.enabled]
        selected_providers = [item for item in request.providers if item in enabled_providers] if request.providers else enabled_providers
        max_providers = max(1, int(request.max_providers))
        provider_candidates = selected_providers[:max_providers]
        results: list[ConnectorRefreshResult] = []
        skipped_providers: list[ConnectorKind] = []
        for provider in provider_candidates:
            try:
                results.append(self.refresh_project_connector(project_id, provider))
            except ValueError:
                skipped_providers.append(provider)
        for provider in selected_providers:
            if provider not in provider_candidates and provider not in skipped_providers:
                skipped_providers.append(provider)
        with self.database.session() as session:
            project = session.get(ProjectRow, project_id)
            if project is None:
                raise ValueError(f"Unknown project: {project_id}")
            intake = self._project_intake(project)
            merged_connections = [self._apply_connection_runtime_semantics(item) for item in self._load_project_connections(session, project_id, intake)]
            health = self._connection_health_from_connections(merged_connections)
        strict_mode = bool(self.settings.strict_providers)
        strict_blockers = self._collect_strict_connection_blockers(intake=intake, connections=merged_connections)
        strict_gap_count = len(strict_blockers)
        strict_blocked = strict_mode and strict_gap_count > 0
        effective_health = ConnectionHealth.unavailable if strict_blocked else health
        report = ProjectConnectionsRefreshResult(
            project_id=project_id,
            refreshed_count=len(results),
            skipped_providers=skipped_providers,
            results=results,
            connection_health=effective_health,
            strict_mode=strict_mode,
            strict_blocked=strict_blocked,
            strict_gap_count=strict_gap_count,
            strict_blockers=strict_blockers,
        )
        self._audit(
            project_id,
            "",
            "connector.project.refresh.all",
            {
                "refreshedCount": report.refreshed_count,
                "skippedProviders": [item.value for item in report.skipped_providers],
                "selectedProviders": [item.value for item in selected_providers],
                "maxProviders": max_providers,
                "strictMode": strict_mode,
                "strictBlocked": strict_blocked,
                "strictGapCount": strict_gap_count,
                "strictBlockers": strict_blockers,
                "connectionHealth": effective_health.value,
            },
        )
        return report

    def refresh_project_connector(self, project_id: str, provider: ConnectorKind) -> ConnectorRefreshResult:
        with trace_span("connector.refresh", {"projectId": project_id, "provider": provider.value}):
            with self.database.session() as session:
                project = session.get(ProjectRow, project_id)
                if project is None:
                    raise ValueError(f"Unknown project: {project_id}")
                intake = self._project_intake(project)
                connections = self._load_project_connections(session, project_id, intake)
                market_providers = {ConnectorKind.trend, ConnectorKind.news, ConnectorKind.qa}
                if provider in market_providers:
                    evidence_items = self._collect_market_evidence(intake, providers={provider})
                    if not evidence_items:
                        raise ValueError(f"Provider {provider.value} could not produce evidence")
                    source = evidence_items[0]
                    existing = next((item for item in connections if item.provider == provider), None)
                    if existing is None:
                        endpoint_raw = {
                            ConnectorKind.trend: self.settings.trend_provider_url,
                            ConnectorKind.news: self.settings.news_provider_url,
                            ConnectorKind.qa: self.settings.qa_provider_url,
                        }.get(provider, "")
                        refreshed_connection = ProjectConnection(
                            connection_id=new_id("conn"),
                            provider=provider,
                            label=provider.value.replace("_", " ").title(),
                            enabled=True,
                            status=source.status,
                            config={"endpoints": self._split_market_endpoints(endpoint_raw)},
                            details=dict(source.details),
                            provenance=list(source.provenance),
                            last_checked_at=utcnow(),
                            last_synced_at=utcnow(),
                            next_sync_at=utcnow() + timedelta(minutes=60),
                        )
                        updated_connections = [*connections, refreshed_connection]
                    else:
                        refreshed_connection = existing.model_copy()
                        refreshed_connection.status = source.status
                        refreshed_connection.details = dict(source.details)
                        refreshed_connection.provenance = list(source.provenance)
                        refreshed_connection.last_checked_at = utcnow()
                        refreshed_connection.last_synced_at = utcnow()
                        refreshed_connection.next_sync_at = utcnow() + timedelta(minutes=60)
                        updated_connections = [
                            refreshed_connection if item.provider == provider else item
                            for item in connections
                        ]
                else:
                    updated_connections, source = self.connectors.refresh_provider(project_id, None, intake, connections, provider)
                self._persist_project_connections(session, project_id, updated_connections)
                health = self._connection_health_from_connections(updated_connections)
                state_row = self._upsert_state_row(session, project_id)
                state_row.connection_health = health.value
                state_row.last_sync_at = utcnow()
                state_row.next_sync_at = utcnow() + timedelta(minutes=max(15, state_row.sync_interval_minutes))
                state_row.updated_at = utcnow()
                session.add(state_row)
            issue = source.fallback_reason or (None if source.status == ConnectorStatus.connected else source.summary)
            self._audit(
                project_id,
                "",
                "connector.refreshed",
                {
                    "provider": provider.value,
                    "status": source.status.value,
                    "latencyMs": source.latency_ms,
                    "retryable": source.retryable,
                    "authSource": source.auth_source
                    or next(
                        (
                            item.details.get("authSource")
                            for item in updated_connections
                            if item.provider == provider
                        ),
                        None,
                    ),
                    "fallbackReason": source.fallback_reason,
                    "failureCode": source.failure_code,
                    "issue": issue,
                },
            )
            set_span_attributes(
                {
                    "connector.refresh.status": source.status.value,
                    "connector.refresh.retryable": bool(source.retryable),
                    "connector.refresh.failure_code": source.failure_code or "",
                }
            )
            return ConnectorRefreshResult(
                project_id=project_id,
                provider=provider,
                status=source.status,
                connection_health=health,
                checked_at=utcnow(),
                issue=issue,
                connection=self._apply_connection_runtime_semantics(
                    next(item for item in updated_connections if item.provider == provider)
                ),
                evidence=source,
            )

    def test_projects_connections(self, request: BulkConnectionsTestRequest) -> BulkConnectionsTestResult:
        results: list[ProjectConnectionsTestResult] = []
        skipped_project_ids: list[str] = []
        for project_id in request.project_ids:
            try:
                results.append(self.test_project_connections(project_id))
            except ValueError:
                skipped_project_ids.append(project_id)
        return BulkConnectionsTestResult(
            project_ids=list(request.project_ids),
            tested_count=len(results),
            skipped_project_ids=skipped_project_ids,
            results=results,
            )

    def refresh_projects_connections(
        self,
        request: BulkProjectConnectionsRefreshRequest,
    ) -> BulkProjectConnectionsRefreshResult:
        project_ids = [item.strip() for item in request.project_ids if item and item.strip()]
        if not project_ids:
            with self.database.session() as session:
                project_ids = list(session.scalars(select(ProjectRow.id).order_by(ProjectRow.created_at.asc())))
        results: list[ProjectConnectionsRefreshResult] = []
        skipped_project_ids: list[str] = []
        refresh_request = ProjectConnectionsRefreshRequest(
            providers=list(request.providers),
            max_providers=max(1, int(request.max_providers)),
        )
        for project_id in project_ids:
            try:
                results.append(self.refresh_project_connections(project_id, refresh_request))
            except ValueError:
                skipped_project_ids.append(project_id)
        report = BulkProjectConnectionsRefreshResult(
            project_ids=project_ids,
            refreshed_count=len(results),
            skipped_project_ids=skipped_project_ids,
            results=results,
        )
        self._audit(
            "",
            "",
            "connector.project.refresh.bulk",
            {
                "projectIds": project_ids,
                "refreshedCount": report.refreshed_count,
                "skippedProjectIds": skipped_project_ids,
                "providers": [item.value for item in refresh_request.providers],
                "maxProviders": refresh_request.max_providers,
            },
        )
        return report

    def refresh_projects_connector(self, provider: ConnectorKind, request: BulkConnectorRefreshRequest) -> BulkConnectorRefreshResult:
        results: list[ConnectorRefreshResult] = []
        skipped_project_ids: list[str] = []
        project_ids = [item.strip() for item in request.project_ids if item and item.strip()]
        if not project_ids:
            with self.database.session() as session:
                project_ids = list(session.scalars(select(ProjectRow.id).order_by(ProjectRow.created_at.asc())))
        for project_id in project_ids:
            try:
                results.append(self.refresh_project_connector(project_id, provider))
            except ValueError:
                skipped_project_ids.append(project_id)
        return BulkConnectorRefreshResult(
            provider=provider,
            project_ids=project_ids,
            refreshed_count=len(results),
            skipped_project_ids=skipped_project_ids,
            results=results,
        )

    def refresh_strict_gap_connectors(self, request: BulkStrictGapRefreshRequest) -> BulkStrictGapRefreshResult:
        health = self.get_workspace_connectors_health()
        selected_providers = {item for item in request.providers}
        max_providers = max(1, int(request.max_providers))
        provider_candidates = [
            item
            for item in health.top_strict_gap_providers
            if item.strict_gap_count > 0 and (not selected_providers or item.provider in selected_providers)
        ][:max_providers]
        project_scope = [item.strip() for item in request.project_ids if item and item.strip()]

        provider_results: list[BulkConnectorRefreshResult] = []
        for provider_item in provider_candidates:
            target_project_ids = project_scope or list(provider_item.affected_project_ids)
            provider_results.append(
                self.refresh_projects_connector(
                    provider_item.provider,
                    BulkConnectorRefreshRequest(project_ids=target_project_ids),
                )
            )

        refreshed_count = sum(item.refreshed_count for item in provider_results)
        skipped_project_count = sum(len(item.skipped_project_ids) for item in provider_results)
        notes: list[str] = []
        if not provider_results:
            notes.append("No strict-gap providers matched the current filter.")
        else:
            notes.append(f"Refreshed {len(provider_results)} provider(s) across strict-gap backlog.")
        result = BulkStrictGapRefreshResult(
            provider_count=len(provider_results),
            refreshed_count=refreshed_count,
            skipped_project_count=skipped_project_count,
            provider_results=provider_results,
            notes=notes,
        )
        self._audit(
            "workspace",
            "",
            "connectors.bulk.strict_gap.refreshed",
            {
                "providerCount": result.provider_count,
                "providers": [item.provider.value for item in provider_results],
                "refreshedCount": result.refreshed_count,
                "skippedProjectCount": result.skipped_project_count,
                "projectScopeCount": len(project_scope),
                "projectIds": project_scope,
                "maxProviders": max_providers,
            },
        )
        return result

