    def sync_project(self, project_id: str, request: Optional[ProjectSyncRequest] = None) -> WorkflowBundle:
        request = request or ProjectSyncRequest()
        with self.database.session() as session:
            project = session.get(ProjectRow, project_id)
            if project is None:
                raise ValueError(f"Unknown project: {project_id}")
            intake = self._project_intake(project)
        return self.run_analysis(project_id, intake, trigger=request.trigger, force=request.force)

    def sync_projects(self, request: BulkProjectSyncRequest) -> BulkProjectSyncResult:
        bundles: list[WorkflowBundle] = []
        skipped_project_ids: list[str] = []
        for project_id in request.project_ids:
            try:
                bundles.append(self.sync_project(project_id, ProjectSyncRequest(trigger=request.trigger, force=request.force)))
            except ValueError:
                skipped_project_ids.append(project_id)
        return BulkProjectSyncResult(
            project_ids=list(request.project_ids),
            processed_count=len(bundles),
            skipped_project_ids=skipped_project_ids,
            bundles=bundles,
        )

