    def _workspace_policy_path(self) -> Path:
        self.settings.state_dir.mkdir(parents=True, exist_ok=True)
        return self.settings.state_dir / "workspace-policy.json"

    def get_policy(self) -> WorkspacePolicy:
        path = self._workspace_policy_path()
        if path.exists():
            try:
                return WorkspacePolicy.model_validate_json(path.read_text(encoding="utf-8"))
            except Exception:
                pass
        return WorkspacePolicy(
            auto_deploy_enabled=self.settings.auto_deploy_enabled,
            approval_required_threshold=self.settings.approval_required_threshold,
            block_auto_deploy_threshold=self.settings.block_auto_deploy_threshold,
            monitor_window_minutes=self.settings.monitor_window_minutes,
            rollback_window_minutes=self.settings.rollback_window_minutes,
            auto_cruise_enabled=self.settings.auto_cruise_enabled,
        )

    def update_policy(self, request: WorkspacePolicyUpdateRequest) -> WorkspacePolicy:
        current = self.get_policy()
        updated = current.model_copy(
            update={
                "auto_deploy_enabled": current.auto_deploy_enabled if request.auto_deploy_enabled is None else request.auto_deploy_enabled,
                "approval_required_threshold": current.approval_required_threshold
                if request.approval_required_threshold is None
                else request.approval_required_threshold,
                "block_auto_deploy_threshold": current.block_auto_deploy_threshold
                if request.block_auto_deploy_threshold is None
                else request.block_auto_deploy_threshold,
                "monitor_window_minutes": current.monitor_window_minutes if request.monitor_window_minutes is None else request.monitor_window_minutes,
                "rollback_window_minutes": current.rollback_window_minutes if request.rollback_window_minutes is None else request.rollback_window_minutes,
                "auto_cruise_enabled": current.auto_cruise_enabled if request.auto_cruise_enabled is None else request.auto_cruise_enabled,
                "allowed_deployment_modes": current.allowed_deployment_modes
                if request.allowed_deployment_modes is None
                else request.allowed_deployment_modes,
            }
        )
        self._workspace_policy_path().write_text(updated.model_dump_json(indent=2, by_alias=True), encoding="utf-8")
        self._audit("workspace", "", "policy.updated", {"actor": "ui", "policy": updated.model_dump(mode="json", by_alias=True)})
        return updated

    def _workspace_billing_path(self) -> Path:
        self.settings.state_dir.mkdir(parents=True, exist_ok=True)
