                name="严格模式真实接入门槛",
                passed=(not strict_enabled) or workspace_health.strict_gap_count == 0,
                expected="strictProviders=false 或 strictGapCount=0",
                actual=f"strictProviders={str(strict_enabled).lower()}, strictGapCount={workspace_health.strict_gap_count}",
                quick_action_path="/settings",
                quick_action_label="修复严格模式接入",
