    def build_remaining_tasks_report(self, project_id: Optional[str] = None) -> RemainingTaskReport:
        normalized_project_id = str(project_id or "").strip() or None
        benchmark = self.build_product_benchmark_report(project_id=normalized_project_id)
        acceptance = self.build_acceptance_report()
        failed_gate_ids = {gate.gate_id for gate in acceptance.gates if not gate.passed}
        failed_gate_map = {gate.gate_id: gate for gate in acceptance.gates if not gate.passed}

        gate_map: dict[str, list[str]] = {
            "real_provider_ingestion_writeback": ["real_provider_samples", "market_workspace_readiness"],
            "visual_farm_production": ["visual_regression_production", "visual_farm_runtime_ready"],
            "runtime_edge_multisite": ["runtime_edge_gateway_ready", "runtime_edge_rollout_ready", "runtime_edge_probe_ready"],
            "ad_revenue_reporting": ["mvp_ad_recommendations"],
            "merchant_settlement": ["billing_gateway_live_routes"],
            "experimentation_runtime_governance": ["workspace_auto_cruise", "runtime_architecture_production"],
        }

        rank = {"p0": 0, "p1": 1, "p2": 2, "p3": 3}
        items: list[RemainingTaskItem] = []
        for capability in benchmark.capabilities:
            if capability.current_status == "production_ready":
                continue
            mapped_gates = [gate_id for gate_id in gate_map.get(capability.capability_id, []) if gate_id in failed_gate_ids]
            blocking = capability.priority == "p0" or capability.current_status == "missing" or bool(mapped_gates)
            mapped_gate_actions = [failed_gate_map[gate_id] for gate_id in mapped_gates if gate_id in failed_gate_map]
            quick_action_path = next(
                (gate.quick_action_path for gate in mapped_gate_actions if gate.quick_action_path),
                None,
            )
            quick_action_label = next(
                (gate.quick_action_label for gate in mapped_gate_actions if gate.quick_action_label),
                "Open remediation" if quick_action_path else None,
            )
            items.append(
                RemainingTaskItem(
                    task_id=f"remaining_{capability.capability_id}",
                    title=capability.title,
                    priority=capability.priority,
                    source_capability_id=capability.capability_id,
                    status="blocked" if blocking else "planned",
                    blocking=blocking,
                    acceptance_gate_ids=mapped_gates,
                    remaining_gaps=capability.remaining_gaps,
                    next_action=capability.next_actions[0] if capability.next_actions else None,
                    quick_action_path=quick_action_path,
                    quick_action_label=quick_action_label,
                )
            )

        items.sort(key=lambda item: (rank.get(item.priority, 9), 0 if item.blocking else 1, item.task_id))
        return RemainingTaskReport(
            project_id=normalized_project_id,
            total=len(items),
            blocking_count=sum(1 for item in items if item.blocking),
            p0_count=sum(1 for item in items if item.priority == "p0"),
            p1_count=sum(1 for item in items if item.priority == "p1"),
            p2_count=sum(1 for item in items if item.priority == "p2"),
            p3_count=sum(1 for item in items if item.priority == "p3"),
            items=items,
            notes=[
                "该清单由 product benchmark 和 acceptance gate 自动汇总，便于按阻断优先级推进。",
                "status=blocked 表示当前有失败 gate、缺失能力或 P0 生产缺口。",
            ],
        )

    def build_remaining_tasks_board_report(self, project_id: Optional[str] = None) -> RemainingTaskBoardReport:
        normalized_project_id = str(project_id or "").strip() or None
        remaining = self.build_remaining_tasks_report(project_id=normalized_project_id)
        group_meta: dict[str, tuple[Literal["provider", "visual", "runtime", "ads", "billing", "experiment", "other"], str]] = {
            "real_provider_ingestion_writeback": ("provider", "Provider read/write"),
            "visual_farm_production": ("visual", "Visual farm"),
            "runtime_edge_multisite": ("runtime", "Runtime edge"),
            "ad_revenue_reporting": ("ads", "Ad reporting"),
            "merchant_settlement": ("billing", "Billing settlement"),
            "experimentation_runtime_governance": ("experiment", "Experiment governance"),
        }
        groups: dict[str, RemainingTaskBoardGroup] = {}
        for item in remaining.items:
            group_id, title = group_meta.get(item.source_capability_id, ("other", "Other"))
            key = str(group_id)
            if key not in groups:
                groups[key] = RemainingTaskBoardGroup(group_id=group_id, title=title)
            group = groups[key]
            group.total += 1
            group.blocking_count += 1 if item.blocking else 0
            group.p0_count += 1 if item.priority == "p0" else 0
            group.p1_count += 1 if item.priority == "p1" else 0
            group.p2_count += 1 if item.priority == "p2" else 0
            group.p3_count += 1 if item.priority == "p3" else 0
            group.task_ids.append(item.task_id)

        ordered_groups = sorted(groups.values(), key=lambda entry: (-entry.blocking_count, -entry.total, entry.title))
        return RemainingTaskBoardReport(
            project_id=normalized_project_id,
            total=remaining.total,
            blocking_count=remaining.blocking_count,
            groups=ordered_groups,
            notes=[
                "该看板把 remaining tasks 按能力组聚合，便于冲刺排期和负责人分工。",
            ],
        )

    def build_visual_regression_report(self) -> VisualRegressionReport:
        report = build_visual_regression_report(self.build_regression_sample_set())
        return self._attach_visual_regression_links(report)

    def build_visual_regression_runs_report(self, project_id: Optional[str] = None) -> VisualRegressionRunsReport:
        normalized_project_id = str(project_id or "").strip() or None
        runs = build_visual_regression_runs(
            self.build_regression_sample_set(),
            strict_mode=bool(self.settings.visual_farm_strict),
        )
        enriched_runs: list[VisualRegressionRun] = []
        for run in runs.runs:
            cases = self._attach_visual_regression_links_to_cases(run.cases)
            if normalized_project_id:
                cases = [case for case in cases if case.project_id == normalized_project_id]
            enriched_runs.append(run.model_copy(update=self._build_visual_run_metrics_update(cases=cases, strict_mode=run.strict_mode)))
        return runs.model_copy(update={"project_id": normalized_project_id, "runs": enriched_runs})

    def execute_visual_regression_runs(self, request: VisualRegressionRunExecuteRequest) -> VisualRegressionRunsReport:
        strict_mode = bool(self.settings.visual_farm_strict) if request.strict_mode is None else bool(request.strict_mode)
        runs = build_visual_regression_runs(
            self.build_regression_sample_set(),
            strict_mode=strict_mode,
        )
        target_project_ids = {project_id.strip() for project_id in request.project_ids if project_id and project_id.strip()}
        target_task_ids = {task_id.strip() for task_id in request.task_ids if task_id and task_id.strip()}
        max_cases = max(0, int(request.max_cases))
        enriched_runs: list[VisualRegressionRun] = []
        for run in runs.runs:
            cases = self._attach_visual_regression_links_to_cases(run.cases)
            if target_project_ids:
                cases = [case for case in cases if case.project_id in target_project_ids]
            if target_task_ids:
                cases = [case for case in cases if case.workflow_task_id in target_task_ids]
            if max_cases > 0:
                cases = cases[:max_cases]
            enriched_runs.append(run.model_copy(update=self._build_visual_run_metrics_update(cases=cases, strict_mode=strict_mode)))
        effective_project_ids = sorted(
            {
                project_id
                for run in enriched_runs
                for project_id in run.project_ids
                if str(project_id).strip()
            }
        )
        effective_task_ids = sorted(
            {
                task_id
                for run in enriched_runs
                for task_id in run.workflow_task_ids
                if str(task_id).strip()
            }
        )
        effective_deployment_artifact_refs = sorted(
            {
                artifact_ref
                for run in enriched_runs
                for artifact_ref in run.deployment_artifact_refs
                if str(artifact_ref).strip()
            }
        )
        effective_deployment_record_ids = sorted(
            {
                deployment_id
                for run in enriched_runs
                for deployment_id in run.deployment_record_ids
                if str(deployment_id).strip()
            }
        )
        report = VisualRegressionRunsReport(generated_at=utcnow(), runs=enriched_runs)
        self._audit(
            "system",
            "",
            "visual_regressions.run.executed",
            {
                "strictMode": strict_mode,
                "projectIds": sorted(target_project_ids) if target_project_ids else effective_project_ids,
                "taskIds": sorted(target_task_ids) if target_task_ids else effective_task_ids,
                "maxCases": max_cases,
                "runCount": len(enriched_runs),
                "caseCount": sum(run.sample_count for run in enriched_runs),
                "runIds": [run.run_id for run in enriched_runs],
                "deploymentArtifactRefs": effective_deployment_artifact_refs,
                "deploymentRecordIds": effective_deployment_record_ids,
            },
        )
        return report

    def enqueue_visual_regression_run(self, request: VisualRegressionRunExecuteRequest, *, actor: str = "quality-ui") -> VisualRegressionRunEnqueueResult:
        target_project_ids = sorted({project_id.strip() for project_id in request.project_ids if project_id and project_id.strip()})
        target_task_ids = sorted({task_id.strip() for task_id in request.task_ids if task_id and task_id.strip()})
        strict_mode = request.strict_mode
        max_cases = max(0, int(request.max_cases))
        payload: dict[str, Any] = {
            "stage": "visual_regression",
            "projectIds": target_project_ids,
            "taskIds": target_task_ids,
            "maxCases": max_cases,
            "actor": actor,
        }
        if strict_mode is not None:
            payload["strictMode"] = bool(strict_mode)
        job = WorkerJob(
            job_id=new_id("job"),
            stage="visual_regression",
            project_id=target_project_ids[0] if target_project_ids else "system",
            task_id="",
            payload=payload,
        )
        enqueued = self.job_queue.enqueue(job)
        if enqueued:
            self._audit(
                job.project_id,
                job.task_id,
                "worker.job.enqueued",
                {"actor": actor, **payload, "jobId": job.job_id},
            )
            message = "Visual regression run job has been enqueued."
        else:
            self._audit(
                job.project_id,
                job.task_id,
                "worker.job.skipped_duplicate",
                {"actor": actor, **payload, "jobId": job.job_id, "fingerprint": job.fingerprint()},
            )
            message = "Visual regression run job already queued; skipped duplicate enqueue."
        return VisualRegressionRunEnqueueResult(
            enqueued=enqueued,
            skipped_duplicate=not enqueued,
            job_id=job.job_id,
            stage=job.stage,
            strict_mode=strict_mode,
            project_ids=target_project_ids,
            task_ids=target_task_ids,
            max_cases=max_cases,
            message=message,
        )

    def build_visual_regression_health_report(self, project_id: Optional[str] = None) -> VisualRegressionHealthReport:
        normalized_project_id = str(project_id or "").strip() or None
        runs = self.build_visual_regression_runs_report(project_id=normalized_project_id)
        latest = runs.runs[0] if runs.runs else None
        notes: list[str] = []
        failure_buckets: list[VisualRegressionFailureBucket] = []
        if latest is None:
            notes.append("No visual regression run available.")
        else:
            if latest.not_configured_case_count > 0:
                notes.append("Visual farm is not configured for part of the sampled pages.")
            if latest.fallback_case_count > 0:
                notes.append("Visual farm fell back for part of the sampled pages.")
            if latest.failed_case_count > 0:
                notes.append("Visual farm execution failed for part of the sampled pages.")
            if latest.strict_blocked_case_count > 0:
                notes.append("Strict mode blocked one or more visual regression cases.")
            failure_buckets = self._build_visual_failure_buckets(latest.cases)
            if failure_buckets:
                notes.append("Visual failure buckets include retryability and suggested remediation paths.")
        return VisualRegressionHealthReport(
            project_id=normalized_project_id,
            strict_mode=bool(self.settings.visual_farm_strict),
            configured_endpoint_count=latest.configured_endpoint_count if latest is not None else 0,
            configured_endpoints=list(latest.configured_endpoints) if latest is not None else [],
            run_count=len(runs.runs),
            last_run_id=latest.run_id if latest is not None else None,
            last_run_executed_at=latest.executed_at if latest is not None else None,
            last_run_connected_case_count=latest.connected_case_count if latest is not None else 0,
            last_run_failed_case_count=latest.failed_case_count if latest is not None else 0,
            last_run_fallback_case_count=latest.fallback_case_count if latest is not None else 0,
            last_run_not_configured_case_count=latest.not_configured_case_count if latest is not None else 0,
            last_run_strict_blocked_case_count=latest.strict_blocked_case_count if latest is not None else 0,
            last_run_attempted_endpoint_count=latest.attempted_endpoint_count if latest is not None else 0,
            last_run_failed_endpoints=list(latest.failed_endpoints) if latest is not None else [],
            failure_buckets=failure_buckets,
            notes=notes,
        )

    def build_visual_farm_status_report(self, project_id: Optional[str] = None) -> VisualFarmStatusReport:
        normalized_project_id = str(project_id or "").strip() or None
        health = self.build_visual_regression_health_report(project_id=normalized_project_id)
        token, auth_header, auth_source = self._visual_farm_runtime_credentials()
        token_configured = bool(token)
        probe_freshness_minutes = max(1, int(self.settings.visual_farm_probe_freshness_minutes))
        probe_history = self.get_visual_farm_probe_history(limit=1, project_id=normalized_project_id)
        latest_probe = probe_history.entries[0] if probe_history.entries else None
        now = utcnow()
        probe_fresh = False
        if latest_probe and latest_probe.created_at:
            probe_created_at = latest_probe.created_at
            if probe_created_at.tzinfo is None:
                probe_created_at = probe_created_at.replace(tzinfo=timezone.utc)
            now_with_tz = now if now.tzinfo is not None else now.replace(tzinfo=timezone.utc)
            probe_fresh = probe_created_at >= (now_with_tz - timedelta(minutes=probe_freshness_minutes))
        probe_stale = not probe_fresh
        strict_publish_ready = bool(
            health.strict_mode
            and health.configured_endpoint_count > 0
            and token_configured
            and probe_fresh
            and (latest_probe.connected_count if latest_probe else 0) > 0
            and (latest_probe.blocking_count if latest_probe else 1) == 0
            and health.last_run_not_configured_case_count == 0
            and health.last_run_fallback_case_count == 0
            and health.last_run_failed_case_count == 0
            and health.last_run_strict_blocked_case_count == 0
        )
        notes = list(health.notes)
        if health.configured_endpoint_count == 0:
            notes.append("No visual farm endpoint configured.")
        if not token_configured:
            notes.append("Visual farm access token is not configured.")
        if latest_probe is None:
            notes.append("No visual farm probe history available yet.")
        elif probe_stale:
            notes.append(f"Latest visual farm probe is stale (> {probe_freshness_minutes}m).")
        elif latest_probe.blocking_count > 0:
            notes.append("Latest visual farm probe still has blocking endpoint failures.")
        if health.strict_mode and not strict_publish_ready:
            notes.append("Strict visual publish readiness is not met.")
        return VisualFarmStatusReport(
            project_id=normalized_project_id,
            strict_mode=health.strict_mode,
            configured_endpoint_count=health.configured_endpoint_count,
            configured_endpoints=health.configured_endpoints,
            access_token_configured=token_configured,
            auth_source=auth_source,
            timeout_ms=max(0, int(self.settings.visual_farm_timeout_ms)),
            run_count=health.run_count,
            last_run_id=health.last_run_id,
            last_run_executed_at=health.last_run_executed_at,
            last_run_connected_case_count=health.last_run_connected_case_count,
            last_run_failed_case_count=health.last_run_failed_case_count,
            last_run_fallback_case_count=health.last_run_fallback_case_count,
            last_run_not_configured_case_count=health.last_run_not_configured_case_count,
            last_run_strict_blocked_case_count=health.last_run_strict_blocked_case_count,
            probe_freshness_minutes=probe_freshness_minutes,
            last_probe_executed_at=latest_probe.created_at if latest_probe else None,
            last_probe_connected_count=latest_probe.connected_count if latest_probe else 0,
            last_probe_failed_count=latest_probe.failed_count if latest_probe else 0,
            last_probe_blocking_count=latest_probe.blocking_count if latest_probe else 0,
            last_probe_recoverable_count=latest_probe.recoverable_count if latest_probe else 0,
            probe_fresh=probe_fresh,
            probe_stale=probe_stale,
            strict_publish_ready=strict_publish_ready,
            failure_buckets=health.failure_buckets,
            notes=notes,
        )

    def _visual_farm_deployment_runtime_config(
        self,
        *,
        gateway_report: Optional[VisualFarmGatewayReport] = None,
    ) -> tuple[list[str], str, str, str]:
        resolved_gateway_report = gateway_report or self.build_visual_farm_gateway_report()
        route = next(
            (
                item
                for item in resolved_gateway_report.routes
                if item.provider_name == resolved_gateway_report.policy.default_provider_name
                and item.route_ready
                and item.resolved_provider_name == item.provider_name
            ),
            None,
        )
        if route is not None:
            route_entry = next(
                (item for item in (resolved_gateway_report.policy.routes or []) if item.provider_name == route.provider_name),
                None,
            )
            if route_entry is not None:
                route_notes = list(route_entry.notes or [])
                raw_route_endpoints = (
                    self._billing_gateway_route_note_value(route_notes, "endpoints")
                    or self._billing_gateway_route_note_value(route_notes, "providerUrls")
                    or self._billing_gateway_route_note_value(route_notes, "provider_urls")
                    or self._billing_gateway_route_note_value(route_notes, "providerURLs")
                    or self._billing_gateway_route_note_value(route_notes, "providerUrl")
                    or self._billing_gateway_route_note_value(route_notes, "provider_url")
                )
                endpoints: list[str] = []
                for candidate in [str(route.endpoint or "").strip(), *self._split_billing_gateway_endpoints(str(raw_route_endpoints or "").strip())]:
                    normalized_endpoint = str(candidate or "").strip()
                    if normalized_endpoint and normalized_endpoint not in endpoints:
                        endpoints.append(normalized_endpoint)
                token, auth_source = self._billing_gateway_resolve_secret(str(route_entry.access_token or "").strip())
                auth_header = str(route_entry.auth_header or "Authorization").strip() or "Authorization"
                if endpoints and token:
                    return endpoints, token, auth_header, auth_source
        gateway_endpoints: list[str] = []
        for candidate in [
            str(self.settings.visual_farm_gateway_url or "").strip(),
            *self._split_billing_gateway_endpoints(str(self.settings.visual_farm_gateway_urls or "").strip()),
        ]:
            normalized_endpoint = str(candidate or "").strip()
            if normalized_endpoint and normalized_endpoint not in gateway_endpoints:
                gateway_endpoints.append(normalized_endpoint)
        gateway_token = str(self.settings.visual_farm_gateway_access_token or "").strip()
        gateway_token, gateway_auth_source = self._billing_gateway_resolve_secret(gateway_token)
        gateway_auth_header = str(self.settings.visual_farm_gateway_auth_header or "Authorization").strip() or "Authorization"
        if gateway_endpoints and gateway_token:
            return gateway_endpoints, gateway_token, gateway_auth_header, gateway_auth_source

        endpoints: list[str] = []
        for item in str(self.settings.visual_farm_endpoints or "").replace("\n", ",").split(","):
            endpoint = item.strip()
            if endpoint and endpoint not in endpoints:
                endpoints.append(endpoint)
        single_endpoint = str(self.settings.visual_farm_endpoint or "").strip()
        if single_endpoint and single_endpoint not in endpoints:
            endpoints.append(single_endpoint)
        token, auth_header, auth_source = self._visual_farm_runtime_credentials()
        return endpoints, token, auth_header, auth_source if token else "none"

    def execute_visual_farm_deployment(self, request: VisualFarmDeploymentRequest) -> VisualFarmDeploymentReport:
        strict_mode = bool(self.settings.visual_farm_strict) if request.strict_mode is None else bool(request.strict_mode)
        normalized_project_id = (request.project_id or "").strip() or None
        normalized_task_id = (request.task_id or "").strip() or None
        project_name: Optional[str] = None
        if normalized_project_id is not None:
            with self.database.session() as session:
                project_row = session.get(ProjectRow, normalized_project_id)
                if project_row is not None:
                    project_name = project_row.name
        gateway_report = self.build_visual_farm_gateway_report(project_id=normalized_project_id)
        gateway_route = next(
            (
                route
                for route in gateway_report.routes
                if route.provider_name == gateway_report.policy.default_provider_name and route.route_ready and route.resolved_provider_name == route.provider_name
            ),
            None,
        )
        matched_gateway_route = next((route for route in gateway_report.routes if route.provider_name == gateway_report.policy.default_provider_name), None)
        endpoints, token, auth_header, auth_source = self._visual_farm_deployment_runtime_config(gateway_report=gateway_report)
        status: Literal["planned", "blocked", "executed"] = "planned"
        failure_code: Optional[str] = None
        retryable = False
        message = "Visual farm deployment plan generated."
        notes = [
            f"strictMode={str(strict_mode).lower()}",
            f"projectId={normalized_project_id or 'workspace'}",
        ]
        provider_endpoint: Optional[str] = None
        provider_url: Optional[str] = None
        provider_artifact_id: Optional[str] = None
        if normalized_task_id:
            notes.append(f"taskId={normalized_task_id}")
        if request.dry_run:
            notes.append("dryRun=true")
            message = "Visual farm deployment preview recorded without provider execution."
        elif not endpoints:
            status = "blocked"
            failure_code = "VISUAL_FARM_DEPLOYMENT_ENDPOINT_MISSING"
            message = "Visual farm deployment endpoint is not configured."
            notes.append("providerMode=local")
        elif not token:
            status = "blocked"
            failure_code = "VISUAL_FARM_DEPLOYMENT_TOKEN_MISSING"
            message = "Visual farm deployment token is not configured."
            notes.append("providerMode=local")
        else:
            health = self.build_visual_farm_status_report(project_id=normalized_project_id)
            regression_health = self.build_visual_regression_health_report(project_id=normalized_project_id)
            payload = {
                "projectId": normalized_project_id,
                "taskId": normalized_task_id,
                "strictMode": strict_mode,
                "actor": request.actor,
                "note": request.note,
                "visualFarmStatus": health.model_dump(mode="json", by_alias=True),
                "visualRegressionHealth": regression_health.model_dump(mode="json", by_alias=True),
                "gatewayPolicy": gateway_report.policy.model_dump(mode="json", by_alias=True),
            }
            headers = {
                "Content-Type": "application/json",
                "Accept": "application/json",
                str(auth_header or "Authorization"): f"Bearer {token}",
            }
            last_reason: Optional[str] = None
            last_code: Optional[str] = None
            for endpoint in endpoints:
                started = time.perf_counter()
                try:
                    request_obj = Request(
                        endpoint,
                        data=json.dumps(payload).encode("utf-8"),
                        headers=headers,
                        method="POST",
                    )
                    with urlopen(request_obj, timeout=max(1, int(self.settings.visual_farm_timeout_ms / 1000))) as response:  # nosec - configurable outbound visual farm deployment
                        raw_body = response.read().decode("utf-8") if hasattr(response, "read") else ""
                        response_payload = json.loads(raw_body) if raw_body.strip() else {}
                    provider_endpoint = endpoint
                    provider_url = str(response_payload.get("artifactUrl") or response_payload.get("url") or endpoint)
                    provider_artifact_id = str(
                        response_payload.get("artifactId")
                        or response_payload.get("deploymentId")
                        or response_payload.get("id")
                        or f"visual_farm_{new_id('art')}"
                    )
                    notes.extend(
                        [
                            "providerMode=external",
                            f"gatewayEndpoint={endpoint}",
                            f"authSource={auth_source}",
                            f"httpStatus={getattr(response, 'status', '200')}",
                            f"latencyMs={int((time.perf_counter() - started) * 1000)}",
                        ]
                    )
                    status = "executed"
                    message = "Visual farm deployment executed through external provider."
                    last_reason = None
                    last_code = None
                    break
                except HTTPError as exc:
                    status = "blocked"
                    retryable = 500 <= int(getattr(exc, "code", 0) or 0) < 600
                    last_reason = f"Visual farm deployment failed with HTTP {getattr(exc, 'code', 'unknown')}."
                    last_code = f"VISUAL_FARM_DEPLOYMENT_HTTP_{getattr(exc, 'code', 'ERROR')}"
                    notes.append(f"attemptFailed={endpoint}:http_{getattr(exc, 'code', 'unknown')}")
                except Exception as exc:
                    status = "blocked"
                    retryable = True
                    last_reason = f"Visual farm deployment failed: {exc}"
                    last_code = "VISUAL_FARM_DEPLOYMENT_REQUEST_FAILED"
                    notes.append(f"attemptFailed={endpoint}:request_failed")
            if status != "executed":
                failure_code = last_code or "VISUAL_FARM_DEPLOYMENT_REQUEST_FAILED"
                message = last_reason or "Visual farm deployment failed."
                notes.extend(
                    [
                        "providerMode=external",
                        f"attemptedEndpointCount={len(endpoints)}",
                    ]
                )
        manifest_path = self._visual_farm_deployment_manifest_path(
            project_id=normalized_project_id,
            strict_mode=strict_mode,
        )
        report = VisualFarmDeploymentReport(
            deployment_id=new_id("visual-farm-deployment"),
            generated_at=utcnow(),
            strict_mode=strict_mode,
            dry_run=request.dry_run,
            project_id=normalized_project_id,
            task_id=normalized_task_id,
            actor=(request.actor or "ui").strip() or "ui",
            note=request.note,
            status=status,
            provider_endpoint=provider_endpoint,
            provider_url=provider_url,
            provider_artifact_id=provider_artifact_id,
            failure_code=failure_code,
            retryable=retryable,
            message=message,
            manifest_path=str(manifest_path),
            notes=notes,
        )
        manifest_payload = {
            "deployment": report.model_dump(mode="json", by_alias=True),
            "gateway": gateway_report.model_dump(mode="json", by_alias=True),
            "status": report.status,
            "projectId": normalized_project_id,
            "strictMode": strict_mode,
            "dryRun": request.dry_run,
            "providerEndpoint": provider_endpoint,
            "providerUrl": provider_url,
            "providerArtifactId": provider_artifact_id,
            "projectName": project_name or "workspace",
        }
        manifest_path.write_text(json.dumps(manifest_payload, ensure_ascii=True, indent=2), encoding="utf-8")
        report = report.model_copy(update={"notes": [*report.notes, f"manifestPath={manifest_path}"]})
        self._audit(
            normalized_project_id or "workspace",
            normalized_task_id or "",
            "visual_farm.deployment.executed",
            {"deployment": report.model_dump(mode="json", by_alias=True)},
        )
        try:
            self.publish_runtime_ingress_bundle(
                project_id=normalized_project_id,
                strict_routes_only=strict_mode,
            )
        except Exception:
            pass
        return report

    def execute_visual_farm_deployment_batch(
        self,
        request: VisualFarmDeploymentBatchRequest,
    ) -> VisualFarmDeploymentBatchReport:
        project_ids: list[str] = []
        for project_id in request.project_ids:
            normalized = str(project_id or "").strip()
            if normalized and normalized not in project_ids:
                project_ids.append(normalized)
        strict_mode = bool(self.settings.visual_farm_strict) if request.strict_mode is None else bool(request.strict_mode)
        items: list[VisualFarmDeploymentReport] = []
        executed_count = 0
        blocked_count = 0
        failed_count = 0
        notes = [
            f"strictMode={str(strict_mode).lower()}",
            f"projectCount={len(project_ids)}",
        ]
        if request.note:
            notes.append(f"note={request.note}")
        for project_id in project_ids:
            try:
                report = self.execute_visual_farm_deployment(
                    VisualFarmDeploymentRequest(
                        project_id=project_id,
                        strict_mode=strict_mode,
                        dry_run=request.dry_run,
                        actor=request.actor,
                        note=request.note,
                    )
                )
            except Exception as exc:
                report = VisualFarmDeploymentReport(
                    deployment_id=new_id("visual-farm-deployment"),
                    generated_at=utcnow(),
                    strict_mode=strict_mode,
                    dry_run=request.dry_run,
                    project_id=project_id,
                    actor=(request.actor or "ui").strip() or "ui",
                    note=request.note,
                    status="blocked",
                    failure_code="VISUAL_FARM_DEPLOYMENT_BATCH_FAILED",
                    retryable=True,
                    message=str(exc),
                    notes=[f"batchFailure={exc}"],
                )
            items.append(report)
            if report.status == "executed":
                executed_count += 1
            elif report.status == "blocked":
                blocked_count += 1
            else:
                failed_count += 1
        batch = VisualFarmDeploymentBatchReport(
            batch_id=new_id("visual-farm-batch"),
            generated_at=utcnow(),
            strict_mode=strict_mode,
            dry_run=request.dry_run,
            actor=(request.actor or "ui").strip() or "ui",
            note=request.note,
            total_count=len(items),
            executed_count=executed_count,
            blocked_count=blocked_count,
            failed_count=failed_count,
            items=items,
            notes=notes,
        )
        self._audit(
            "workspace",
            "",
            "visual_farm.deployment.batch.executed",
            {"batch": batch.model_dump(mode="json", by_alias=True)},
        )
        return batch

    def enqueue_visual_farm_deployment_batch(
        self,
        request: VisualFarmDeploymentBatchRequest,
        *,
        actor: str = "settings-ui",
    ) -> VisualFarmDeploymentBatchEnqueueResult:
        project_ids: list[str] = []
        for item in request.project_ids:
            normalized = str(item or "").strip()
            if normalized and normalized not in project_ids:
                project_ids.append(normalized)
        payload: dict[str, Any] = {
            "stage": "visual_farm_deployment_batch",
            "projectIds": project_ids,
            "strictMode": bool(request.strict_mode) if request.strict_mode is not None else None,
            "dryRun": bool(request.dry_run),
            "actor": (request.actor or actor).strip() or actor,
        }
        if request.note and request.note.strip():
            payload["note"] = request.note.strip()
        job = WorkerJob(
            job_id=new_id("job"),
            stage="visual_farm_deployment_batch",
            project_id="workspace",
            task_id="visual_farm_deployment_batch",
            payload=payload,
        )
        enqueued = self.job_queue.enqueue(job)
        if enqueued:
            self._audit(
                job.project_id,
                job.task_id,
                "worker.job.enqueued",
                {"actor": payload["actor"], **payload, "jobId": job.job_id},
            )
            message = "Visual farm deployment batch job has been enqueued."
        else:
            self._audit(
                job.project_id,
                job.task_id,
                "worker.job.skipped_duplicate",
                {"actor": payload["actor"], **payload, "jobId": job.job_id, "fingerprint": job.fingerprint()},
            )
            message = "Visual farm deployment batch job already queued; skipped duplicate enqueue."
        return VisualFarmDeploymentBatchEnqueueResult(
            enqueued=enqueued,
            skipped_duplicate=not enqueued,
            job_id=job.job_id,
            stage=job.stage,
            strict_mode=bool(request.strict_mode) if request.strict_mode is not None else bool(self.settings.visual_farm_strict),
            dry_run=bool(request.dry_run),
            project_ids=project_ids,
            message=message,
        )

    def get_visual_farm_deployment_history(
        self,
        limit: int = 20,
        *,
        project_id: Optional[str] = None,
    ) -> VisualFarmDeploymentHistoryReport:
        bounded_limit = min(100, max(1, int(limit)))
        normalized_project_id = (project_id or "").strip() or None
        items: list[VisualFarmDeploymentReport] = []
        notes: list[str] = []
        with self.database.session() as session:
            rows = session.scalars(
                select(AuditRow)
                .where(AuditRow.action == "visual_farm.deployment.executed")
                .order_by(AuditRow.created_at.desc())
                .limit(bounded_limit)
            ).all()
        for row in rows:
            payload = dict(row.payload_json or {})
            deployment_payload = payload.get("deployment")
            if not isinstance(deployment_payload, dict):
                continue
            try:
                item = VisualFarmDeploymentReport.model_validate(deployment_payload)
            except Exception:
                continue
            if normalized_project_id and (item.project_id or "") != normalized_project_id:
                continue
            items.append(item)
            if len(items) >= bounded_limit:
                break
        latest = items[0] if items else None
        if normalized_project_id:
            notes.append(f"projectId={normalized_project_id}")
        if latest is not None:
            notes.append(f"latestStatus={latest.status}")
            if latest.provider_endpoint:
                notes.append(f"latestProviderEndpoint={latest.provider_endpoint}")
        summary = VisualFarmHistorySummary(
            total_count=len(items),
            executed_count=sum(1 for item in items if item.status == "executed"),
            blocked_count=sum(1 for item in items if item.status == "blocked"),
            planned_count=sum(1 for item in items if item.status == "planned"),
        )
        return VisualFarmDeploymentHistoryReport(
            generated_at=utcnow(),
            project_id=normalized_project_id,
            total=len(items),
            summary=summary,
            executed_count=summary.executed_count,
            blocked_count=summary.blocked_count,
            planned_count=summary.planned_count,
            items=items,
            notes=notes,
        )

    def get_visual_farm_deployment_batch_history(
        self,
        limit: int = 20,
        *,
        project_id: Optional[str] = None,
    ) -> VisualFarmDeploymentBatchHistoryReport:
        bounded_limit = min(100, max(1, int(limit)))
        normalized_project_id = (project_id or "").strip() or None
        entries: list[VisualFarmDeploymentBatchHistoryEntry] = []
        with self.database.session() as session:
            rows = session.scalars(
                select(AuditRow)
                .where(AuditRow.action == "visual_farm.deployment.batch.executed")
                .order_by(AuditRow.created_at.desc())
                .limit(bounded_limit)
            ).all()
        for row in rows:
            payload = dict(row.payload_json or {})
            batch_payload = payload.get("batch")
            if not isinstance(batch_payload, dict):
                continue
            raw_items = batch_payload.get("items")
            items = raw_items if isinstance(raw_items, list) else []
            project_ids: list[str] = []
            for item in items:
                if not isinstance(item, dict):
                    continue
                candidate = str(item.get("projectId") or "").strip()
                if candidate and candidate not in project_ids:
                    project_ids.append(candidate)
            if normalized_project_id and normalized_project_id not in project_ids:
                continue
            entries.append(
                VisualFarmDeploymentBatchHistoryEntry(
                    audit_id=str(row.id),
                    created_at=row.created_at,
                    actor=str(payload.get("actor") or row.actor or "ui"),
                    batch_id=str(batch_payload.get("batchId") or ""),
                    strict_mode=bool(batch_payload.get("strictMode", False)),
                    dry_run=bool(batch_payload.get("dryRun", True)),
                    total_count=int(batch_payload.get("totalCount") or 0),
                    executed_count=int(batch_payload.get("executedCount") or 0),
                    blocked_count=int(batch_payload.get("blockedCount") or 0),
                    failed_count=int(batch_payload.get("failedCount") or 0),
                    project_ids=project_ids,
                    notes=[str(item) for item in batch_payload.get("notes", []) if str(item).strip()],
                )
            )
            if len(entries) >= bounded_limit:
                break
        summary = VisualFarmHistorySummary(
            total_count=len(entries),
            executed_count=sum(1 for item in entries if item.executed_count > 0),
            blocked_count=sum(1 for item in entries if item.blocked_count > 0),
            failed_count=sum(1 for item in entries if item.failed_count > 0),
            dry_run_count=sum(1 for item in entries if item.dry_run),
        )
        return VisualFarmDeploymentBatchHistoryReport(
            generated_at=utcnow(),
            project_id=normalized_project_id,
            total=len(entries),
            summary=summary,
            executed_count=sum(item.executed_count for item in entries),
            blocked_count=sum(item.blocked_count for item in entries),
            failed_count=sum(item.failed_count for item in entries),
            entries=entries,
        )

    def _runtime_ingress_bundle_path(self) -> Path:
        self.settings.state_dir.mkdir(parents=True, exist_ok=True)
        return self.settings.state_dir / "runtime-ingress-bundle.json"

    def _runtime_ingress_route_manifest_path(
        self,
        *,
        project_id: Optional[str] = None,
        strict_routes_only: Optional[bool] = None,
    ) -> Path:
        self.settings.state_dir.mkdir(parents=True, exist_ok=True)
        normalized_project_id = (project_id or "").strip() or "workspace"
        strict_flag = bool(self.settings.strict_providers) if strict_routes_only is None else bool(strict_routes_only)
        strict_suffix = "strict" if strict_flag else "relaxed"
        return self.settings.state_dir / f"runtime-ingress-{normalized_project_id}-{strict_suffix}-manifest.json"

    def _runtime_ingress_gateway_runtime_config(self) -> dict[str, Any]:
        endpoint = str(self.settings.runtime_ingress_gateway_url or "").strip()
        endpoints: list[str] = []
        for candidate in [endpoint, *self._split_billing_gateway_endpoints(str(self.settings.runtime_ingress_gateway_urls or "").strip())]:
            normalized_endpoint = str(candidate or "").strip()
            if normalized_endpoint and normalized_endpoint not in endpoints:
                endpoints.append(normalized_endpoint)
        token = str(self.settings.runtime_ingress_gateway_access_token or "").strip()
        token, auth_source = self._billing_gateway_resolve_secret(token)
        auth_header = str(self.settings.runtime_ingress_gateway_auth_header or "Authorization").strip() or "Authorization"
        return {
            "endpoint": (endpoints[0] if endpoints else None),
            "endpoints": endpoints,
            "token": token or None,
            "authHeader": auth_header,
            "authSource": auth_source,
            "timeoutMs": max(1, int(self.settings.runtime_ingress_gateway_timeout_ms)),
        }

    def _execute_runtime_ingress_gateway_publish(
        self,
        bundle: RuntimeIngressBundleReport,
    ) -> RuntimeIngressGatewayPublishReport:
        config = self._runtime_ingress_gateway_runtime_config()
        endpoints = [str(item).strip() for item in list(config.get("endpoints") or []) if str(item).strip()]
        notes = [
            f"gatewayMode=external",
            f"authSource={config.get('authSource') or 'config'}",
            f"strictRoutesOnly={str(bundle.strict_routes_only).lower()}",
        ]
        if not endpoints:
            return RuntimeIngressGatewayPublishReport(
                generated_at=utcnow(),
                project_id=bundle.project_id,
                strict_routes_only=bundle.strict_routes_only,
                status="blocked",
                failure_code="RUNTIME_INGRESS_GATEWAY_ENDPOINT_MISSING",
                retryable=False,
                message="Runtime ingress gateway endpoint is not configured.",
                gateway_mode="external",
                auth_source=config.get("authSource") or "config",
                notes=[*notes, "blocked=runtime_ingress_gateway_endpoint_missing"],
            )
        payload = {
            "projectId": bundle.project_id,
            "strictRoutesOnly": bundle.strict_routes_only,
            "bundleReady": bundle.bundle_ready,
            "runtimeEdgeExport": bundle.runtime_edge_export.model_dump(mode="json", by_alias=True),
            "runtimeEdgeGateway": bundle.runtime_edge_gateway.model_dump(mode="json", by_alias=True),
            "runtimeEdgeDeploymentHistory": bundle.runtime_edge_deployment_history.model_dump(mode="json", by_alias=True),
            "visualFarmGateway": bundle.visual_farm_gateway.model_dump(mode="json", by_alias=True),
            "visualFarmDeploymentHistory": bundle.visual_farm_deployment_history.model_dump(mode="json", by_alias=True),
            "visualFarmStatus": bundle.visual_farm_status.model_dump(mode="json", by_alias=True),
            "notes": list(bundle.notes),
        }
        headers = {"Content-Type": "application/json", "Accept": "application/json"}
        token = str(config.get("token") or "").strip()
        if token:
            headers[str(config.get("authHeader") or "Authorization")] = f"Bearer {token}"
        timeout_seconds = max(1, int(int(config.get("timeoutMs") or self.settings.runtime_ingress_gateway_timeout_ms) / 1000))
        attempts: list[dict[str, Any]] = []
        for endpoint in endpoints:
            request = Request(
                endpoint,
                data=json.dumps(payload, ensure_ascii=True).encode("utf-8"),
                headers=headers,
                method="POST",
            )
            try:
                with urlopen(request, timeout=timeout_seconds) as response:  # nosec - configurable outbound ingress publish gateway
                    raw_body = response.read().decode("utf-8") if hasattr(response, "read") else ""
                    response_payload = json.loads(raw_body) if raw_body.strip() else {}
                    gateway_artifact_id = (
                        response_payload.get("artifactId")
                        or response_payload.get("deploymentId")
                        or response_payload.get("gatewayArtifactId")
                    )
                    gateway_url = response_payload.get("artifactUrl") or response_payload.get("url")
                    message = str(
                        response_payload.get("message")
                        or "Runtime ingress bundle published via external gateway endpoint."
                    )
                    resolved_notes = [
                        *notes,
                        f"gatewayEndpoint={endpoint}",
                        f"httpStatus={getattr(response, 'status', '200')}",
                        f"artifactId={gateway_artifact_id or ''}",
                        f"endpointAttempts={len(attempts) + 1}/{len(endpoints)}",
                    ]
                    if attempts:
                        resolved_notes.append("gatewayFailover=true")
                        resolved_notes.extend(
                            [
                                f"previousAttempt[{idx + 1}]={item['endpoint']}|{item['failureCode']}"
                                for idx, item in enumerate(attempts)
                            ]
                        )
                    return RuntimeIngressGatewayPublishReport(
                        generated_at=utcnow(),
                        project_id=bundle.project_id,
                        strict_routes_only=bundle.strict_routes_only,
                        status="completed",
                        gateway_endpoint=endpoint,
                        gateway_url=str(gateway_url).strip() or None,
                        gateway_artifact_id=str(gateway_artifact_id).strip() or None,
                        gateway_mode="external",
                        auth_source=config.get("authSource") or "config",
                        message=message,
                        notes=resolved_notes,
                    )
            except HTTPError as exc:
                attempts.append(
                    {
                        "endpoint": endpoint,
                        "failureCode": f"RUNTIME_INGRESS_GATEWAY_HTTP_{getattr(exc, 'code', 'ERROR')}",
                        "retryable": 500 <= int(getattr(exc, "code", 0) or 0) < 600,
                        "detail": f"httpError={getattr(exc, 'code', 'unknown')}",
                    }
                )
            except Exception as exc:
                attempts.append(
                    {
                        "endpoint": endpoint,
                        "failureCode": "RUNTIME_INGRESS_GATEWAY_REQUEST_FAILED",
                        "retryable": True,
                        "detail": f"error={exc}",
                    }
                )
        last = attempts[-1] if attempts else {
            "endpoint": None,
            "failureCode": "RUNTIME_INGRESS_GATEWAY_REQUEST_FAILED",
            "retryable": True,
            "detail": "error=unknown",
        }
        return RuntimeIngressGatewayPublishReport(
            generated_at=utcnow(),
            project_id=bundle.project_id,
            strict_routes_only=bundle.strict_routes_only,
            status="failed",
            failure_code=str(last.get("failureCode") or "RUNTIME_INGRESS_GATEWAY_REQUEST_FAILED"),
            retryable=bool(last.get("retryable", True)),
            gateway_endpoint=str(last.get("endpoint") or "").strip() or None,
            gateway_mode="external",
            auth_source=config.get("authSource") or "config",
            message=(
                f"Runtime ingress gateway request failed across {len(endpoints)} endpoint(s); "
                f"last failure={str(last.get('failureCode') or 'RUNTIME_INGRESS_GATEWAY_REQUEST_FAILED')}."
            ),
            notes=[
                *notes,
                f"endpointsConfigured={len(endpoints)}",
                *[
                    f"attempt[{idx + 1}]={item['endpoint']}|{item['failureCode']}|retryable={str(bool(item['retryable'])).lower()}|{item['detail']}"
                    for idx, item in enumerate(attempts)
                ],
            ],
        )

