    def build_runtime_ingress_bundle_report(
        self,
        *,
        project_id: Optional[str] = None,
        strict_routes_only: Optional[bool] = None,
    ) -> RuntimeIngressBundleReport:
        strict = bool(self.settings.strict_providers) if strict_routes_only is None else bool(strict_routes_only)
        projects = self.list_projects()
        if project_id:
            projects = [project for project in projects if project.project_id == project_id]
        runtime_edge_route_map = self.build_workspace_runtime_edge_route_map_report(
            project_id=project_id,
            strict_routes_only=strict,
        )
        runtime_edge_export = self.build_runtime_edge_gateway_export_report(
            project_id=project_id,
            strict_routes_only=strict,
        )
        runtime_edge_gateway = self.build_runtime_edge_gateway_report(project_id=project_id)
        runtime_edge_history = self.get_runtime_edge_deployment_history(limit=20, project_id=project_id)
        visual_farm_gateway = self.build_visual_farm_gateway_report(project_id=project_id)
        visual_farm_history = self.get_visual_farm_deployment_history(limit=20, project_id=project_id)
        visual_farm_status = self.build_visual_farm_status_report(project_id=project_id)
        route_map_by_project_id = {item.project_id: item for item in runtime_edge_route_map.items}
        route_manifest_items: list[RuntimeIngressRouteManifestItem] = []
        runtime_ready_host_count = 0
        preview_only_host_count = 0
        blocked_host_count = 0
        manifest_project_ids: set[str] = set()
        for project_row in projects:
            route_item = route_map_by_project_id.get(project_row.project_id)
            try:
                config = self.build_project_runtime_edge_config(project_row.project_id)
            except Exception:
                config = None
            manifest_project_ids.add(project_row.project_id)
            if route_item is not None:
                execution_action = route_item.execution_action
                route_mode = route_item.route_mode
                runtime_ready = route_item.runtime_ready
                proxy_url = route_item.proxy_url
                health_url = route_item.health_url
                notes = list(route_item.notes)
                site_host = route_item.site_host
                public_path = route_item.public_path
                proxy_path = route_item.proxy_path
                strict_proxy_path = route_item.strict_proxy_path
                rewrite_rule = route_item.rewrite_rule
                upstream_host = route_item.upstream_host
            else:
                execution_action = "block"
                route_mode = "strict" if strict else "default"
                runtime_ready = False
                site_host = urlparse(project_row.url).hostname or ""
                public_path = "/"
                proxy_path = f"/api/projects/{project_row.project_id}/runtime-execute/proxy"
                strict_proxy_path = f"/api/projects/{project_row.project_id}/runtime-execute/proxy-strict"
                rewrite_rule = f"rewrite {project_row.url.rstrip('/') if project_row.url else '/'} -> {proxy_path}"
                upstream_host = urlparse(self._runtime_edge_api_base_url()).netloc or "127.0.0.1:8000"
                proxy_url = f"{self._runtime_edge_api_base_url()}/api/projects/{project_row.project_id}/runtime-execute/proxy"
                health_url = f"{self._runtime_edge_api_base_url()}/api/runtime-route/health?projectId={project_row.project_id}"
                notes = ["runtime_route_unavailable", "manifest_fallback"]
            if execution_action == "serve_runtime":
                runtime_ready_host_count += 1
            elif execution_action == "serve_preview":
                preview_only_host_count += 1
            else:
                blocked_host_count += 1
            route_manifest_items.append(
                RuntimeIngressRouteManifestItem(
                    project_id=project_row.project_id,
                    project_name=project_row.name,
                    site_host=site_host,
                    public_path=public_path,
                    proxy_path=proxy_path,
                    strict_proxy_path=strict_proxy_path,
                    rewrite_rule=rewrite_rule,
                    upstream_host=upstream_host,
                    runtime_ready=runtime_ready,
                    execution_action=execution_action,
                    route_mode=route_mode,
                    proxy_url=proxy_url if config is not None or route_item is not None else proxy_url,
                    health_url=health_url,
                    notes=notes,
                )
            )
        route_manifest = RuntimeIngressRouteManifestReport(
            generated_at=utcnow(),
            project_id=project_id,
            strict_routes_only=strict,
            project_count=len(manifest_project_ids),
            host_count=len(route_manifest_items),
            runtime_ready_host_count=runtime_ready_host_count,
            preview_only_host_count=preview_only_host_count,
            blocked_host_count=blocked_host_count,
            items=route_manifest_items,
            warnings=list(runtime_edge_route_map.warnings),
            recommendations=list(runtime_edge_route_map.recommendations),
        )
        bundle_ready = bool(runtime_edge_export.host_count > 0 or visual_farm_gateway.route_count > 0)
        notes = [
            f"strictRoutesOnly={str(strict).lower()}",
            f"projectId={project_id or 'workspace'}",
            f"runtimeEdgeHosts={runtime_edge_export.host_count}",
            f"visualFarmRoutes={visual_farm_gateway.route_count}",
            f"routeManifestHosts={route_manifest.host_count}",
        ]
        notes.append(f"runtimeEdgeGatewayReady={str(runtime_edge_gateway.gateway_ready).lower()}")
        notes.append(f"visualFarmGatewayReady={str(visual_farm_gateway.gateway_ready).lower()}")
        notes.append(f"bundleReady={str(bundle_ready).lower()}")
        return RuntimeIngressBundleReport(
            generated_at=utcnow(),
            project_id=project_id,
            strict_routes_only=strict,
            runtime_edge_export=runtime_edge_export,
            runtime_edge_gateway=runtime_edge_gateway,
            route_manifest=route_manifest,
            runtime_edge_deployment_history=runtime_edge_history,
            visual_farm_gateway=visual_farm_gateway,
            visual_farm_deployment_history=visual_farm_history,
            visual_farm_status=visual_farm_status,
            bundle_ready=bundle_ready,
            notes=notes,
        )

    def publish_runtime_ingress_bundle(
        self,
        *,
        project_id: Optional[str] = None,
        strict_routes_only: Optional[bool] = None,
    ) -> RuntimeIngressBundleReport:
        bundle = self.build_runtime_ingress_bundle_report(
            project_id=project_id,
            strict_routes_only=strict_routes_only,
        )
        gateway_publish = self._execute_runtime_ingress_gateway_publish(bundle)
        bundle = bundle.model_copy(update={"gateway_publish": gateway_publish})
        self._runtime_ingress_bundle_path().write_text(bundle.model_dump_json(indent=2, by_alias=True), encoding="utf-8")
        route_manifest_path = self._runtime_ingress_route_manifest_path(
            project_id=project_id,
            strict_routes_only=strict_routes_only,
        )
        route_manifest_path.write_text(
            bundle.route_manifest.model_dump_json(indent=2, by_alias=True),
            encoding="utf-8",
        )
        bundle = bundle.model_copy(update={"notes": [*bundle.notes, f"routeManifestPath={route_manifest_path}"]})
        self._audit(
            "workspace",
            "",
            "runtime.ingress.bundle.published",
            {"bundle": bundle.model_dump(mode="json", by_alias=True)},
        )
        return bundle

    def execute_runtime_ingress_bundle_batch(
        self,
        request: RuntimeIngressBundleBatchRequest,
    ) -> RuntimeIngressBundleBatchReport:
        project_ids: list[str] = []
        for project_id in request.project_ids:
            normalized = str(project_id or "").strip()
            if normalized and normalized not in project_ids:
                project_ids.append(normalized)

        items: list[RuntimeIngressBundleReport] = []
        completed_count = 0
        blocked_count = 0
        failed_count = 0
        notes = [
            f"strictRoutesOnly={str(request.strict_routes_only).lower()}",
            f"projectCount={len(project_ids)}",
        ]
        if request.note:
            notes.append(f"note={request.note}")

        for project_id in project_ids:
            try:
                bundle = self.publish_runtime_ingress_bundle(
                    project_id=project_id,
                    strict_routes_only=request.strict_routes_only,
                )
            except Exception as exc:
                fallback = self.build_runtime_ingress_bundle_report(
                    project_id=project_id,
                    strict_routes_only=request.strict_routes_only,
                )
                bundle = fallback.model_copy(
                    update={
                        "gateway_publish": RuntimeIngressGatewayPublishReport(
                            generated_at=utcnow(),
                            project_id=project_id,
                            strict_routes_only=request.strict_routes_only,
                            status="failed",
                            failure_code="RUNTIME_INGRESS_BUNDLE_BATCH_FAILED",
                            retryable=True,
                            gateway_mode="external",
                            auth_source="none",
                            message=str(exc),
                            notes=[f"batchFailure={exc}"],
                        )
                    }
                )
            items.append(bundle)
            status = str(bundle.gateway_publish.status if bundle.gateway_publish is not None else "failed")
            if status == "completed":
                completed_count += 1
            elif status == "blocked":
                blocked_count += 1
            else:
                failed_count += 1

        batch = RuntimeIngressBundleBatchReport(
            batch_id=new_id("runtime-ingress-batch"),
            generated_at=utcnow(),
            strict_routes_only=request.strict_routes_only,
            actor=(request.actor or "ui").strip() or "ui",
            note=request.note,
            total_count=len(items),
            completed_count=completed_count,
            blocked_count=blocked_count,
            failed_count=failed_count,
            items=items,
            notes=notes,
        )
        self._audit(
            "workspace",
            "",
            "runtime.ingress.bundle.batch.executed",
            {"batch": batch.model_dump(mode="json", by_alias=True)},
        )
        return batch

    def get_runtime_ingress_bundle_batch_history(
        self,
        *,
        project_id: Optional[str] = None,
        limit: int = 20,
    ) -> RuntimeIngressBundleBatchHistoryReport:
        normalized_project_id = (project_id or "").strip() or None
        bounded_limit = max(1, min(int(limit), 100))
        with self.database.session() as session:
            rows = session.scalars(
                select(AuditRow)
                .where(AuditRow.action == "runtime.ingress.bundle.batch.executed")
                .order_by(AuditRow.created_at.desc())
                .limit(bounded_limit * 3)
            ).all()
        entries: list[RuntimeIngressBundleBatchHistoryEntry] = []
        for row in rows:
            payload = dict(row.payload_json or {})
            batch = payload.get("batch")
            if not isinstance(batch, dict):
                continue
            raw_items = batch.get("items")
            items = raw_items if isinstance(raw_items, list) else []
            project_ids: list[str] = []
            for item in items:
                if not isinstance(item, dict):
                    continue
                candidate = str(item.get("projectId") or "").strip()
                if candidate and candidate not in project_ids:
                    project_ids.append(candidate)
            if normalized_project_id and normalized_project_id not in project_ids:
                continue
            entries.append(
                RuntimeIngressBundleBatchHistoryEntry(
                    audit_id=str(row.id),
                    created_at=row.created_at,
                    actor=str(payload.get("actor") or row.actor or "ui"),
                    batch_id=str(batch.get("batchId") or ""),
                    strict_routes_only=bool(batch.get("strictRoutesOnly", False)),
                    total_count=int(batch.get("totalCount") or 0),
                    completed_count=int(batch.get("completedCount") or 0),
                    blocked_count=int(batch.get("blockedCount") or 0),
                    failed_count=int(batch.get("failedCount") or 0),
                    project_ids=project_ids,
                    notes=[str(item) for item in batch.get("notes", []) if str(item).strip()],
                )
            )
            if len(entries) >= bounded_limit:
                break
        return RuntimeIngressBundleBatchHistoryReport(
            generated_at=utcnow(),
            project_id=normalized_project_id,
            total=len(entries),
            completed_count=sum(item.completed_count for item in entries),
            blocked_count=sum(item.blocked_count for item in entries),
            failed_count=sum(item.failed_count for item in entries),
            entries=entries,
        )

    def build_runtime_ingress_bundle_batch_health_report(
        self,
        *,
        project_id: Optional[str] = None,
    ) -> RuntimeIngressBundleBatchHealthReport:
        normalized_project_id = (project_id or "").strip() or None
        history = self.get_runtime_ingress_bundle_batch_history(project_id=normalized_project_id, limit=1)
        latest = history.entries[0] if history.entries else None
        freshness_minutes = max(5, int(self.settings.monitor_window_minutes))
        notes: list[str] = [
            f"freshnessMinutes={freshness_minutes}",
            f"projectId={normalized_project_id or 'workspace'}",
        ]
        stale = True
        healthy = False
        if latest is None:
            notes.append("noRuntimeIngressBatchHistory=true")
        else:
            created_at = latest.created_at
            if created_at.tzinfo is None:
                created_at = created_at.replace(tzinfo=timezone.utc)
            now = utcnow()
            if now.tzinfo is None:
                now = now.replace(tzinfo=timezone.utc)
            stale = created_at < (now - timedelta(minutes=freshness_minutes))
            healthy = (not stale) and latest.failed_count == 0 and latest.blocked_count == 0 and latest.completed_count >= 1
            notes.extend(
                [
                    f"lastBatchId={latest.batch_id}",
                    f"lastBatchAt={created_at.isoformat()}",
                    f"lastFailedCount={latest.failed_count}",
                    f"lastBlockedCount={latest.blocked_count}",
                    f"lastCompletedCount={latest.completed_count}",
                    f"stale={str(stale).lower()}",
                    f"healthy={str(healthy).lower()}",
                ]
            )
        return RuntimeIngressBundleBatchHealthReport(
            generated_at=utcnow(),
            project_id=normalized_project_id,
            freshness_minutes=freshness_minutes,
            run_count=history.total,
            last_batch_id=latest.batch_id if latest else None,
            last_batch_at=latest.created_at if latest else None,
            last_total_count=latest.total_count if latest else 0,
            last_completed_count=latest.completed_count if latest else 0,
            last_blocked_count=latest.blocked_count if latest else 0,
            last_failed_count=latest.failed_count if latest else 0,
            healthy=healthy,
            stale=stale,
            notes=notes,
        )

    def _runtime_ingress_config_artifact_path(
        self,
        *,
        format: str,
        project_id: Optional[str] = None,
        strict_routes_only: Optional[bool] = None,
    ) -> Path:
        self.settings.state_dir.mkdir(parents=True, exist_ok=True)
        normalized_project_id = (project_id or "").strip() or "workspace"
        normalized_format = "nginx" if format.lower() == "nginx" else "caddy"
        strict_flag = bool(self.settings.strict_providers) if strict_routes_only is None else bool(strict_routes_only)
        strict_suffix = "strict" if strict_flag else "relaxed"
        return self.settings.state_dir / f"runtime-ingress-{normalized_project_id}-{strict_suffix}.{normalized_format}"

    def build_runtime_ingress_config_artifact_report(
        self,
        *,
        format: str,
        project_id: Optional[str] = None,
        strict_routes_only: Optional[bool] = None,
    ) -> RuntimeIngressConfigArtifactReport:
        normalized_format = "nginx" if format.lower() == "nginx" else "caddy"
        bundle = self.build_runtime_ingress_bundle_report(
            project_id=project_id,
            strict_routes_only=strict_routes_only,
        )
        content = (
            bundle.runtime_edge_export.nginx_map_conf
            if normalized_format == "nginx"
            else bundle.runtime_edge_export.caddyfile_fragment
        )
        artifact_path = self._runtime_ingress_config_artifact_path(
            format=normalized_format,
            project_id=project_id,
            strict_routes_only=strict_routes_only,
        )
        manifest_path = self._runtime_ingress_route_manifest_path(
            project_id=project_id,
            strict_routes_only=strict_routes_only,
        )
        notes = list(bundle.notes)
        if normalized_format == "nginx":
            notes.append("Use the generated map in an nginx server block with proxy_pass to $seo_ad_runtime_proxy.")
        else:
            notes.append("Use the generated fragment as a Caddy site block or import snippet.")
        notes.append(f"artifactPath={artifact_path}")
        notes.append(f"manifestPath={manifest_path}")
        return RuntimeIngressConfigArtifactReport(
            generated_at=utcnow(),
            project_id=project_id,
            strict_routes_only=bundle.strict_routes_only,
            format=normalized_format,
            artifact_path=str(artifact_path),
            manifest_path=str(manifest_path),
            content=content,
            bundle_ready=bundle.bundle_ready,
            notes=notes,
        )

    def publish_runtime_ingress_config_artifact(
        self,
        *,
        format: str,
        project_id: Optional[str] = None,
        strict_routes_only: Optional[bool] = None,
    ) -> RuntimeIngressConfigArtifactReport:
        artifact = self.build_runtime_ingress_config_artifact_report(
            format=format,
            project_id=project_id,
            strict_routes_only=strict_routes_only,
        )
        bundle = self.build_runtime_ingress_bundle_report(
            project_id=project_id,
            strict_routes_only=strict_routes_only,
        )
        gateway_publish = self._execute_runtime_ingress_config_gateway_publish(
            artifact=artifact,
            bundle=bundle,
        )
        path = Path(artifact.artifact_path)
        path.write_text(artifact.content, encoding="utf-8")
        manifest_path = Path(artifact.manifest_path) if artifact.manifest_path else None
        if manifest_path is not None:
            manifest_path.write_text(bundle.route_manifest.model_dump_json(indent=2, by_alias=True), encoding="utf-8")
        artifact = artifact.model_copy(update={"gateway_publish": gateway_publish})
        self._audit(
            "workspace",
            "",
            "runtime.ingress.config.published",
            {"artifact": artifact.model_dump(mode="json", by_alias=True)},
        )
        return artifact

    def get_runtime_ingress_config_artifact_history(
        self,
        *,
        format: Optional[str] = None,
        project_id: Optional[str] = None,
        limit: int = 20,
    ) -> RuntimeIngressConfigArtifactHistoryReport:
        normalized_project_id = (project_id or "").strip() or None
        normalized_format = (format or "").strip().lower() or None
        bounded_limit = max(1, min(int(limit), 100))
        with self.database.session() as session:
            rows = session.scalars(
                select(AuditRow)
                .where(AuditRow.action == "runtime.ingress.config.published")
                .order_by(AuditRow.created_at.desc())
                .limit(bounded_limit * 3)
            ).all()
        entries: list[RuntimeIngressConfigArtifactHistoryEntry] = []
        for row in rows:
            payload = dict(row.payload_json or {})
            artifact = payload.get("artifact")
            if not isinstance(artifact, dict):
                continue
            entry_project_id = artifact.get("projectId")
            entry_format = str(artifact.get("format") or "").strip().lower() or "nginx"
            if normalized_project_id and entry_project_id != normalized_project_id:
                continue
            if normalized_format and entry_format != normalized_format:
                continue
            entries.append(
                RuntimeIngressConfigArtifactHistoryEntry(
                    audit_id=str(row.id),
                    created_at=row.created_at,
                    actor=str(payload.get("actor") or row.actor or "ui"),
                    project_id=entry_project_id,
                    strict_routes_only=bool(artifact.get("strictRoutesOnly", False)),
                    format="caddy" if entry_format == "caddy" else "nginx",
                    artifact_path=str(artifact.get("artifactPath") or ""),
                    bundle_ready=bool(artifact.get("bundleReady", False)),
                    notes=[str(item) for item in artifact.get("notes", [])],
                )
            )
            if len(entries) >= bounded_limit:
                break
        return RuntimeIngressConfigArtifactHistoryReport(
            generated_at=utcnow(),
            project_id=normalized_project_id,
            format="caddy" if normalized_format == "caddy" else ("nginx" if normalized_format == "nginx" else None),
            total=len(entries),
            bundle_ready_count=sum(1 for item in entries if item.bundle_ready),
            entries=entries,
        )

    def probe_visual_farm(self, project_id: Optional[str] = None) -> VisualFarmProbeReport:
        def _classify_probe_signal(*, status: str, failure_code: str | None, retryable: bool) -> tuple[bool, str]:
            if status == "connected":
                return (False, "info")
            code = str(failure_code or "").strip().upper()
            if code in {"VISUAL_FARM_AUTH_INVALID", "VISUAL_FARM_PERMISSION_DENIED", "VISUAL_FARM_ENDPOINT_NOT_FOUND"}:
                return (True, "critical")
            if code in {"VISUAL_FARM_RATE_LIMITED", "VISUAL_FARM_REQUEST_TIMEOUT", "VISUAL_FARM_NETWORK_ERROR", "VISUAL_FARM_UNAVAILABLE"}:
                return (False, "warning")
            if retryable:
                return (False, "warning")
            return (True, "critical")

        timeout_ms = max(1000, int(self.settings.visual_farm_timeout_ms))
        timeout_sec = max(1, int(timeout_ms / 1000))
        token, auth_header, auth_source = self._visual_farm_runtime_credentials()
        access_token_configured = bool(token)
        strict_mode = bool(self.settings.visual_farm_strict)
        normalized_project_id = (project_id or "").strip() or None
        if normalized_project_id == "workspace":
            normalized_project_id = None
        audit_project_id = normalized_project_id or "workspace"
        if normalized_project_id is not None:
            with self.database.session() as session:
                project = session.get(ProjectRow, normalized_project_id)
                if project is None:
                    raise ValueError(f"Unknown project: {normalized_project_id}")
        endpoints: list[str] = []
        for item in str(self.settings.visual_farm_endpoints or "").replace("\n", ",").split(","):
            endpoint = item.strip()
            if endpoint and endpoint not in endpoints:
                endpoints.append(endpoint)
        single_endpoint = str(self.settings.visual_farm_endpoint or "").strip()
        if single_endpoint and single_endpoint not in endpoints:
            endpoints.append(single_endpoint)

        probes: list[VisualFarmEndpointProbe] = []
        notes: list[str] = []
        if not endpoints:
            notes.append("No visual farm endpoint configured.")
            report = VisualFarmProbeReport(
                strict_mode=strict_mode,
                project_id=normalized_project_id,
                configured_endpoint_count=0,
                probed_endpoint_count=0,
                connected_count=0,
                failed_count=0,
                not_configured_count=1,
                blocking_count=1,
                recoverable_count=0,
                access_token_configured=access_token_configured,
                auth_source=auth_source,
                timeout_ms=timeout_ms,
                probes=probes,
                notes=notes,
            )
            self._audit(
                audit_project_id,
                "",
                "visual_farm.probe.executed",
                {
                    "actor": "system",
                    "strictMode": report.strict_mode,
                    "projectId": report.project_id,
                    "configuredEndpointCount": report.configured_endpoint_count,
                    "probedEndpointCount": report.probed_endpoint_count,
                    "connectedCount": report.connected_count,
                    "failedCount": report.failed_count,
                    "notConfiguredCount": report.not_configured_count,
                    "blockingCount": report.blocking_count,
                    "recoverableCount": report.recoverable_count,
                    "accessTokenConfigured": report.access_token_configured,
                    "authSource": report.auth_source,
                    "timeoutMs": report.timeout_ms,
                    "probes": [item.model_dump(mode="json", by_alias=True) for item in report.probes],
                    "notes": list(report.notes),
                },
            )
            return report

        for endpoint in endpoints:
            started = time.perf_counter()
            request_headers = {"User-Agent": "SEO-AD-AutoPilot/1.0", "Accept": "application/json"}
            if token:
                request_headers[auth_header or "Authorization"] = f"Bearer {token}"
            request = Request(endpoint, headers=request_headers, method="GET")
            try:
                with urlopen(request, timeout=timeout_sec) as response:  # nosec - configured provider endpoint
                    status_code = int(getattr(response, "status", 200) or 200)
                latency_ms = int((time.perf_counter() - started) * 1000)
                probes.append(
                    VisualFarmEndpointProbe(
                        endpoint=endpoint,
                        status="connected",
                        latency_ms=latency_ms,
                        http_status=status_code,
                        retryable=False,
                        blocking=False,
                        alert_severity="info",
                        message="endpoint reachable",
                    )
                )
            except HTTPError as exc:
                status_code = int(getattr(exc, "code", 0) or 0)
                if status_code == 401:
                    failure_code = "VISUAL_FARM_AUTH_INVALID"
                    retryable = False
                elif status_code == 403:
                    failure_code = "VISUAL_FARM_PERMISSION_DENIED"
                    retryable = False
                elif status_code == 404:
                    failure_code = "VISUAL_FARM_ENDPOINT_NOT_FOUND"
                    retryable = False
                elif status_code == 429:
                    failure_code = "VISUAL_FARM_RATE_LIMITED"
                    retryable = True
                elif status_code >= 500:
                    failure_code = "VISUAL_FARM_UNAVAILABLE"
                    retryable = True
                else:
                    failure_code = "VISUAL_FARM_HTTP_ERROR"
                    retryable = False
                blocking, alert_severity = _classify_probe_signal(status="failed", failure_code=failure_code, retryable=retryable)
                probes.append(
                    VisualFarmEndpointProbe(
                        endpoint=endpoint,
                        status="failed",
                        latency_ms=int((time.perf_counter() - started) * 1000),
                        http_status=status_code or None,
                        failure_code=failure_code,
                        retryable=retryable,
                        blocking=blocking,
                        alert_severity=alert_severity,
                        message=str(exc),
                    )
                )
            except Exception as exc:
                message = str(exc).lower()
                if "timeout" in message:
                    failure_code = "VISUAL_FARM_REQUEST_TIMEOUT"
                    retryable = True
                elif "name or service not known" in message or "temporary failure in name resolution" in message:
                    failure_code = "VISUAL_FARM_NETWORK_ERROR"
                    retryable = True
                elif "connection refused" in message or "connection reset" in message:
                    failure_code = "VISUAL_FARM_NETWORK_ERROR"
                    retryable = True
                else:
                    failure_code = "VISUAL_FARM_REQUEST_FAILED"
                    retryable = True
                blocking, alert_severity = _classify_probe_signal(status="failed", failure_code=failure_code, retryable=retryable)
                probes.append(
                    VisualFarmEndpointProbe(
                        endpoint=endpoint,
                        status="failed",
                        latency_ms=int((time.perf_counter() - started) * 1000),
                        failure_code=failure_code,
                        retryable=retryable,
                        blocking=blocking,
                        alert_severity=alert_severity,
                        message=str(exc),
                    )
                )

        connected_count = sum(1 for item in probes if item.status == "connected")
        failed_count = sum(1 for item in probes if item.status == "failed")
        blocking_count = sum(1 for item in probes if item.blocking)
        recoverable_count = sum(1 for item in probes if item.status == "failed" and not item.blocking)
        if failed_count > 0:
            notes.append("Some visual farm endpoints failed probe; inspect failureCode and retryable fields.")
        if strict_mode and connected_count == 0:
            notes.append("visual_farm_strict=true and no endpoint is connected; strict visual checks will block release.")
        if not access_token_configured:
            notes.append("Visual farm access token is not configured.")
        report = VisualFarmProbeReport(
            strict_mode=strict_mode,
            project_id=normalized_project_id,
            configured_endpoint_count=len(endpoints),
            probed_endpoint_count=len(probes),
            connected_count=connected_count,
            failed_count=failed_count,
            not_configured_count=0,
            blocking_count=blocking_count,
            recoverable_count=recoverable_count,
            access_token_configured=access_token_configured,
            auth_source=auth_source,
            timeout_ms=timeout_ms,
            probes=probes,
            notes=notes,
        )
        self._audit(
            audit_project_id,
            "",
            "visual_farm.probe.executed",
            {
                "actor": "system",
                "strictMode": report.strict_mode,
                "projectId": report.project_id,
                "configuredEndpointCount": report.configured_endpoint_count,
                "probedEndpointCount": report.probed_endpoint_count,
                "connectedCount": report.connected_count,
                "failedCount": report.failed_count,
                "notConfiguredCount": report.not_configured_count,
                "blockingCount": report.blocking_count,
                "recoverableCount": report.recoverable_count,
                "accessTokenConfigured": report.access_token_configured,
                "authSource": report.auth_source,
                "timeoutMs": report.timeout_ms,
                "probes": [item.model_dump(mode="json", by_alias=True) for item in report.probes],
                "notes": list(report.notes),
            },
        )
        return report

    def enqueue_visual_farm_probe(
        self,
        *,
        actor: str = "settings-ui",
        project_id: Optional[str] = None,
        task_id: Optional[str] = None,
    ) -> VisualFarmProbeEnqueueResult:
        payload: dict[str, Any] = {
            "stage": "visual_farm_probe",
            "actor": actor,
        }
        normalized_project_id = (project_id or "").strip() or "workspace"
        if project_id and project_id.strip():
            payload["projectId"] = project_id.strip()
        if task_id and task_id.strip():
            payload["taskId"] = task_id.strip()
        job = WorkerJob(
            job_id=new_id("job"),
            stage="visual_farm_probe",
            project_id=normalized_project_id,
            task_id=(task_id or "").strip(),
            payload=payload,
        )
        enqueued = self.job_queue.enqueue(job)
        if enqueued:
            self._audit(
                job.project_id,
                job.task_id,
                "worker.job.enqueued",
                {"actor": actor, **payload, "jobId": job.job_id},
            )
            message = "Visual farm probe job has been enqueued."
        else:
            self._audit(
                job.project_id,
                job.task_id,
                "worker.job.skipped_duplicate",
                {"actor": actor, **payload, "jobId": job.job_id, "fingerprint": job.fingerprint()},
            )
            message = "Visual farm probe job already queued; skipped duplicate enqueue."
        return VisualFarmProbeEnqueueResult(
            enqueued=enqueued,
            skipped_duplicate=not enqueued,
            job_id=job.job_id,
            stage=job.stage,
            message=message,
        )

    def enqueue_runtime_ingress_bundle_batch(
        self,
        request: RuntimeIngressBundleBatchRequest,
        *,
        actor: str = "settings-ui",
    ) -> RuntimeIngressBundleBatchEnqueueResult:
        project_ids: list[str] = []
        for item in request.project_ids:
            normalized = str(item or "").strip()
            if normalized and normalized not in project_ids:
                project_ids.append(normalized)
        payload: dict[str, Any] = {
            "stage": "runtime_ingress_bundle_batch",
            "projectIds": project_ids,
            "strictRoutesOnly": bool(request.strict_routes_only),
            "actor": (request.actor or actor).strip() or actor,
        }
        if request.note and request.note.strip():
            payload["note"] = request.note.strip()
        job = WorkerJob(
            job_id=new_id("job"),
            stage="runtime_ingress_bundle_batch",
            project_id="workspace",
            task_id="runtime_ingress_bundle_batch",
            payload=payload,
        )
        enqueued = self.job_queue.enqueue(job)
        if enqueued:
            self._audit(
                job.project_id,
                job.task_id,
                "worker.job.enqueued",
                {"actor": payload["actor"], **payload, "jobId": job.job_id},
            )
            message = "Runtime ingress bundle batch job has been enqueued."
        else:
            self._audit(
                job.project_id,
                job.task_id,
                "worker.job.skipped_duplicate",
                {
                    "actor": payload["actor"],
                    **payload,
                    "jobId": job.job_id,
                    "fingerprint": job.fingerprint(),
                },
            )
            message = "Runtime ingress bundle batch job already queued; skipped duplicate enqueue."
        return RuntimeIngressBundleBatchEnqueueResult(
            enqueued=enqueued,
            skipped_duplicate=not enqueued,
            job_id=job.job_id,
            stage=job.stage,
            strict_routes_only=bool(request.strict_routes_only),
            project_ids=project_ids,
            message=message,
        )

