    def get_visual_farm_probe_history(
        self,
        limit: int = 20,
        *,
        project_id: Optional[str] = None,
        strict_mode: Optional[bool] = None,
    ) -> VisualFarmProbeHistoryReport:
        normalized_project_id = (project_id or "").strip() or None
        with self.database.session() as session:
            rows = session.scalars(
                select(AuditRow)
                .where(AuditRow.action == "visual_farm.probe.executed")
                .order_by(AuditRow.created_at.desc())
                .limit(200)
            ).all()
        entries: list[VisualFarmProbeHistoryEntry] = []
        for row in rows:
            payload = dict(row.payload_json or {})
            if normalized_project_id is not None and row.project_id != normalized_project_id:
                continue
            payload_strict_mode = bool(payload.get("strictMode", False))
            if strict_mode is not None and payload_strict_mode != strict_mode:
                continue
            raw_probes = payload.get("probes") or []
            probes: list[VisualFarmEndpointProbe] = []
            if isinstance(raw_probes, list):
                for item in raw_probes:
                    if isinstance(item, dict):
                        probes.append(VisualFarmEndpointProbe.model_validate(item))
            entries.append(
                VisualFarmProbeHistoryEntry(
                    audit_id=row.id,
                    actor=row.actor,
                    created_at=row.created_at,
                    strict_mode=payload_strict_mode,
                    project_id=row.project_id,
                    configured_endpoint_count=int(payload.get("configuredEndpointCount") or 0),
                    probed_endpoint_count=int(payload.get("probedEndpointCount") or 0),
                    connected_count=int(payload.get("connectedCount") or 0),
                    failed_count=int(payload.get("failedCount") or 0),
                    not_configured_count=int(payload.get("notConfiguredCount") or 0),
                    blocking_count=int(payload.get("blockingCount") or 0),
                    recoverable_count=int(payload.get("recoverableCount") or 0),
                    access_token_configured=bool(payload.get("accessTokenConfigured", False)),
                    auth_source=str(payload.get("authSource") or "none"),
                    timeout_ms=int(payload.get("timeoutMs") or 0),
                    probes=probes,
                    notes=[str(item) for item in payload.get("notes", [])],
                    span_id=str(payload.get("spanId") or "") or None,
                    trace_id=str(payload.get("traceId") or "") or None,
                )
            )
            if len(entries) >= max(1, int(limit)):
                break
        summary = VisualFarmHistorySummary(
            total_count=len(entries),
            strict_mode_count=sum(1 for item in entries if item.strict_mode),
            connected_count=sum(item.connected_count for item in entries),
            failed_count=sum(item.failed_count for item in entries),
            blocking_count=sum(item.blocking_count for item in entries),
            recoverable_count=sum(item.recoverable_count for item in entries),
        )
        return VisualFarmProbeHistoryReport(
            project_id=normalized_project_id,
            strict_mode=strict_mode,
            summary=summary,
            entries=entries,
        )

    def _visual_failure_category(self, case: VisualRegressionCase) -> tuple[str, str]:
        if case.provider_status == "not_configured":
            return ("config", case.provider_failure_code or "VISUAL_FARM_NOT_CONFIGURED")
        if case.visual_farm_strict_blocked:
            code = case.provider_failure_code or "VISUAL_FARM_STRICT_BLOCKED"
            return ("config", code)
        if case.provider_status == "fallback":
            code = case.provider_failure_code or "VISUAL_FARM_FALLBACK"
            return ("unavailable", code)
        code = case.provider_failure_code or "VISUAL_FARM_FAILED"
        category = self._failure_category(code)
        if category == "other" and case.provider_status == "failed":
            category = "unavailable"
        return (category, code)

    def _visual_failure_retryable(self, category: str) -> bool:
        return category in {"network", "rate_limit", "unavailable", "other"}

    def _visual_failure_action(self, category: str) -> tuple[str, Optional[str]]:
        if category in {"auth", "permission"}:
            return ("Rotate visual farm credentials and re-run protected screenshot jobs.", "/settings")
        if category == "config":
            return ("Fix visual farm endpoint configuration before next strict run.", "/settings")
        if category in {"network", "rate_limit", "unavailable"}:
            return ("Retry visual run after provider/network recovery window.", "/monitor?focus=retry&category=network")
        if category == "validation":
            return ("Validate visual farm request payload and endpoint contract.", "/quality")
        return ("Inspect visual farm provider logs and re-run the failed samples.", "/quality")

    def _build_visual_failure_buckets(self, cases: list[VisualRegressionCase]) -> list[VisualRegressionFailureBucket]:
        buckets: dict[str, dict[str, Any]] = {}
        for case in cases:
            if case.provider_status == "connected":
                continue
            category, failure_code = self._visual_failure_category(case)
            bucket = buckets.setdefault(
                category,
                {"count": 0, "failureCodes": set(), "sampleIds": set()},
            )
            bucket["count"] += 1
            bucket["failureCodes"].add(failure_code)
            bucket["sampleIds"].add(case.sample_id)
        results: list[VisualRegressionFailureBucket] = []
        for category, payload in sorted(buckets.items(), key=lambda item: (-int(item[1]["count"]), item[0])):
            action, quick_path = self._visual_failure_action(category)
            results.append(
                VisualRegressionFailureBucket(
                    category=category,
                    count=int(payload["count"]),
                    retryable=self._visual_failure_retryable(category),
                    failure_codes=sorted(str(code) for code in payload["failureCodes"] if str(code).strip()),
                    sample_ids=sorted(str(sample_id) for sample_id in payload["sampleIds"] if str(sample_id).strip()),
                    suggested_action=action,
                    quick_action_path=quick_path,
                )
            )
        return results

    def build_skill_regression_report(self) -> SkillRegressionReport:
        return build_skill_regression_report()

    def _market_source_config(self) -> list[tuple[ConnectorKind, str]]:
        return [
            (ConnectorKind.trend, self.settings.trend_provider_url),
            (ConnectorKind.news, self.settings.news_provider_url),
            (ConnectorKind.qa, self.settings.qa_provider_url),
        ]

    def build_market_evidence_provider_status_report(self) -> MarketEvidenceProviderStatusReport:
        entries: list[MarketEvidenceProviderStatus] = []
        configured_count = 0
        auth_configured_count = 0
        strict_ready_count = 0
        for provider, endpoint in self._market_source_config():
            token, auth_source, auth_header = self._market_provider_auth(provider)
            configured = bool(str(endpoint or "").strip())
            auth_configured = bool(str(token or "").strip())
            strict_ready = configured and auth_configured
            fallback_reason = None
            notes: list[str] = []
            if not configured:
                fallback_reason = "missing provider endpoint"
                notes.append("Provider endpoint is not configured.")
            if not auth_configured:
                fallback_reason = fallback_reason or "missing provider auth"
                notes.append("Provider auth token or credentials are not configured.")
            if strict_ready:
                notes.append("Provider is ready for strict market evidence refreshes.")
            entries.append(
                MarketEvidenceProviderStatus(
                    provider=provider,
                    provider_label=provider.value.replace("_", " ").title(),
                    endpoint=str(endpoint or "").strip() or None,
                    configured=configured,
                    auth_configured=auth_configured,
                    auth_header=auth_header,
                    auth_source=auth_source,
                    strict_ready=strict_ready,
                    fallback_reason=fallback_reason,
                    notes=notes,
                )
            )
            configured_count += int(configured)
            auth_configured_count += int(auth_configured)
            strict_ready_count += int(strict_ready)
        notes = [
            "Market evidence providers are resolved from settings first, then used by connector refresh and analysis.",
            "Use the bulk market evidence refresh action to exercise trend/news/qa in one pass.",
        ]
        return MarketEvidenceProviderStatusReport(
            report_id=new_id("market-provider"),
            provider_count=len(entries),
            configured_count=configured_count,
            auth_configured_count=auth_configured_count,
            strict_ready_count=strict_ready_count,
            entries=entries,
            notes=notes,
        )

    def _attach_visual_regression_links(self, report: VisualRegressionReport) -> VisualRegressionReport:
        return report.model_copy(update={"cases": self._attach_visual_regression_links_to_cases(report.cases)})

    def _attach_visual_regression_links_to_cases(self, cases: list[VisualRegressionCase]) -> list[VisualRegressionCase]:
        if not cases:
            return []

        with self.database.session() as session:
            projects = session.scalars(select(ProjectRow)).all()
            tasks = session.scalars(select(TaskRow).order_by(TaskRow.updated_at.desc())).all()

        task_by_project: dict[str, TaskRow] = {}
        for task in tasks:
            task_by_project.setdefault(task.project_id, task)

        project_by_url: dict[str, ProjectRow] = {}
        project_by_name: dict[str, ProjectRow] = {}
        for project in projects:
            normalized_url = self._normalize_visual_case_url(project.url)
            if normalized_url:
                project_by_url.setdefault(normalized_url, project)
            project_by_name.setdefault(project.name.strip().lower(), project)

        enriched: list[VisualRegressionCase] = []
        for case in cases:
            project = project_by_url.get(self._normalize_visual_case_url(case.page_url)) or project_by_name.get(case.name.strip().lower())
            task = task_by_project.get(project.id) if project is not None else None
            deployment_artifact_ref = None
            deployment_record_id = None
            if task is not None and task.deployment_json:
                deployment_artifact_ref = str(task.deployment_json.get("artifactRef") or "") or None
                deployment_record_id = str(task.deployment_json.get("deploymentId") or task.deployment_json.get("deployment_id") or "") or None
            enriched.append(
                case.model_copy(
                    update={
                        "project_id": project.id if project is not None else None,
                        "project_name": project.name if project is not None else None,
                        "workflow_task_id": task.id if task is not None else None,
                        "deployment_artifact_ref": deployment_artifact_ref,
                        "deployment_record_id": deployment_record_id,
                    }
                )
            )
        return enriched

    def _build_visual_run_metrics_update(self, *, cases: list[VisualRegressionCase], strict_mode: bool) -> dict[str, Any]:
        attempted_endpoints = sorted(
            {
                str(attempt.get("endpoint"))
                for case in cases
                for attempt in (case.provider_attempts or [])
                if isinstance(attempt, dict) and attempt.get("endpoint")
            }
        )
        failed_endpoints = sorted(
            {
                str(attempt.get("endpoint"))
                for case in cases
                for attempt in (case.provider_attempts or [])
                if isinstance(attempt, dict)
                and attempt.get("endpoint")
                and str(attempt.get("status") or "").lower() not in {"connected", "ok", "success", "completed"}
            }
        )
        farm_latency_values = [int(case.visual_farm_latency_ms) for case in cases if case.visual_farm_latency_ms is not None]
        provider_candidates = [str(case.visual_farm_provider or "").strip() for case in cases if str(case.visual_farm_provider or "").strip()]
        project_ids = sorted({str(case.project_id).strip() for case in cases if str(case.project_id or "").strip()})
        workflow_task_ids = sorted({str(case.workflow_task_id).strip() for case in cases if str(case.workflow_task_id or "").strip()})
        deployment_artifact_refs = sorted(
            {str(case.deployment_artifact_ref).strip() for case in cases if str(case.deployment_artifact_ref or "").strip()}
        )
        deployment_record_ids = sorted(
            {str(case.deployment_record_id).strip() for case in cases if str(case.deployment_record_id or "").strip()}
        )

        return {
            "strict_mode": strict_mode,
            "sample_count": len(cases),
            "pass_count": sum(1 for case in cases if case.passed),
            "fail_count": sum(1 for case in cases if not case.passed),
            "average_diff_percent": round(sum(case.actual_diff_percent for case in cases) / max(len(cases), 1), 2) if cases else 0.0,
            "farm_provider": provider_candidates[0] if provider_candidates else None,
            "connected_case_count": sum(1 for case in cases if case.provider_status == "connected"),
            "strict_blocked_case_count": sum(1 for case in cases if case.visual_farm_strict_blocked),
            "failed_case_count": sum(1 for case in cases if case.provider_status == "failed"),
            "fallback_case_count": sum(1 for case in cases if case.provider_status == "fallback"),
            "not_configured_case_count": sum(1 for case in cases if case.provider_status == "not_configured"),
            "attempted_endpoint_count": len(attempted_endpoints),
            "attempted_endpoints": attempted_endpoints,
            "failed_endpoints": failed_endpoints,
            "provider_attempt_count": sum(len(case.provider_attempts or []) for case in cases),
            "average_farm_latency_ms": int(sum(farm_latency_values) / len(farm_latency_values)) if farm_latency_values else None,
            "project_ids": project_ids,
            "workflow_task_ids": workflow_task_ids,
            "deployment_artifact_refs": deployment_artifact_refs,
            "deployment_record_ids": deployment_record_ids,
            "cases": cases,
        }

    def _normalize_visual_case_url(self, value: str) -> str:
        parsed = urlparse((value or "").strip())
        if not parsed.scheme and not parsed.netloc:
            return (value or "").strip().rstrip("/").lower()
        path = parsed.path.rstrip("/") or "/"
        return f"{parsed.netloc.lower()}{path.lower()}"

    def _resolve_auth_secret_with_header(self, raw_value: str, source_label: str) -> tuple[str, str, str]:
        normalized = str(raw_value or "").strip()
        if not normalized:
            return "", "Authorization", "none"
        if normalized[:1] not in {"{", "["}:
            return normalized, "Authorization", source_label
        try:
            parsed = json.loads(normalized)
        except Exception:
            return normalized, "Authorization", source_label
        auth_header = "Authorization"
        candidates: list[Any] = []
        if isinstance(parsed, dict):
            auth_header = str(parsed.get("authHeader") or parsed.get("headerName") or auth_header).strip() or "Authorization"
            candidates.extend(
                [
                    parsed.get("accessToken"),
                    parsed.get("access_token"),
                    parsed.get("token"),
                    parsed.get("authToken"),
                    parsed.get("privateKey"),
                ]
            )
            credentials = parsed.get("credentials")
            if isinstance(credentials, dict):
                candidates.extend(
                    [
                        credentials.get("accessToken"),
                        credentials.get("access_token"),
                        credentials.get("token"),
                        credentials.get("authToken"),
                    ]
                )
        for candidate in candidates:
            token = str(candidate or "").strip()
            if token:
                return token, auth_header, f"{source_label}:json"
        return normalized, auth_header, f"{source_label}:json"

    def _market_provider_auth(self, provider: ConnectorKind) -> tuple[str, str, str]:
        provider_credentials_json = {
            ConnectorKind.trend: self.settings.trend_provider_credentials_json,
            ConnectorKind.news: self.settings.news_provider_credentials_json,
            ConnectorKind.qa: self.settings.qa_provider_credentials_json,
        }.get(provider, "")
        token, header, source = self._resolve_auth_secret_with_header(
            str(provider_credentials_json or "").strip(),
            "settings:provider:credentialsJson",
        )
        if token:
            return token, source, header

        provider_service_account_json = {
            ConnectorKind.trend: self.settings.trend_provider_service_account_json,
            ConnectorKind.news: self.settings.news_provider_service_account_json,
            ConnectorKind.qa: self.settings.qa_provider_service_account_json,
        }.get(provider, "")
        token, header, source = self._resolve_auth_secret_with_header(
            str(provider_service_account_json or "").strip(),
            "settings:provider:serviceAccountJson",
        )
        if token:
            return token, source, header

        provider_key = {
            ConnectorKind.trend: self.settings.trend_provider_access_token,
            ConnectorKind.news: self.settings.news_provider_access_token,
            ConnectorKind.qa: self.settings.qa_provider_access_token,
        }.get(provider, "")
        token, header, source = self._resolve_auth_secret_with_header(str(provider_key or "").strip(), "settings:provider")
        if token:
            return token, source, header

        token, header, source = self._resolve_auth_secret_with_header(
            str(self.settings.market_provider_credentials_json or "").strip(),
            "settings:shared:credentialsJson",
        )
        if token:
            return token, source, header

        token, header, source = self._resolve_auth_secret_with_header(
            str(self.settings.market_provider_service_account_json or "").strip(),
            "settings:shared:serviceAccountJson",
        )
        if token:
            return token, source, header

        token, header, source = self._resolve_auth_secret_with_header(
            str(self.settings.market_provider_access_token or "").strip(),
            "settings:shared",
        )
        if token:
            return token, source, header

        env_specific = {
            ConnectorKind.trend: "SEO_AD_BOT_TREND_PROVIDER_ACCESS_TOKEN",
            ConnectorKind.news: "SEO_AD_BOT_NEWS_PROVIDER_ACCESS_TOKEN",
            ConnectorKind.qa: "SEO_AD_BOT_QA_PROVIDER_ACCESS_TOKEN",
        }.get(provider, "")
        if env_specific:
            token, header, source = self._resolve_auth_secret_with_header(
                str(os.getenv(env_specific, "")).strip(),
                f"env:{env_specific}",
            )
            if token:
                return token, source, header

        token, header, source = self._resolve_auth_secret_with_header(
            str(os.getenv("SEO_AD_BOT_MARKET_PROVIDER_ACCESS_TOKEN", "")).strip(),
            "env:SEO_AD_BOT_MARKET_PROVIDER_ACCESS_TOKEN",
        )
        if token:
            return token, source, header
        return "", "none", "Authorization"

    def _split_market_endpoints(self, raw: str) -> list[str]:
        if not raw:
            return []
        items: list[str] = []
        for part in raw.replace("\n", ",").split(","):
            endpoint = part.strip()
            if endpoint:
                items.append(endpoint)
        return items

    def _collect_market_evidence(
        self,
        intake: SiteIntake,
        providers: Optional[set[ConnectorKind]] = None,
    ) -> list[SourceEvidence]:
        evidence: list[SourceEvidence] = []
        strict = bool(self.settings.strict_providers)
        for provider, raw_endpoints in self._market_source_config():
            if providers is not None and provider not in providers:
                continue
            started = time.perf_counter()
            source_type = provider.value
            endpoints = self._split_market_endpoints(raw_endpoints)
            provider_token, auth_source, auth_header = self._market_provider_auth(provider)
            timeout_sec = max(1, int(self.settings.market_provider_timeout_ms / 1000))
            if not endpoints:
                status = ConnectorStatus.synthetic
                failure_code = None
                fallback_reason = "provider endpoint not configured"
                if strict:
                    status = ConnectorStatus.unavailable
                    failure_code = f"{provider.value.upper()}_PROVIDER_MISSING"
                entry = SourceEvidence(
                    provider=provider,
                    status=status,
                    summary=f"{provider.value} source is not configured; fallback evidence generated.",
                    provenance=["synthetic", f"source={provider.value}"],
                    details={
                        "keywords": list(intake.keywords[:5]),
                        "siteUrl": intake.url,
                        "authSource": auth_source,
                        "endpointsConfigured": [],
                        "endpointsTried": [],
                    },
                    source_type=source_type,  # type: ignore[arg-type]
                    source_ref=None,
                    fallback_reason=fallback_reason,
                    failure_code=failure_code,
                    retryable=False,
                    auth_source=auth_source,
                    latency_ms=int((time.perf_counter() - started) * 1000),
                )
                evidence.append(entry)
                continue
            attempts: list[dict[str, Any]] = []
            connected_payload: Optional[dict[str, Any]] = None
            connected_endpoint: Optional[str] = None
            for endpoint in endpoints:
                endpoint_started = time.perf_counter()
                try:
                    request_headers = {"User-Agent": "SEO-AD-AutoPilot/1.0", "Accept": "application/json"}
                    if provider_token:
                        request_headers[auth_header or "Authorization"] = f"Bearer {provider_token}"
                    request = Request(endpoint, headers=request_headers)
                    with urlopen(request, timeout=timeout_sec) as response:  # nosec - provider read-only call
                        body = response.read().decode("utf-8", errors="replace")
                    payload = json.loads(body) if body else {}
                    connected_payload = payload if isinstance(payload, dict) else {"raw": body[:240]}
                    connected_endpoint = endpoint
                    attempts.append(
                        {
                            "endpoint": endpoint,
                            "status": "connected",
                            "payloadKeys": sorted(list(connected_payload.keys()))[:20],
                            "authSource": auth_source,
                            "latencyMs": int((time.perf_counter() - endpoint_started) * 1000),
                        }
                    )
                    break
                except HTTPError as exc:
                    attempts.append(
                        {
                            "endpoint": endpoint,
                            "status": "error",
                            "failureCode": f"{provider.value.upper()}_HTTP_ERROR",
                            "fallbackReason": f"HTTP {getattr(exc, 'code', 'unknown')}",
                            "retryable": 500 <= int(getattr(exc, "code", 0) or 0) < 600,
                            "authSource": auth_source,
                            "latencyMs": int((time.perf_counter() - endpoint_started) * 1000),
                        }
                    )
                except Exception as exc:
                    attempts.append(
                        {
                            "endpoint": endpoint,
                            "status": "error",
                            "failureCode": f"{provider.value.upper()}_REQUEST_FAILED",
                            "fallbackReason": str(exc),
                            "retryable": True,
                            "authSource": auth_source,
                            "latencyMs": int((time.perf_counter() - endpoint_started) * 1000),
                        }
                    )

            if connected_payload is not None and connected_endpoint is not None:
                ref = str(connected_payload.get("id") or connected_payload.get("ref") or connected_payload.get("url") or connected_endpoint)
                source_ref = f"{provider.value}:{ref}"
                evidence.append(
                    SourceEvidence(
                        provider=provider,
                        status=ConnectorStatus.connected,
                        summary=f"{provider.value} source returned evidence from {connected_endpoint}.",
                        provenance=[f"endpoint={connected_endpoint}", f"attempts={len(attempts)}", "mode=live"],
                        details={
                            "sample": connected_payload,
                            "attempts": attempts,
                            "authSource": auth_source,
                            "endpointsConfigured": endpoints,
                            "endpointsTried": [item.get("endpoint") for item in attempts],
                            "selectedEndpoint": connected_endpoint,
                            "requestTimeoutMs": self.settings.market_provider_timeout_ms,
                        },
                        source_type=source_type,  # type: ignore[arg-type]
                        source_ref=source_ref,
                        retryable=True,
                        auth_source=auth_source,
                        latency_ms=int((time.perf_counter() - started) * 1000),
                    )
                )
            else:
                last = attempts[-1] if attempts else {}
                status = ConnectorStatus.error if strict else ConnectorStatus.synthetic
                fallback_reason = str(last.get("fallbackReason") or "all endpoints failed")
                failure_code = str(last.get("failureCode") or f"{provider.value.upper()}_REQUEST_FAILED")
                evidence.append(
                    SourceEvidence(
                        provider=provider,
                        status=status,
                        summary=(
                            f"{provider.value} source request failed across {len(endpoints)} endpoint(s)."
                            if strict
                            else f"{provider.value} source request failed across {len(endpoints)} endpoint(s); synthetic fallback evidence generated."
                        ),
                        provenance=[f"attempts={len(attempts)}", "mode=synthetic" if not strict else "mode=strict-error"],
                        details={
                            "attempts": attempts,
                            "authSource": auth_source,
                            "endpointsConfigured": endpoints,
                            "endpointsTried": [item.get("endpoint") for item in attempts],
                            "keywords": list(intake.keywords[:5]),
                            "siteUrl": intake.url,
                            "requestTimeoutMs": self.settings.market_provider_timeout_ms,
                        },
                        source_type=source_type,  # type: ignore[arg-type]
                        source_ref=(
                            f"synthetic:{provider.value}:{(urlparse(intake.url).netloc.lower() or intake.url.lower())}"
                            if not strict
                            else (endpoints[-1] if endpoints else None)
                        ),
                        fallback_reason=fallback_reason,
                        failure_code=failure_code if strict else None,
                        retryable=bool(last.get("retryable", True)),
                        auth_source=auth_source,
                        latency_ms=int((time.perf_counter() - started) * 1000),
                    )
                )
        return evidence

    def build_market_evidence_report(self, project_id: str) -> MarketEvidenceReport:
        with self.database.session() as session:
            project = session.get(ProjectRow, project_id)
            if project is None:
                raise ValueError(f"Unknown project: {project_id}")
            task = session.scalars(select(TaskRow).where(TaskRow.project_id == project_id).order_by(TaskRow.updated_at.desc())).first()
            if task is None:
                return MarketEvidenceReport(
                    report_id=new_id("market"),
                    project_id=project_id,
                    trend=[],
                    news=[],
                    qa=[],
                    summaries=[
                        self._build_market_evidence_summary("trend", []),
                        self._build_market_evidence_summary("news", []),
                        self._build_market_evidence_summary("qa", []),
                    ],
                    notes=[
                        "Project has no task yet; market evidence report is empty and synthetic.",
                        "This keeps acceptance and health reports resilient for newly created projects.",
                    ],
                )
            bundle = self._bundle_from_row(task)
            ingestion = bundle.ingestion_report or IngestionReport(
                report_id=new_id("ingest"),
                project_id=project_id,
                task_id=task.id,
                status=ConnectorStatus.synthetic,
            )
            trend = [item for item in ingestion.evidence if item.source_type == "trend"]
            news = [item for item in ingestion.evidence if item.source_type == "news"]
            qa = [item for item in ingestion.evidence if item.source_type == "qa"]
            return MarketEvidenceReport(
                report_id=new_id("market"),
                project_id=project_id,
                trend=trend,
                news=news,
                qa=qa,
                summaries=[
                    self._build_market_evidence_summary("trend", trend),
                    self._build_market_evidence_summary("news", news),
                    self._build_market_evidence_summary("qa", qa),
                ],
                notes=[
                    f"trend={len(trend)} news={len(news)} qa={len(qa)}",
                    "Market evidence is split out from the ingestion report so the UI can render it independently.",
                ],
            )

    def build_market_evidence_health_report(self, project_id: str) -> MarketEvidenceHealthReport:
        report = self.build_market_evidence_report(project_id)
        strict_enabled = bool(self.settings.strict_providers)
        connected_count = sum(1 for item in [*report.trend, *report.news, *report.qa] if item.status == ConnectorStatus.connected)
        synthetic_count = sum(1 for item in [*report.trend, *report.news, *report.qa] if item.status == ConnectorStatus.synthetic)
        failed_count = sum(
            1
            for item in [*report.trend, *report.news, *report.qa]
            if item.status in {ConnectorStatus.error, ConnectorStatus.missing_credentials, ConnectorStatus.unavailable}
        )
        latest_fetched_at = max((item.fetched_at for item in [*report.trend, *report.news, *report.qa]), default=None)
        evidence_freshness_minutes = max(30, int(self.settings.provider_evidence_freshness_minutes))
        freshness_cutoff = utcnow()
        if freshness_cutoff.tzinfo is None:
            freshness_cutoff = freshness_cutoff.replace(tzinfo=timezone.utc)
        freshness_cutoff = freshness_cutoff - timedelta(minutes=evidence_freshness_minutes)

        def _is_fresh(value: datetime | None) -> bool:
            if value is None:
                return False
            checked = value
            if checked.tzinfo is None:
                checked = checked.replace(tzinfo=timezone.utc)
            return checked >= freshness_cutoff

        fresh_count = sum(1 for item in [*report.trend, *report.news, *report.qa] if item.status == ConnectorStatus.connected and _is_fresh(item.fetched_at))
        stale_count = max(0, connected_count - fresh_count)
        strict_ready = connected_count >= 1 and ((not strict_enabled) or fresh_count >= 1)
        return MarketEvidenceHealthReport(
            report_id=new_id("market-health"),
            project_id=project_id,
            strict_providers_enabled=strict_enabled,
            connected_count=connected_count,
            synthetic_count=synthetic_count,
            failed_count=failed_count,
            fresh_count=fresh_count,
            stale_count=stale_count,
            latest_fetched_at=latest_fetched_at,
            strict_ready=strict_ready,
            notes=[
                f"freshnessMinutes={evidence_freshness_minutes}",
                "strictReady follows connected samples and freshness window.",
            ],
        )

    def build_workspace_market_evidence_health_report(self, project_id: Optional[str] = None) -> WorkspaceMarketEvidenceHealthReport:
        with self.database.session() as session:
            projects = session.scalars(select(ProjectRow).order_by(ProjectRow.created_at.desc())).all()
        project_filter = (project_id or "").strip() or None
        if project_filter is not None:
            projects = [project for project in projects if project.id == project_filter]
        project_reports = [self.build_market_evidence_health_report(project.id) for project in projects]
        strict_enabled = bool(self.settings.strict_providers)
        project_count = len(project_reports)
        connected_count = sum(item.connected_count for item in project_reports)
        synthetic_count = sum(item.synthetic_count for item in project_reports)
        failed_count = sum(item.failed_count for item in project_reports)
        fresh_count = sum(item.fresh_count for item in project_reports)
        stale_count = sum(item.stale_count for item in project_reports)
        strict_ready_project_count = sum(1 for item in project_reports if item.strict_ready)
        strict_ready_project_ids = [item.project_id for item in project_reports if item.strict_ready]
        stale_project_ids = [item.project_id for item in project_reports if item.stale_count > 0]
        latest_fetched_at = max((item.latest_fetched_at for item in project_reports if item.latest_fetched_at is not None), default=None)
        return WorkspaceMarketEvidenceHealthReport(
            report_id=new_id("workspace-market-health"),
            project_id=project_filter,
            strict_providers_enabled=strict_enabled,
            project_count=project_count,
            connected_count=connected_count,
            synthetic_count=synthetic_count,
            failed_count=failed_count,
            fresh_count=fresh_count,
            stale_count=stale_count,
            strict_ready_project_count=strict_ready_project_count,
            strict_ready_project_rate_percent=round((strict_ready_project_count / project_count) * 100, 1) if project_count else 0.0,
            latest_fetched_at=latest_fetched_at,
            strict_ready_project_ids=strict_ready_project_ids,
            stale_project_ids=stale_project_ids,
            notes=[
                "Workspace market evidence health aggregates project-level connected/fresh coverage.",
                "Strict readiness follows per-project market evidence freshness.",
            ],
        )

    def build_workspace_cruise_health_report(self, project_id: Optional[str] = None) -> WorkspaceCruiseHealthReport:
        with self.database.session() as session:
            projects = session.scalars(select(ProjectRow).order_by(ProjectRow.created_at.desc())).all()
            states = {state.project_id: state for state in session.scalars(select(ProjectStateRow)).all()}
        now = utcnow()
        project_filter = (project_id or "").strip() or None
        if project_filter is not None:
            projects = [project for project in projects if project.id == project_filter]
        auto_cruise_enabled = bool(self.settings.auto_cruise_enabled)
        def _normalize(value: datetime | None) -> datetime | None:
            if value is None:
                return None
            if value.tzinfo is None:
                return value.replace(tzinfo=timezone.utc)
            return value

        enabled_project_ids: list[str] = []
        due_project_ids: list[str] = []
        overdue_project_ids: list[str] = []
        project_samples: list[WorkspaceCruiseProjectHealthItem] = []
        next_due_candidates: list[datetime] = []
        last_sync_candidates: list[datetime] = []
        for project in projects:
            state = states.get(project.id)
            if state is None:
                continue
            enabled = bool(state.auto_cruise_enabled)
            if not enabled:
                continue
            enabled_project_ids.append(project.id)
            next_sync_at = _normalize(state.next_sync_at)
            last_sync_at = _normalize(state.last_sync_at)
            due_now = next_sync_at is None or next_sync_at <= now
            overdue = due_now and (last_sync_at is None or last_sync_at <= now - timedelta(minutes=max(15, state.sync_interval_minutes)))
            if due_now:
                due_project_ids.append(project.id)
            if overdue:
                overdue_project_ids.append(project.id)
            if next_sync_at is not None:
                next_due_candidates.append(next_sync_at)
            if last_sync_at is not None:
                last_sync_candidates.append(last_sync_at)
            if len(project_samples) < 12:
                project_samples.append(
                    WorkspaceCruiseProjectHealthItem(
                        project_id=project.id,
                        name=project.name,
                        url=project.url,
                        auto_cruise_enabled=enabled,
                        connection_health=state.connection_health,
                        sync_interval_minutes=state.sync_interval_minutes,
                        last_sync_at=last_sync_at,
                        next_sync_at=next_sync_at,
                        due_now=due_now,
                        overdue=overdue,
                        last_run_status=state.last_run_status,
                    )
                )
        return WorkspaceCruiseHealthReport(
            report_id=new_id("workspace-cruise-health"),
            generated_at=now,
            project_id=project_filter,
            auto_cruise_enabled=auto_cruise_enabled,
            project_count=len(projects),
            enabled_project_count=len(enabled_project_ids),
            due_project_count=len(due_project_ids),
            overdue_project_count=len(overdue_project_ids),
            next_due_at=min(next_due_candidates) if next_due_candidates else None,
            last_sync_at=max(last_sync_candidates) if last_sync_candidates else None,
            enabled_project_ids=enabled_project_ids,
            due_project_ids=due_project_ids,
            overdue_project_ids=overdue_project_ids,
            project_samples=project_samples,
            notes=[
                "Auto-cruise health aggregates project-level schedule state.",
                "Due projects are eligible for worker sync jobs and overdue projects need attention.",
            ],
        )

    def build_project_cruise_health_report(self, project_id: str) -> ProjectCruiseHealthReport:
        with self.database.session() as session:
            project = session.get(ProjectRow, project_id)
            if project is None:
                raise ValueError(f"Unknown project: {project_id}")
            state = session.get(ProjectStateRow, project_id)
            if state is None:
                state = self._upsert_state_row(session, project_id)
        now = utcnow()

        def _normalize(value: datetime | None) -> datetime | None:
            if value is None:
                return None
            if value.tzinfo is None:
                return value.replace(tzinfo=timezone.utc)
            return value

        last_sync_at = _normalize(state.last_sync_at)
        next_sync_at = _normalize(state.next_sync_at)
        due_now = next_sync_at is None or next_sync_at <= now
        overdue = due_now and (last_sync_at is None or last_sync_at <= now - timedelta(minutes=max(15, state.sync_interval_minutes)))
        sample = WorkspaceCruiseProjectHealthItem(
            project_id=project.id,
            name=project.name,
            url=project.url,
            auto_cruise_enabled=bool(state.auto_cruise_enabled),
            connection_health=state.connection_health,
            sync_interval_minutes=state.sync_interval_minutes,
            last_sync_at=last_sync_at,
            next_sync_at=next_sync_at,
            due_now=due_now,
            overdue=overdue,
            last_run_status=state.last_run_status,
        )
        return ProjectCruiseHealthReport(
            report_id=new_id("project-cruise-health"),
            project_id=project.id,
            generated_at=now,
            auto_cruise_enabled=bool(state.auto_cruise_enabled),
            connection_health=state.connection_health,
            sync_interval_minutes=state.sync_interval_minutes,
            last_sync_at=last_sync_at,
            next_sync_at=next_sync_at,
            due_now=due_now,
            overdue=overdue,
            last_run_status=state.last_run_status,
            project_sample=sample,
            notes=[
                "Project auto-cruise health is derived from current project state.",
                "Due and overdue are normalized to UTC to avoid timezone drift.",
            ],
        )

    def _build_market_evidence_summary(
        self,
        source_type: Literal["trend", "news", "qa"],
        items: list[SourceEvidence],
    ) -> MarketEvidenceSummary:
        auth_sources = sorted({str(item.auth_source) for item in items if item.auth_source})
        fallback_reasons = sorted({str(item.fallback_reason) for item in items if item.fallback_reason})
        latest_fetched_at = max((item.fetched_at for item in items), default=None)
        connected_items = [item for item in items if item.status == ConnectorStatus.connected]
        connected_endpoints = sorted(
            {
                str(item.details.get("connectedEndpoint") or item.details.get("endpoint") or "").strip()
                for item in connected_items
                if str(item.details.get("connectedEndpoint") or item.details.get("endpoint") or "").strip()
            }
        )
        connected_source_refs = sorted({str(item.source_ref) for item in connected_items if item.source_ref})
        latency_values = [int(item.latency_ms) for item in items if item.latency_ms is not None]
        average_latency_ms = int(sum(latency_values) / len(latency_values)) if latency_values else None
        return MarketEvidenceSummary(
            source_type=source_type,
            total_count=len(items),
            connected_count=sum(1 for item in items if item.status == ConnectorStatus.connected),
            synthetic_count=sum(1 for item in items if item.status == ConnectorStatus.synthetic),
            failed_count=sum(1 for item in items if item.status in {ConnectorStatus.error, ConnectorStatus.unavailable, ConnectorStatus.missing_credentials}),
            latest_fetched_at=latest_fetched_at,
            auth_sources=auth_sources,
            fallback_reasons=fallback_reasons,
            connected_endpoints=connected_endpoints,
            connected_source_refs=connected_source_refs,
            average_latency_ms=average_latency_ms,
        )

    def _build_alert_report(self, *, emit_side_effects: bool) -> AlertReport:
        remediation = self.build_connector_remediation_report()
        blocking: list[AlertItem] = []
        recoverable: list[AlertItem] = []
        now = utcnow()
        for item in remediation.items:
            primary_provider = item.providers[0] if item.providers else "unknown"
            summary = f"{item.failure_code}: {item.action}"
            computed_blocking, computed_severity, matched_rule = self._apply_alert_rule(item)
            alert = AlertItem(
                alert_id=new_id("alert"),
                created_at=now,
                category=item.category,
                severity=computed_severity,
                blocking=computed_blocking,
                failure_code=item.failure_code,
                provider=primary_provider,
                project_count=item.affected_projects,
                project_ids=item.project_ids,
                summary=summary,
                remediation_path=item.quick_action_path,
                rule_id=matched_rule,
            )
            if computed_blocking:
                blocking.append(alert)
            else:
                recoverable.append(alert)
        visual_blocking, visual_recoverable = self._build_visual_regression_alert_items(now)
        blocking.extend(visual_blocking)
        recoverable.extend(visual_recoverable)
        probe_blocking, probe_recoverable = self._build_visual_farm_probe_alert_items(now)
        blocking.extend(probe_blocking)
        recoverable.extend(probe_recoverable)
        report = AlertReport(
            report_id=new_id("alert-report"),
            generated_at=now,
            blocking=blocking,
            recoverable=recoverable,
            notes=[
                "Blocking alerts include auth/config/permission issues that prevent safe writes.",
                "Recoverable alerts include network/rate-limit/transient provider failures.",
                "Visual regression alerts include strict-blocked visual checks and visual farm fallback/failure signals.",
                "Visual farm probe alerts surface endpoint auth/network failures before visual runs start.",
            ],
        )
        signature = self._alert_report_signature(report)
        report.notes.append(f"alertSignature={signature}")
        if emit_side_effects:
            cooldown_seconds = max(0, int(self.settings.alert_emit_cooldown_seconds))
            emission_suppressed = self._should_suppress_alert_emit(report, signature=signature)
            if emission_suppressed:
                report.notes.append(
                    f"Alert emission suppressed: unchanged signature within cooldown ({cooldown_seconds}s)."
                )
                self._audit(
                    "workspace",
                    "",
                    "alerts.emit.suppressed",
                    {
                        "actor": "system",
                        "signature": signature,
                        "cooldownSeconds": cooldown_seconds,
                        "blockingCount": len(report.blocking),
                        "recoverableCount": len(report.recoverable),
                    },
                )
            else:
                webhook_notes = self._emit_alert_webhooks(report)
                if webhook_notes:
                    report.notes.extend(webhook_notes)
                self._audit(
                    "workspace",
                    "",
                    "alerts.emit.executed",
                    {
                        "actor": "system",
                        "signature": signature,
                        "cooldownSeconds": cooldown_seconds,
                        "blockingCount": len(report.blocking),
                        "recoverableCount": len(report.recoverable),
                    },
                )
            with self.database.session() as session:
                session.add(
                    AlertSnapshotRow(
                        id=report.report_id,
                        generated_at=report.generated_at,
                        report_json=report.model_dump(mode="json", by_alias=True),
                        blocking_count=len(report.blocking),
                        recoverable_count=len(report.recoverable),
                    )
                )
        return report

    def build_alert_report(self) -> AlertReport:
        return self._build_alert_report(emit_side_effects=True)

    def get_latest_alert_report(self) -> AlertReport:
        with self.database.session() as session:
            row = session.scalars(select(AlertSnapshotRow).order_by(AlertSnapshotRow.generated_at.desc())).first()
        if row is not None and row.report_json:
            report = AlertReport.model_validate(row.report_json)
            notes = list(report.notes)
            notes.append("Read-only latest snapshot returned; no webhook emission.")
            return report.model_copy(update={"notes": notes})
        report = self._build_alert_report(emit_side_effects=False)
        notes = list(report.notes)
        notes.append("No historical snapshot found; generated read-only report without webhook emission.")
        return report.model_copy(update={"notes": notes})

    def _alert_report_signature(self, report: AlertReport) -> str:
        rows: list[str] = []
        for queue_name, alerts in (("blocking", report.blocking), ("recoverable", report.recoverable)):
            for item in alerts:
                project_ids = ",".join(sorted({str(project_id) for project_id in item.project_ids}))
                rows.append(
                    "|".join(
                        [
                            queue_name,
                            str(item.category),
                            str(item.severity),
                            str(item.failure_code),
                            str(item.provider),
                            project_ids,
                            str(item.project_count),
                        ]
                    )
                )
        payload = "\n".join(sorted(rows)).encode("utf-8")
        return hashlib.sha256(payload).hexdigest()

    def _should_suppress_alert_emit(self, report: AlertReport, *, signature: str) -> bool:
        cooldown_seconds = max(0, int(self.settings.alert_emit_cooldown_seconds))
        if cooldown_seconds <= 0:
            return False
        with self.database.session() as session:
            latest = session.scalars(select(AlertSnapshotRow).order_by(AlertSnapshotRow.generated_at.desc())).first()
        if latest is None or not latest.report_json:
            return False
        latest_generated_at = latest.generated_at
        if latest_generated_at.tzinfo is None:
            latest_generated_at = latest_generated_at.replace(tzinfo=timezone.utc)
        report_generated_at = report.generated_at
        if report_generated_at.tzinfo is None:
            report_generated_at = report_generated_at.replace(tzinfo=timezone.utc)
        elapsed_seconds = max(0, int((report_generated_at - latest_generated_at).total_seconds()))
        if elapsed_seconds > cooldown_seconds:
            return False
        try:
            previous_report = AlertReport.model_validate(latest.report_json)
        except Exception:
            return False
        previous_signature = self._alert_report_signature(previous_report)
        return previous_signature == signature

    def _build_visual_regression_alert_items(self, now: datetime) -> tuple[list[AlertItem], list[AlertItem]]:
        try:
            runs = self.build_visual_regression_runs_report()
        except Exception:
            return [], []
        latest = runs.runs[0] if runs.runs else None
        if latest is None:
            return [], []

        buckets: dict[str, dict[str, Any]] = {}
        run_id = str(latest.run_id or "").strip()
        for case in latest.cases:
            if case.passed and not case.visual_farm_strict_blocked:
                continue
            failure_code = str(case.provider_failure_code or "").strip()
            if case.visual_farm_strict_blocked:
                failure_code = failure_code or "VISUAL_REGRESSION_STRICT_BLOCKED"
            elif not failure_code:
                if case.provider_status == "fallback":
                    failure_code = "VISUAL_FARM_FALLBACK"
                elif case.provider_status == "not_configured":
                    failure_code = "VISUAL_FARM_NOT_CONFIGURED"
                elif case.provider_status == "failed":
                    failure_code = "VISUAL_FARM_FAILED"
                else:
                    failure_code = "VISUAL_REGRESSION_FAILED"
            bucket = buckets.setdefault(
                failure_code,
                {
                    "projectIds": set(),
                    "sampleIds": set(),
                    "count": 0,
                    "strictBlocked": False,
                    "statusHints": set(),
                },
            )
            if case.project_id:
                bucket["projectIds"].add(case.project_id)
            if case.sample_id:
                bucket["sampleIds"].add(case.sample_id)
            bucket["count"] += 1
            bucket["strictBlocked"] = bool(bucket["strictBlocked"] or case.visual_farm_strict_blocked)
            if case.provider_status:
                bucket["statusHints"].add(case.provider_status)

        blocking: list[AlertItem] = []
        recoverable: list[AlertItem] = []
        for failure_code, data in buckets.items():
            normalized_code = failure_code.upper()
            category = self._failure_category(normalized_code)
            is_blocking = bool(data["strictBlocked"] or category in {"auth", "config", "permission"})
            severity: Literal["critical", "warning", "info"]
            if is_blocking:
                severity = "critical"
            elif category in {"network", "rate_limit", "validation", "unavailable"}:
                severity = "warning"
            else:
                severity = "info"
            status_hints = sorted(str(item) for item in data["statusHints"] if str(item))
            project_ids = sorted(str(item) for item in data["projectIds"] if str(item))
            sample_ids = sorted(str(item) for item in data["sampleIds"] if str(item))
            remediation_query = {
                "focus": "visual-regressions",
                "failureCode": normalized_code,
            }
            if run_id:
                remediation_query["runId"] = run_id
            if sample_ids:
                remediation_query["sampleIds"] = ",".join(sample_ids[:20])
            alert = AlertItem(
                alert_id=new_id("alert"),
                created_at=now,
                category=category,
                severity=severity,
                blocking=is_blocking,
                failure_code=normalized_code,
                provider="visual_farm",
                project_count=len(project_ids),
                project_ids=project_ids,
                summary=f"{normalized_code}: visual regression issues detected ({data['count']} cases)",
                remediation_path=f"/quality?{urlencode(remediation_query)}",
                rule_id="visual_regression_default",
            )
            if is_blocking:
                blocking.append(alert)
            else:
                recoverable.append(alert)
        return blocking, recoverable

    def _build_visual_farm_probe_alert_items(self, now: datetime) -> tuple[list[AlertItem], list[AlertItem]]:
        history = self.get_visual_farm_probe_history(limit=1)
        strict_mode = bool(self.settings.visual_farm_strict)
        if not history.entries:
            category = "config"
            severity: Literal["critical", "warning", "info"] = "critical" if strict_mode else "warning"
            alert = AlertItem(
                alert_id=new_id("alert"),
                created_at=now,
                category=category,
                severity=severity,
                blocking=bool(strict_mode),
                failure_code="VISUAL_FARM_PROBE_MISSING",
                provider="visual_farm",
                project_count=1,
                project_ids=["workspace"],
                summary="VISUAL_FARM_PROBE_MISSING: no visual farm probe history available",
                remediation_path="/settings?focus=visual-farm&failureCode=VISUAL_FARM_PROBE_MISSING&from=probe",
                rule_id="visual_farm_probe_default",
            )
            return ([alert], []) if alert.blocking else ([], [alert])
        latest = history.entries[0]
        freshness_minutes = max(1, int(self.settings.visual_farm_probe_freshness_minutes))
        latest_created_at = latest.created_at
        if latest_created_at.tzinfo is None:
            latest_created_at = latest_created_at.replace(tzinfo=timezone.utc)
        now_with_tz = now if now.tzinfo is not None else now.replace(tzinfo=timezone.utc)
        stale_probe = latest_created_at < (now_with_tz - timedelta(minutes=freshness_minutes))

        buckets: dict[str, dict[str, Any]] = {}
        if stale_probe:
            buckets["VISUAL_FARM_PROBE_STALE"] = {
                "count": 1,
                "endpoints": set(),
                "blocking": bool(strict_mode),
                "alertSeverity": "critical" if strict_mode else "warning",
            }
        if latest.failed_count > 0:
            for probe in latest.probes:
                if probe.status != "failed":
                    continue
                failure_code = str(probe.failure_code or "VISUAL_FARM_PROBE_FAILED").strip().upper()
                bucket = buckets.setdefault(
                    failure_code,
                    {
                        "count": 0,
                        "endpoints": set(),
                        "blocking": False,
                        "alertSeverity": "warning",
                    },
                )
                bucket["count"] += 1
                if probe.endpoint:
                    bucket["endpoints"].add(str(probe.endpoint))
                bucket["blocking"] = bool(bucket["blocking"] or probe.blocking)
                if str(probe.alert_severity) == "critical":
                    bucket["alertSeverity"] = "critical"
                elif str(bucket["alertSeverity"]) != "critical" and str(probe.alert_severity) == "info":
                    bucket["alertSeverity"] = "info"
        if not buckets:
            return [], []

        blocking: list[AlertItem] = []
        recoverable: list[AlertItem] = []
        for failure_code, data in buckets.items():
            severity_hint = str(data["alertSeverity"])
            is_blocking = bool(data["blocking"])
            if is_blocking:
                severity: Literal["critical", "warning", "info"] = "critical"
            else:
                if severity_hint in {"critical", "warning", "info"}:
                    severity = severity_hint  # type: ignore[assignment]
                else:
                    severity = "warning"
            endpoints = sorted(str(item) for item in data["endpoints"] if str(item))
            remediation_query = {
                "focus": "visual-farm",
                "failureCode": failure_code,
                "from": "probe",
            }
            if failure_code == "VISUAL_FARM_PROBE_STALE":
                remediation_query["freshnessMinutes"] = str(freshness_minutes)
                remediation_query["lastProbeAt"] = latest_created_at.isoformat()
            if endpoints:
                remediation_query["endpoints"] = ",".join(endpoints[:10])
            alert = AlertItem(
                alert_id=new_id("alert"),
                created_at=now,
                category=self._failure_category(failure_code),
                severity=severity,
                blocking=is_blocking,
                failure_code=failure_code,
                provider="visual_farm",
                project_count=1,
                project_ids=["workspace"],
                summary=f"{failure_code}: visual farm probe failed ({data['count']} endpoint(s))",
                remediation_path=f"/settings?{urlencode(remediation_query)}",
                rule_id="visual_farm_probe_default",
            )
            if is_blocking:
                blocking.append(alert)
            else:
                recoverable.append(alert)
        return blocking, recoverable

    def _split_webhook_targets(self, raw_value: str) -> list[str]:
        normalized = str(raw_value or "").replace("\n", ",")
        targets = [item.strip() for item in normalized.split(",") if item.strip()]
        deduped: list[str] = []
        for target in targets:
            if target not in deduped:
                deduped.append(target)
        return deduped

    def _emit_alert_webhooks(self, report: AlertReport) -> list[str]:
        general_targets = self._split_webhook_targets(self.settings.alert_webhook_urls)
        legacy_target = str(self.settings.alert_webhook_url or "").strip()
        if legacy_target and legacy_target not in general_targets:
            general_targets.append(legacy_target)
        blocking_targets = self._split_webhook_targets(self.settings.alert_blocking_webhook_urls)
        recoverable_targets = self._split_webhook_targets(self.settings.alert_recoverable_webhook_urls)
        notes: list[str] = []

        for target in general_targets:
            outcome = self._emit_single_alert_webhook(target, report, route="all")
            if outcome:
                notes.append(outcome)
        if report.blocking:
            blocking_only = AlertReport(
                report_id=report.report_id,
                generated_at=report.generated_at,
                blocking=list(report.blocking),
                recoverable=[],
                notes=list(report.notes),
            )
            for target in blocking_targets:
                outcome = self._emit_single_alert_webhook(target, blocking_only, route="blocking")
                if outcome:
                    notes.append(outcome)
        if report.recoverable:
            recoverable_only = AlertReport(
                report_id=report.report_id,
                generated_at=report.generated_at,
                blocking=[],
                recoverable=list(report.recoverable),
                notes=list(report.notes),
            )
            for target in recoverable_targets:
                outcome = self._emit_single_alert_webhook(target, recoverable_only, route="recoverable")
                if outcome:
                    notes.append(outcome)
        oncall_deliveries = self._emit_oncall_routes(report)
        if oncall_deliveries:
            notes.extend(oncall_deliveries)
        pagerduty_deliveries = self._emit_pagerduty_events(report)
        if pagerduty_deliveries:
            notes.extend(pagerduty_deliveries)
        opsgenie_deliveries = self._emit_opsgenie_events(report)
