    def _emit_pagerduty_events(self, report: AlertReport) -> list[str]:
        routing_key = str(self.settings.alert_pagerduty_routing_key or "").strip()
        endpoint = str(self.settings.alert_pagerduty_endpoint or "").strip()
        source = str(self.settings.alert_pagerduty_source or "seo-ad-autopilot").strip() or "seo-ad-autopilot"
        if not routing_key or not endpoint:
            return []
        notes: list[str] = []
        if report.blocking:
            outcome = self._emit_single_pagerduty_event(
                endpoint=endpoint,
                routing_key=routing_key,
                source=source,
                report=report,
                route="pagerduty:blocking",
                severity="critical",
                summary=f"Blocking alerts detected ({len(report.blocking)})",
            )
            if outcome:
                notes.append(outcome)
        if report.recoverable:
            outcome = self._emit_single_pagerduty_event(
                endpoint=endpoint,
                routing_key=routing_key,
                source=source,
                report=report,
                route="pagerduty:recoverable",
                severity="warning",
                summary=f"Recoverable alerts detected ({len(report.recoverable)})",
            )
            if outcome:
                notes.append(outcome)
        return notes

    def _emit_single_pagerduty_event(
        self,
        *,
        endpoint: str,
        routing_key: str,
        source: str,
        report: AlertReport,
        route: str,
        severity: Literal["critical", "warning", "info", "error"],
        summary: str,
    ) -> Optional[str]:
        payload = {
            "routing_key": routing_key,
            "event_action": "trigger",
            "dedup_key": f"seo-ad:{route}:{report.report_id}",
            "payload": {
                "summary": summary,
                "source": source,
                "severity": severity,
                "component": "alerts",
                "group": "seo-ad-autopilot",
                "class": route,
                "custom_details": {
                    "reportId": report.report_id,
                    "generatedAt": report.generated_at.isoformat(),
                    "blockingCount": len(report.blocking),
                    "recoverableCount": len(report.recoverable),
                },
            },
        }
        try:
            timeout_seconds = max(0.5, int(self.settings.alert_webhook_timeout_ms) / 1000.0)
            request = Request(
                endpoint,
                data=json.dumps(payload).encode("utf-8"),
                headers={"Content-Type": "application/json", "Accept": "application/json", "User-Agent": "SEO-AD-AutoPilot/1.0"},
                method="POST",
            )
            with urlopen(request, timeout=timeout_seconds) as response:  # nosec - configurable outbound integration
                status_code = int(getattr(response, "status", 202) or 202)
            self._audit(
                "workspace",
                "",
                "alerts.webhook.sent",
                {
                    "reportId": report.report_id,
                    "target": endpoint,
                    "channel": "pagerduty",
                    "route": route,
                    "statusCode": status_code,
                    "blockingCount": len(report.blocking),
                    "recoverableCount": len(report.recoverable),
                },
            )
            return f"PagerDuty delivered to {endpoint} ({route})."
        except Exception as exc:
            self._audit(
                "workspace",
                "",
                "alerts.webhook.failed",
                {
                    "reportId": report.report_id,
                    "target": endpoint,
                    "channel": "pagerduty",
                    "route": route,
                    "error": str(exc),
                    "blockingCount": len(report.blocking),
                    "recoverableCount": len(report.recoverable),
                },
            )
            return f"PagerDuty delivery failed ({route}): {exc}"

