    def _emit_single_teams_event(
        self,
        *,
        webhook_url: str,
        source: str,
        report: AlertReport,
        route: str,
        title: str,
        severity: Literal["critical", "warning", "info"],
    ) -> Optional[str]:
        payload = {
            "@type": "MessageCard",
            "@context": "https://schema.org/extensions",
            "summary": title,
            "themeColor": "E81123" if severity == "critical" else "FFB900" if severity == "warning" else "0078D4",
            "title": title,
            "sections": [
                {
                    "activityTitle": source,
                    "activitySubtitle": route,
                    "facts": [
                        {"name": "reportId", "value": report.report_id},
                        {"name": "blocking", "value": str(len(report.blocking))},
                        {"name": "recoverable", "value": str(len(report.recoverable))},
                        {"name": "severity", "value": severity},
                    ],
                    "markdown": True,
                }
            ],
        }
        try:
            timeout_seconds = max(0.5, int(self.settings.alert_webhook_timeout_ms) / 1000.0)
            request = Request(
                webhook_url,
                data=json.dumps(payload).encode("utf-8"),
                headers={"Content-Type": "application/json", "Accept": "application/json", "User-Agent": "SEO-AD-AutoPilot/1.0"},
                method="POST",
            )
            with urlopen(request, timeout=timeout_seconds) as response:  # nosec - configurable outbound integration
                status_code = int(getattr(response, "status", 200) or 200)
            self._audit(
                "workspace",
                "",
                "alerts.webhook.sent",
                {
                    "reportId": report.report_id,
                    "target": webhook_url,
                    "channel": "teams",
                    "route": route,
                    "statusCode": status_code,
                    "blockingCount": len(report.blocking),
                    "recoverableCount": len(report.recoverable),
                },
            )
            return f"Teams delivered to {webhook_url} ({route})."
        except Exception as exc:
            self._audit(
                "workspace",
                "",
                "alerts.webhook.failed",
                {
                    "reportId": report.report_id,
                    "target": webhook_url,
                    "channel": "teams",
                    "route": route,
                    "error": str(exc),
                    "blockingCount": len(report.blocking),
                    "recoverableCount": len(report.recoverable),
                },
            )
            return f"Teams delivery failed ({route}): {exc}"

