    def _emit_single_azure_devops_work_item(
        self,
        *,
        endpoint: str,
        pat: str,
        report: AlertReport,
        route: str,
        title: str,
        severity: str,
    ) -> Optional[str]:
        token = base64.b64encode(f":{pat}".encode("utf-8")).decode("ascii")
        payload = [
            {"op": "add", "path": "/fields/System.Title", "value": title},
            {
                "op": "add",
                "path": "/fields/System.Description",
                "value": (
                    f"reportId={report.report_id}<br/>"
                    f"route={route}<br/>"
                    f"blocking={len(report.blocking)}<br/>"
                    f"recoverable={len(report.recoverable)}"
                ),
            },
            {"op": "add", "path": "/fields/Microsoft.VSTS.Common.Severity", "value": severity},
            {"op": "add", "path": "/fields/System.Tags", "value": f"seo-ad-autopilot;alerts;{route.replace(':', '-')}"},
        ]
        try:
            timeout_seconds = max(0.5, int(self.settings.alert_webhook_timeout_ms) / 1000.0)
            request = Request(
                endpoint,
                data=json.dumps(payload).encode("utf-8"),
                headers={
                    "Content-Type": "application/json-patch+json",
                    "Accept": "application/json",
                    "Authorization": f"Basic {token}",
                    "User-Agent": "SEO-AD-AutoPilot/1.0",
                },
                method="POST",
            )
            with urlopen(request, timeout=timeout_seconds) as response:  # nosec - configurable outbound integration
                status_code = int(getattr(response, "status", 200) or 200)
            self._audit(
                "workspace",
                "",
                "alerts.webhook.sent",
                {
                    "reportId": report.report_id,
                    "target": endpoint,
                    "channel": "azure_devops",
                    "route": route,
                    "statusCode": status_code,
                    "blockingCount": len(report.blocking),
                    "recoverableCount": len(report.recoverable),
                },
            )
            return f"Azure DevOps delivered to {endpoint} ({route})."
        except Exception as exc:
            self._audit(
                "workspace",
                "",
                "alerts.webhook.failed",
                {
                    "reportId": report.report_id,
                    "target": endpoint,
                    "channel": "azure_devops",
                    "route": route,
                    "error": str(exc),
                    "blockingCount": len(report.blocking),
                    "recoverableCount": len(report.recoverable),
                },
            )
            return f"Azure DevOps delivery failed ({route}): {exc}"

    def _emit_twilio_events(self, report: AlertReport) -> list[str]:
        account_sid = str(self.settings.alert_twilio_account_sid or "").strip()
        auth_token = str(self.settings.alert_twilio_auth_token or "").strip()
        from_number = str(self.settings.alert_twilio_from_number or "").strip()
        to_numbers = self._split_webhook_targets(str(self.settings.alert_twilio_to_numbers or ""))
        if not account_sid or not auth_token or not from_number or not to_numbers:
            return []
        endpoint = f"https://api.twilio.com/2010-04-01/Accounts/{account_sid}/Messages.json"
        notes: list[str] = []
        for to_number in to_numbers:
            if report.blocking:
                outcome = self._emit_single_twilio_sms(
                    endpoint=endpoint,
                    account_sid=account_sid,
                    auth_token=auth_token,
                    from_number=from_number,
                    to_number=to_number,
                    report=report,
                    route="twilio:blocking",
                    body=f"[SEO-AD] Blocking alerts detected: {len(report.blocking)}. reportId={report.report_id}",
                )
                if outcome:
                    notes.append(outcome)
            if report.recoverable:
                outcome = self._emit_single_twilio_sms(
                    endpoint=endpoint,
                    account_sid=account_sid,
                    auth_token=auth_token,
                    from_number=from_number,
                    to_number=to_number,
                    report=report,
                    route="twilio:recoverable",
                    body=f"[SEO-AD] Recoverable alerts detected: {len(report.recoverable)}. reportId={report.report_id}",
                )
                if outcome:
                    notes.append(outcome)
        return notes

    def _emit_single_twilio_sms(
        self,
        *,
        endpoint: str,
        account_sid: str,
        auth_token: str,
        from_number: str,
        to_number: str,
        report: AlertReport,
        route: str,
        body: str,
    ) -> Optional[str]:
        token = base64.b64encode(f"{account_sid}:{auth_token}".encode("utf-8")).decode("ascii")
        payload = urlencode({"From": from_number, "To": to_number, "Body": body}).encode("utf-8")
        try:
            timeout_seconds = max(0.5, int(self.settings.alert_webhook_timeout_ms) / 1000.0)
            request = Request(
                endpoint,
                data=payload,
                headers={
                    "Content-Type": "application/x-www-form-urlencoded",
                    "Accept": "application/json",
                    "Authorization": f"Basic {token}",
                    "User-Agent": "SEO-AD-AutoPilot/1.0",
                },
                method="POST",
            )
            with urlopen(request, timeout=timeout_seconds) as response:  # nosec - configurable outbound integration
                status_code = int(getattr(response, "status", 201) or 201)
            self._audit(
                "workspace",
                "",
                "alerts.webhook.sent",
                {
                    "reportId": report.report_id,
                    "target": to_number,
                    "channel": "twilio",
                    "route": route,
                    "statusCode": status_code,
                    "blockingCount": len(report.blocking),
                    "recoverableCount": len(report.recoverable),
                },
            )
            return f"Twilio delivered to {to_number} ({route})."
        except Exception as exc:
            self._audit(
                "workspace",
                "",
                "alerts.webhook.failed",
                {
                    "reportId": report.report_id,
                    "target": to_number,
                    "channel": "twilio",
                    "route": route,
                    "error": str(exc),
                    "blockingCount": len(report.blocking),
                    "recoverableCount": len(report.recoverable),
                },
            )
            return f"Twilio delivery failed ({route}): {exc}"

