    def _emit_smtp_events(self, report: AlertReport) -> list[str]:
        host = str(self.settings.alert_smtp_host or "").strip()
        username = str(self.settings.alert_smtp_username or "").strip()
        password = str(self.settings.alert_smtp_password or "").strip()
        from_address = str(self.settings.alert_smtp_from_address or "").strip()
        to_addresses = self._split_webhook_targets(str(self.settings.alert_smtp_to_addresses or ""))
        if not host or not username or not password or not from_address or not to_addresses:
            return []
        notes: list[str] = []
        if report.blocking:
            outcome = self._emit_single_smtp_message(
                host=host,
                port=int(self.settings.alert_smtp_port),
                username=username,
                password=password,
                from_address=from_address,
                to_addresses=to_addresses,
                use_tls=bool(self.settings.alert_smtp_use_tls),
                report=report,
                route="email:blocking",
                subject=f"[SEO-AD] Blocking alerts detected ({len(report.blocking)})",
                body=(
                    f"reportId={report.report_id}\n"
                    f"generatedAt={report.generated_at.isoformat()}\n"
                    f"blocking={len(report.blocking)}\n"
                    f"recoverable={len(report.recoverable)}\n"
                ),
            )
            if outcome:
                notes.append(outcome)
        if report.recoverable:
            outcome = self._emit_single_smtp_message(
                host=host,
                port=int(self.settings.alert_smtp_port),
                username=username,
                password=password,
                from_address=from_address,
                to_addresses=to_addresses,
                use_tls=bool(self.settings.alert_smtp_use_tls),
                report=report,
                route="email:recoverable",
                subject=f"[SEO-AD] Recoverable alerts detected ({len(report.recoverable)})",
                body=(
                    f"reportId={report.report_id}\n"
                    f"generatedAt={report.generated_at.isoformat()}\n"
                    f"blocking={len(report.blocking)}\n"
                    f"recoverable={len(report.recoverable)}\n"
                ),
            )
            if outcome:
                notes.append(outcome)
        return notes

    def _emit_single_smtp_message(
        self,
        *,
        host: str,
        port: int,
        username: str,
        password: str,
        from_address: str,
        to_addresses: list[str],
        use_tls: bool,
        report: AlertReport,
        route: str,
        subject: str,
        body: str,
    ) -> Optional[str]:
        message = EmailMessage()
        message["Subject"] = subject
        message["From"] = from_address
        message["To"] = ", ".join(to_addresses)
        message.set_content(body)
        try:
            timeout_seconds = max(0.5, int(self.settings.alert_webhook_timeout_ms) / 1000.0)
            with smtplib.SMTP(host, port, timeout=timeout_seconds) as client:
                client.ehlo()
                if use_tls:
                    client.starttls()
                    client.ehlo()
                client.login(username, password)
                client.send_message(message)
            for target in to_addresses:
                self._audit(
                    "workspace",
                    "",
                    "alerts.webhook.sent",
                    {
                        "reportId": report.report_id,
                        "target": target,
                        "channel": "email",
                        "route": route,
                        "statusCode": 250,
                        "blockingCount": len(report.blocking),
                        "recoverableCount": len(report.recoverable),
                    },
                )
            return f"Email delivered to {len(to_addresses)} recipient(s) ({route})."
        except Exception as exc:
            for target in to_addresses:
                self._audit(
                    "workspace",
                    "",
                    "alerts.webhook.failed",
                    {
                        "reportId": report.report_id,
                        "target": target,
                        "channel": "email",
                        "route": route,
                        "error": str(exc),
                        "blockingCount": len(report.blocking),
                        "recoverableCount": len(report.recoverable),
                    },
                )
            return f"Email delivery failed ({route}): {exc}"

    def _resolve_oncall_alerts(self, route: OnCallRoute, alerts: list[AlertItem]) -> list[AlertItem]:
        if not route.enabled:
            return []
        category_filter = {value for value in route.categories if value}
        severity_filter = {value for value in route.severities if value}
        provider_filter = {value for value in route.providers if value}
        matched: list[AlertItem] = []
        for item in alerts:
            if route.blocking is not None and item.blocking != route.blocking:
                continue
            if category_filter and item.category not in category_filter:
                continue
            if severity_filter and item.severity not in severity_filter:
                continue
            if provider_filter and item.provider not in provider_filter:
                continue
            matched.append(item)
        return matched

    def _emit_oncall_routes(self, report: AlertReport) -> list[str]:
        policy = self.get_oncall_policy()
        all_alerts = [*report.blocking, *report.recoverable]
        notes: list[str] = []
        emitted: set[tuple[str, str]] = set()
        for route in policy.routes:
            matched = self._resolve_oncall_alerts(route, all_alerts)
            if not matched:
                continue
            primary_report = AlertReport(
                report_id=report.report_id,
                generated_at=report.generated_at,
                blocking=[item for item in matched if item.blocking],
                recoverable=[item for item in matched if not item.blocking],
                notes=[f"oncallRoute={route.route_id}", "deliveryPhase=primary"],
            )
            for target in route.primary_channels:
                key = (target, f"oncall:{route.route_id}:primary")
                if key in emitted:
                    continue
                emitted.add(key)
                outcome = self._emit_single_alert_webhook(target, primary_report, route=f"oncall:{route.route_id}:primary")
                if outcome:
                    notes.append(outcome)
            if route.escalation_channels:
                escalation_report = primary_report.model_copy(
                    update={
                        "notes": [
                            f"oncallRoute={route.route_id}",
                            "deliveryPhase=escalation",
                            f"escalationAfterMinutes={route.escalation_after_minutes}",
                        ]
                    }
                )
                for target in route.escalation_channels:
                    key = (target, f"oncall:{route.route_id}:escalation")
                    if key in emitted:
                        continue
                    emitted.add(key)
                    outcome = self._emit_single_alert_webhook(target, escalation_report, route=f"oncall:{route.route_id}:escalation")
                    if outcome:
                        notes.append(outcome)
        return notes

    def _emit_single_alert_webhook(self, target: str, report: AlertReport, *, route: str) -> Optional[str]:
        target = str(target or "").strip()
        if not target:
            return None
        payload = {
            "reportId": report.report_id,
            "generatedAt": report.generated_at.isoformat(),
            "blockingCount": len(report.blocking),
            "recoverableCount": len(report.recoverable),
            "route": route,
            "blocking": [item.model_dump(mode="json", by_alias=True) for item in report.blocking],
            "recoverable": [item.model_dump(mode="json", by_alias=True) for item in report.recoverable],
        }
        try:
            if target.startswith("file://"):
                parsed = urlparse(target)
                path = Path(parsed.path)
                path.parent.mkdir(parents=True, exist_ok=True)
                with path.open("a", encoding="utf-8") as handle:
                    handle.write(json.dumps(payload, ensure_ascii=True) + "\n")
                self._audit(
                    "workspace",
                    "",
                    "alerts.webhook.sent",
                    {
                        "reportId": report.report_id,
                        "target": target,
                        "channel": "file",
                        "route": route,
                        "blockingCount": len(report.blocking),
                        "recoverableCount": len(report.recoverable),
                    },
                )
                return f"Webhook delivered to {target} ({route})."

            timeout_seconds = max(0.5, int(self.settings.alert_webhook_timeout_ms) / 1000.0)
            headers = {"Content-Type": "application/json", "Accept": "application/json", "User-Agent": "SEO-AD-AutoPilot/1.0"}
            token = str(self.settings.alert_webhook_token or "").strip()
            if token:
                headers["Authorization"] = f"Bearer {token}"
            request = Request(target, data=json.dumps(payload).encode("utf-8"), headers=headers, method="POST")
            with urlopen(request, timeout=timeout_seconds) as response:  # nosec - configurable outbound webhook
                status_code = int(getattr(response, "status", 200) or 200)
            self._audit(
                "workspace",
                "",
                "alerts.webhook.sent",
                {
                    "reportId": report.report_id,
                    "target": target,
                    "channel": "http",
                    "route": route,
                    "statusCode": status_code,
                    "blockingCount": len(report.blocking),
                    "recoverableCount": len(report.recoverable),
                },
            )
            return f"Webhook delivered to {target} ({route})."
        except Exception as exc:
            self._audit(
                "workspace",
                "",
                "alerts.webhook.failed",
                {
                    "reportId": report.report_id,
                    "target": target,
                    "route": route,
                    "error": str(exc),
                    "blockingCount": len(report.blocking),
                    "recoverableCount": len(report.recoverable),
                },
            )
            return f"Webhook delivery failed ({route}): {exc}"

    def _filter_alert_report(
        self,
        report: AlertReport,
        *,
        project_ids: Optional[list[str]] = None,
        categories: Optional[list[str]] = None,
        severities: Optional[list[str]] = None,
        providers: Optional[list[str]] = None,
        blocking: Optional[bool] = None,
    ) -> AlertReport:
        project_filter = {item for item in (project_ids or []) if item}
        category_filter = {item for item in (categories or []) if item}
        severity_filter = {item for item in (severities or []) if item}
        provider_filter = {item for item in (providers or []) if item}

        def matches(item: AlertItem) -> bool:
            if project_filter and not project_filter.intersection(set(item.project_ids)):
                return False
            if category_filter and item.category not in category_filter:
                return False
            if severity_filter and item.severity not in severity_filter:
                return False
            if provider_filter and item.provider not in provider_filter:
                return False
            if blocking is not None and item.blocking != blocking:
                return False
            return True

        return AlertReport(
            report_id=report.report_id,
            generated_at=report.generated_at,
            blocking=[item for item in report.blocking if matches(item)],
            recoverable=[item for item in report.recoverable if matches(item)],
            notes=report.notes,
        )

    def filter_alert_report(
        self,
        report: AlertReport,
        *,
        project_ids: Optional[list[str]] = None,
        categories: Optional[list[str]] = None,
        severities: Optional[list[str]] = None,
        providers: Optional[list[str]] = None,
        blocking: Optional[bool] = None,
    ) -> AlertReport:
        return self._filter_alert_report(
            report,
            project_ids=project_ids,
            categories=categories,
            severities=severities,
            providers=providers,
            blocking=blocking,
        )

    def build_alert_history_report(
        self,
        limit: int = 10,
        offset: int = 0,
        order: Literal["desc", "asc"] = "desc",
        cursor: Optional[str] = None,
        *,
        project_id: Optional[str] = None,
        project_ids: Optional[list[str]] = None,
        categories: Optional[list[str]] = None,
        severities: Optional[list[str]] = None,
        providers: Optional[list[str]] = None,
        blocking: Optional[bool] = None,
    ) -> AlertHistoryReport:
        normalized_order: Literal["desc", "asc"] = "asc" if str(order).lower() == "asc" else "desc"
        bounded_limit = max(1, min(int(limit), 100))
        bounded_offset = max(0, int(offset))
        normalized_project_id = str(project_id or "").strip() or None
        combined_project_ids = [str(item).strip() for item in (project_ids or []) if str(item).strip()]
        if normalized_project_id and normalized_project_id not in combined_project_ids:
            combined_project_ids.append(normalized_project_id)
        parsed_cursor: Optional[tuple[datetime, str]] = None
        if cursor:
            head, sep, tail = cursor.partition("|")
            if sep and head and tail:
                try:
                    parsed_cursor = (datetime.fromisoformat(head), tail)
                except ValueError:
                    parsed_cursor = None
        with self.database.session() as session:
            total = session.query(AlertSnapshotRow).count()
            query = select(AlertSnapshotRow)
            if parsed_cursor is not None:
                cursor_generated_at, cursor_id = parsed_cursor
                if normalized_order == "asc":
                    query = query.where(
                        or_(
                            AlertSnapshotRow.generated_at > cursor_generated_at,
                            and_(AlertSnapshotRow.generated_at == cursor_generated_at, AlertSnapshotRow.id > cursor_id),
                        )
                    )
                else:
                    query = query.where(
                        or_(
                            AlertSnapshotRow.generated_at < cursor_generated_at,
                            and_(AlertSnapshotRow.generated_at == cursor_generated_at, AlertSnapshotRow.id < cursor_id),
                        )
                    )
            if normalized_order == "asc":
                query = query.order_by(AlertSnapshotRow.generated_at.asc(), AlertSnapshotRow.id.asc())
            else:
                query = query.order_by(AlertSnapshotRow.generated_at.desc(), AlertSnapshotRow.id.desc())
            if parsed_cursor is None:
                query = query.offset(bounded_offset)
            rows = session.scalars(query.limit(bounded_limit + 1)).all()
            has_more = len(rows) > bounded_limit
            rows = rows[:bounded_limit]
            snapshots = [
                self._filter_alert_report(
                    AlertReport.model_validate(row.report_json),
                    project_ids=combined_project_ids or None,
                    categories=categories,
                    severities=severities,
                    providers=providers,
                    blocking=blocking,
                )
                for row in rows
            ]
            next_cursor = None
            if rows and has_more:
                tail_row = rows[-1]
                next_cursor = f"{tail_row.generated_at.isoformat()}|{tail_row.id}"
        if not snapshots:
            snapshots = [
                self._filter_alert_report(
                    self.build_alert_report(),
                    project_ids=combined_project_ids or None,
                    categories=categories,
                    severities=severities,
                    providers=providers,
                    blocking=blocking,
                )
            ]
            total = max(total, len(snapshots))
            has_more = False
            next_cursor = None
        return AlertHistoryReport(
            generated_at=utcnow(),
            project_id=normalized_project_id if normalized_project_id else (combined_project_ids[0] if len(combined_project_ids) == 1 else None),
            total=total,
            limit=bounded_limit,
            offset=bounded_offset,
            order=normalized_order,
            cursor=cursor,
            next_cursor=next_cursor,
            has_more=has_more,
            snapshots=snapshots,
        )

    def build_alert_delivery_report(
        self,
        limit: int = 50,
        route: Optional[str] = None,
        status: Optional[str] = None,
        project_id: Optional[str] = None,
    ) -> AlertDeliveryReport:
        bounded_limit = max(1, min(int(limit), 200))
        status_filter = str(status or "").strip().lower()
        route_filter = str(route or "").strip().lower()
        normalized_project_id = str(project_id or "").strip() or None
        entries: list[AlertDeliveryEntry] = []
        sent_count = 0
        failed_count = 0
        with self.database.session() as session:
            rows = session.scalars(
                select(AuditRow)
                .where(AuditRow.action.in_(["alerts.webhook.sent", "alerts.webhook.failed"]))
                .order_by(AuditRow.created_at.desc())
                .limit(max(200, bounded_limit * 4))
            ).all()
        for row in rows:
            payload = dict(row.payload_json or {})
            event_status = "sent" if row.action == "alerts.webhook.sent" else "failed"
            event_route = str(payload.get("route") or "unknown")
            if status_filter and event_status != status_filter:
                continue
            if route_filter and route_filter not in event_route.lower():
                continue
            snapshot_project_ids = self._alert_snapshot_project_ids(row)
            if normalized_project_id and normalized_project_id not in snapshot_project_ids:
                continue
            target = str(payload.get("target") or "")
            channel = str(payload.get("channel") or ("file" if target.startswith("file://") else "http"))
            status_code_raw = payload.get("statusCode")
            status_code = None
            if isinstance(status_code_raw, int):
                status_code = status_code_raw
            elif isinstance(status_code_raw, str) and status_code_raw.isdigit():
                status_code = int(status_code_raw)
            entries.append(
                AlertDeliveryEntry(
                    audit_id=row.id,
                    created_at=row.created_at,
                    status=event_status,
                    route=event_route,
                    target=target,
                    channel=channel,
                    report_id=str(payload.get("reportId") or "") or None,
                    project_ids=snapshot_project_ids,
                    blocking_count=int(payload.get("blockingCount") or 0),
                    recoverable_count=int(payload.get("recoverableCount") or 0),
                    status_code=status_code,
                    error=str(payload.get("error") or "") or None,
                    span_id=str(payload.get("spanId") or "") or None,
                    trace_id=str(payload.get("traceId") or "") or None,
                )
            )
            if event_status == "sent":
                sent_count += 1
            else:
                failed_count += 1
                if len(entries) >= bounded_limit:
                    break
        return AlertDeliveryReport(
            generated_at=utcnow(),
            project_id=normalized_project_id,
            total=len(entries),
            sent=sent_count,
            failed=failed_count,
            entries=entries,
        )

    def build_alert_emit_status_report(self, project_id: Optional[str] = None) -> AlertEmitStatusReport:
        now = utcnow()
        cutoff = now - timedelta(hours=24)
        cooldown_seconds = max(0, int(self.settings.alert_emit_cooldown_seconds))
        normalized_project_id = str(project_id or "").strip() or None
        executed_count = 0
        suppressed_count = 0
        last_executed_at = None
        last_suppressed_at = None
        last_signature = None

        with self.database.session() as session:
            rows = session.scalars(
                select(AuditRow)
                .where(AuditRow.action.in_(["alerts.emit.executed", "alerts.emit.suppressed"]))
                .order_by(AuditRow.created_at.desc())
                .limit(500)
            ).all()
        for row in rows:
            created_at = row.created_at
            if created_at.tzinfo is None:
                created_at = created_at.replace(tzinfo=timezone.utc)
            payload = dict(row.payload_json or {})
            snapshot_project_ids = self._alert_snapshot_project_ids(row)
            if normalized_project_id and normalized_project_id not in snapshot_project_ids:
                continue
            if last_signature is None:
                last_signature = str(payload.get("signature") or "") or None
            if row.action == "alerts.emit.executed" and last_executed_at is None:
                last_executed_at = created_at
            if row.action == "alerts.emit.suppressed" and last_suppressed_at is None:
                last_suppressed_at = created_at
            if created_at >= cutoff:
                if row.action == "alerts.emit.executed":
                    executed_count += 1
                elif row.action == "alerts.emit.suppressed":
                    suppressed_count += 1

        notes: list[str] = []
        if cooldown_seconds <= 0:
            notes.append("Alert emit cooldown is disabled (0s).")
        else:
            notes.append(f"Alert emit cooldown is enabled ({cooldown_seconds}s).")
        if suppressed_count > 0:
            notes.append("Cooldown suppressed one or more duplicate alert emissions in the last 24h.")
        return AlertEmitStatusReport(
            cooldown_seconds=cooldown_seconds,
            project_id=normalized_project_id,
            executed_count_24h=executed_count,
            suppressed_count_24h=suppressed_count,
            last_executed_at=last_executed_at,
            last_suppressed_at=last_suppressed_at,
            last_signature=last_signature,
            notes=notes,
        )

    def build_alert_emit_history_report(
        self,
        *,
        limit: int = 50,
        status: Optional[Literal["executed", "suppressed"]] = None,
        project_id: Optional[str] = None,
    ) -> AlertEmitHistoryReport:
        bounded_limit = max(1, min(int(limit), 200))
        status_filter = str(status or "").strip().lower()
        normalized_project_id = str(project_id or "").strip() or None
        entries: list[AlertEmitHistoryEntry] = []
        executed_count = 0
        suppressed_count = 0
        with self.database.session() as session:
            rows = session.scalars(
                select(AuditRow)
                .where(AuditRow.action.in_(["alerts.emit.executed", "alerts.emit.suppressed"]))
                .order_by(AuditRow.created_at.desc())
                .limit(max(200, bounded_limit * 4))
            ).all()
        for row in rows:
            payload = dict(row.payload_json or {})
            event_status = "executed" if row.action == "alerts.emit.executed" else "suppressed"
            if status_filter and event_status != status_filter:
                continue
            snapshot_project_ids = self._alert_snapshot_project_ids(row)
            if normalized_project_id and normalized_project_id not in snapshot_project_ids:
                continue
            created_at = row.created_at
            if created_at.tzinfo is None:
                created_at = created_at.replace(tzinfo=timezone.utc)
            entries.append(
                AlertEmitHistoryEntry(
                    audit_id=row.id,
                    created_at=created_at,
                    status=event_status,
                    signature=str(payload.get("signature") or "") or None,
                    cooldown_seconds=max(0, int(payload.get("cooldownSeconds") or 0)),
                    blocking_count=max(0, int(payload.get("blockingCount") or 0)),
                    recoverable_count=max(0, int(payload.get("recoverableCount") or 0)),
                    project_ids=snapshot_project_ids,
                    span_id=str(payload.get("spanId") or "") or None,
                    trace_id=str(payload.get("traceId") or "") or None,
                )
            )
            if event_status == "executed":
                executed_count += 1
            else:
                suppressed_count += 1
            if len(entries) >= bounded_limit:
                break
        return AlertEmitHistoryReport(
            project_id=normalized_project_id,
            total=len(entries),
            executed=executed_count,
            suppressed=suppressed_count,
            entries=entries,
        )

    def _alert_snapshot_project_ids(self, audit_row: AuditRow) -> list[str]:
        report_id = str((audit_row.payload_json or {}).get("reportId") or "").strip()
        if not report_id:
            return []
        with self.database.session() as session:
            snapshot = session.get(AlertSnapshotRow, report_id)
        if snapshot is None:
            return []
        return self._alert_report_project_ids(snapshot.report_json)

    def _alert_report_project_ids(self, report_json: Any) -> list[str]:
        if not isinstance(report_json, dict):
            return []
        project_ids: set[str] = set()
        for section_name in ("blocking", "recoverable"):
            items = report_json.get(section_name) or []
            if not isinstance(items, list):
                continue
            for item in items:
                if not isinstance(item, dict):
                    continue
                raw_project_ids = item.get("projectIds") or item.get("project_ids") or []
                if isinstance(raw_project_ids, list):
                    for value in raw_project_ids:
                        project_id = str(value).strip()
                        if project_id:
                            project_ids.add(project_id)
                raw_project_id = item.get("projectId") or item.get("project_id")
                if raw_project_id:
                    project_id = str(raw_project_id).strip()
                    if project_id:
                        project_ids.add(project_id)
        return sorted(project_ids)

    def _failure_category(self, code: str) -> str:
        normalized = code.upper()
        if "AUTH" in normalized:
            return "auth"
        if "ANTI_BOT" in normalized or "CHALLENGE" in normalized:
            return "permission"
        if "PERMISSION" in normalized:
            return "permission"
        if "RATE_LIMIT" in normalized or "RATELIMIT" in normalized:
            return "rate_limit"
        if "NETWORK" in normalized or "TIMEOUT" in normalized:
            return "network"
        if "VALIDATION" in normalized:
            return "validation"
        if normalized.startswith("CONFIG_") or "_MISSING_" in normalized:
            return "config"
        if "UNAVAILABLE" in normalized:
            return "unavailable"
        return "other"

    def build_connector_failure_report(self, project_id: Optional[str] = None) -> ConnectorFailureReport:
        buckets: dict[str, dict[str, Any]] = {}
        active_projects: set[str] = set()
        seen_occurrences: set[tuple[str, str, str]] = set()
        normalized_project_id = str(project_id or "").strip() or None

        def _normalize_timestamp(value: Optional[datetime]) -> datetime:
            normalized = value or utcnow()
            if normalized.tzinfo is None:
                normalized = normalized.replace(tzinfo=timezone.utc)
            return normalized

        with self.database.session() as session:
            task_query = select(TaskRow).order_by(TaskRow.updated_at.desc())
            if normalized_project_id:
                task_query = task_query.where(TaskRow.project_id == normalized_project_id)
            rows = session.scalars(task_query).all()
            active_projects = {row.project_id for row in rows}
            for row in rows:
                ingestion_payload = (row.analysis_json or {}).get("ingestionReport") or {}
                for evidence in ingestion_payload.get("evidence", []) or []:
                    code = str(evidence.get("failureCode") or "").strip()
                    if not code:
                        continue
                    provider = str(evidence.get("provider") or "unknown")
                    occurrence_key = (row.project_id, provider, code)
                    if occurrence_key in seen_occurrences:
                        continue
                    seen_occurrences.add(occurrence_key)
                    bucket = buckets.setdefault(
                        code,
                        {
                            "category": self._failure_category(code),
                            "count": 0,
                            "providers": set(),
                            "projects": set(),
                            "last_seen_at": _normalize_timestamp(row.updated_at or row.created_at),
                        },
                    )
                    bucket["count"] += 1
                    bucket["providers"].add(provider)
                    bucket["projects"].add(row.project_id)
                    bucket["last_seen_at"] = max(
                        _normalize_timestamp(bucket["last_seen_at"]),
                        _normalize_timestamp(row.updated_at or row.created_at),
                    )

                deployment_payload = row.deployment_json or {}
                deployment_code = str(deployment_payload.get("failureCode") or "").strip()
                if deployment_code:
                    deployment_provider = str(deployment_payload.get("mode") or "deploy")
                    occurrence_key = (row.project_id, deployment_provider, deployment_code)
                    if occurrence_key in seen_occurrences:
                        continue
                    seen_occurrences.add(occurrence_key)
                    bucket = buckets.setdefault(
                        deployment_code,
                        {
                            "category": self._failure_category(deployment_code),
                            "count": 0,
                            "providers": set(),
                            "projects": set(),
                            "last_seen_at": _normalize_timestamp(row.updated_at or row.created_at),
                        },
                    )
                    bucket["count"] += 1
                    bucket["providers"].add(deployment_provider)
                    bucket["projects"].add(row.project_id)
                    bucket["last_seen_at"] = max(
                        _normalize_timestamp(bucket["last_seen_at"]),
                        _normalize_timestamp(row.updated_at or row.created_at),
                    )

            project_query = select(ProjectRow).order_by(ProjectRow.updated_at.desc())
            if normalized_project_id:
                project_query = project_query.where(ProjectRow.id == normalized_project_id)
            projects = session.scalars(project_query).all()
            for project in projects:
                intake = self._project_intake(project)
                connections = self._load_project_connections(session, project.id, intake)
                for connection in connections:
                    code = str(connection.details.get("errorCode") or "").strip()
                    if not code:
                        continue
                    provider = connection.provider.value
                    occurrence_key = (project.id, provider, code)
                    if occurrence_key in seen_occurrences:
                        continue
                    seen_occurrences.add(occurrence_key)
                    bucket = buckets.setdefault(
                        code,
                        {
                            "category": self._failure_category(code),
                            "count": 0,
                            "providers": set(),
                            "projects": set(),
                            "last_seen_at": _normalize_timestamp(project.updated_at or project.created_at),
                        },
                    )
                    bucket["count"] += 1
                    bucket["providers"].add(provider)
                    bucket["projects"].add(project.id)
                    active_projects.add(project.id)
                    observed_at = connection.last_checked_at or connection.last_error_at or connection.last_synced_at
                    if observed_at is None:
                        observed_at = project.updated_at or project.created_at
                    bucket["last_seen_at"] = max(
                        _normalize_timestamp(bucket["last_seen_at"]),
                        _normalize_timestamp(observed_at),
                    )

        entries = [
            ConnectorFailureEntry(
                failure_code=code,
                category=data["category"],
                count=data["count"],
                providers=sorted(data["providers"]),
                affected_projects=len(data["projects"]),
                project_ids=sorted(data["projects"]),
                last_seen_at=data["last_seen_at"],
            )
            for code, data in sorted(buckets.items(), key=lambda item: (-item[1]["count"], item[0]))
        ]
        return ConnectorFailureReport(
            report_id=new_id("conn-fail"),
            project_id=normalized_project_id,
            total_failures=sum(entry.count for entry in entries),
            active_project_count=len(active_projects),
            entries=entries,
            notes=[
                "Failure codes aggregate connector reads and deployment writebacks.",
                "Use category and provider columns to prioritize remediation by source.",
            ],
        )

    def retry_connectors(self, request: ConnectorRetryRequest) -> ConnectorRetryResult:
        with trace_span("connectors.retry", {"requestedCategories": ",".join(request.categories or ["network"])}):
            categories = set(request.categories or ["network"])
            provider_filter = set(item.value for item in request.providers)
            project_filter = set(request.project_ids)
            max_retries = max(1, int(request.max_retries))
            attempted = 0
            refreshed = 0
            skipped = 0
            failed = 0
            notes: list[str] = []

            with self.database.session() as session:
                project_rows = session.scalars(select(ProjectRow).order_by(ProjectRow.updated_at.desc())).all()

            for row in project_rows:
                if project_filter and row.id not in project_filter:
                    continue
                intake = self._project_intake(row)
                with self.database.session() as session:
                    connections = self._load_project_connections(session, row.id, intake)
                for connection in connections:
                    if attempted >= max_retries:
                        notes.append(f"Reached max_retries={max_retries}.")
                        result = ConnectorRetryResult(
                            attempted=attempted,
                            refreshed=refreshed,
                            skipped=skipped,
                            failed=failed,
                            categories=sorted(categories),
                            notes=notes,
                        )
                        self._audit(
                            "workspace",
                            "",
                            "connectors.retry",
                            {
                                "actor": "operator",
                                "spanId": new_id("span"),
                                "attempted": result.attempted,
                                "refreshed": result.refreshed,
                                "failed": result.failed,
                                "skipped": result.skipped,
                                "categories": result.categories,
                                "projectIds": sorted(project_filter) if project_filter else [item.id for item in project_rows],
                                "alertIds": [],
                                "notes": result.notes[:5],
                                "strictProviders": bool(self.settings.strict_providers),
                            },
                        )
                        set_span_attributes(
                            {
                                "connectors.retry.attempted": attempted,
                                "connectors.retry.refreshed": refreshed,
                                "connectors.retry.failed": failed,
                                "connectors.retry.skipped": skipped,
                            }
                        )
                        return result
                    if provider_filter and connection.provider.value not in provider_filter:
                        skipped += 1
                        continue
                    error_code = str(connection.details.get("errorCode") or "").strip()
                    if not error_code:
                        skipped += 1
                        continue
                    category = self._failure_category(error_code)
                    if category not in categories:
                        skipped += 1
                        continue
                    is_playwright_antibot_manual_block = (
                        connection.provider == ConnectorKind.playwright
                        and (
                            error_code.upper() in {"PLAYWRIGHT_ANTI_BOT_COOLDOWN", "PLAYWRIGHT_ANTI_BOT_BLOCKED"}
                            or bool(connection.details.get("manualInterventionRequired"))
                        )
                    )
                    if is_playwright_antibot_manual_block:
                        skipped += 1
                        notes.append(
                            f"{row.id}:{connection.provider.value} skipped ({error_code or 'PLAYWRIGHT_ANTI_BOT_BLOCKED'}) until manual intervention clears anti-bot block"
                        )
                        continue
                    retryable = bool(connection.details.get("retryable", False))
                    if request.retryable_only and not retryable:
                        skipped += 1
                        continue
                    attempted += 1
                    try:
                        result = self.refresh_project_connector(row.id, connection.provider)
                        if result.status == ConnectorStatus.connected:
                            refreshed += 1
                        else:
                            failed += 1
                            notes.append(
                                f"{row.id}:{connection.provider.value} -> {result.status.value} ({result.evidence.failure_code or 'no-code'})"
                            )
                    except Exception as exc:
                        failed += 1
                        notes.append(f"{row.id}:{connection.provider.value} refresh failed: {exc}")

            result = ConnectorRetryResult(
                attempted=attempted,
                refreshed=refreshed,
                skipped=skipped,
                failed=failed,
                categories=sorted(categories),
                notes=notes,
            )
            self._audit(
                "workspace",
                "",
                "connectors.retry",
                {
                    "actor": "operator",
                    "spanId": new_id("span"),
                    "attempted": result.attempted,
                    "refreshed": result.refreshed,
                    "failed": result.failed,
                    "skipped": result.skipped,
                    "categories": result.categories,
                    "projectIds": sorted(project_filter) if project_filter else [item.id for item in project_rows],
                    "alertIds": [],
                    "notes": result.notes[:5],
                    "strictProviders": bool(self.settings.strict_providers),
                },
            )
            set_span_attributes(
                {
                    "connectors.retry.attempted": result.attempted,
                    "connectors.retry.refreshed": result.refreshed,
                    "connectors.retry.failed": result.failed,
                    "connectors.retry.skipped": result.skipped,
                }
            )
            return result

    def refresh_market_evidence_connectors(self, request: BulkMarketEvidenceRefreshRequest) -> BulkMarketEvidenceRefreshResult:
        selected_providers = {item for item in request.providers}
        max_providers = max(1, int(request.max_providers))
        provider_order = [ConnectorKind.trend, ConnectorKind.news, ConnectorKind.qa]
        provider_candidates = [provider for provider in provider_order if not selected_providers or provider in selected_providers][:max_providers]
        project_scope = [item.strip() for item in request.project_ids if item and item.strip()]

        provider_results: list[BulkConnectorRefreshResult] = []
        for provider in provider_candidates:
            provider_results.append(
                self.refresh_projects_connector(
                    provider,
                    BulkConnectorRefreshRequest(project_ids=project_scope),
                )
            )

        refreshed_count = sum(item.refreshed_count for item in provider_results)
        skipped_project_count = sum(len(item.skipped_project_ids) for item in provider_results)
        notes: list[str] = []
        if not provider_results:
            notes.append("No market evidence providers matched the current filter.")
        else:
            notes.append(f"Refreshed {len(provider_results)} market evidence provider(s) across workspace projects.")
            if not project_scope:
                notes.append("Empty project scope means all workspace projects were refreshed.")
        result = BulkMarketEvidenceRefreshResult(
            provider_count=len(provider_results),
            refreshed_count=refreshed_count,
            skipped_project_count=skipped_project_count,
            provider_results=provider_results,
            notes=notes,
        )
        self._audit(
            "workspace",
            "",
            "connectors.bulk.market_evidence.refreshed",
            {
                "providerCount": result.provider_count,
                "providers": [item.provider.value for item in provider_results],
                "refreshedCount": result.refreshed_count,
                "skippedProjectCount": result.skipped_project_count,
                "projectScopeCount": len(project_scope),
                "projectIds": project_scope,
                "maxProviders": max_providers,
            },
        )
        return result

    def retry_visual_regressions(self, request: VisualRegressionRetryRequest) -> VisualRegressionRetryResult:
        categories = set(request.categories or ["network", "rate_limit", "unavailable"])
        max_cases = max(1, int(request.max_cases))
        target_project_ids = {str(item).strip() for item in request.project_ids if str(item).strip()}
        with trace_span("visual_regressions.retry", {"requestedCategories": ",".join(sorted(categories))}):
            initial_runs = self.build_visual_regression_runs_report()
            latest = initial_runs.runs[0] if initial_runs.runs else None
            if latest is None:
                result = VisualRegressionRetryResult(
                    attempted=0,
                    rerun_passed=0,
                    rerun_failed=0,
                    skipped=0,
                    categories=sorted(categories),
                    run_id=None,
                    notes=["No visual regression run available."],
                )
                set_span_attributes(
                    {
                        "visual_regressions.retry.attempted": 0,
                        "visual_regressions.retry.rerun_passed": 0,
                        "visual_regressions.retry.rerun_failed": 0,
                        "visual_regressions.retry.skipped": 0,
                    }
                )
                return result

            selected_sample_ids: list[str] = []
            skipped = 0
            for case in latest.cases:
                if target_project_ids and case.project_id not in target_project_ids:
                    skipped += 1
                    continue
                if len(selected_sample_ids) >= max_cases:
                    skipped += 1
                    continue
                if case.provider_status == "connected":
                    skipped += 1
                    continue
                category, _ = self._visual_failure_category(case)
                if category not in categories:
                    skipped += 1
                    continue
                if request.retryable_only and not self._visual_failure_retryable(category):
                    skipped += 1
                    continue
                selected_sample_ids.append(case.sample_id)

            attempted = len(selected_sample_ids)
            if attempted == 0:
                result = VisualRegressionRetryResult(
                    attempted=0,
                    rerun_passed=0,
                    rerun_failed=0,
                    skipped=skipped,
                    categories=sorted(categories),
                    run_id=None,
                    notes=["No visual regression case matched retry filters."],
                )
                set_span_attributes(
                    {
                        "visual_regressions.retry.attempted": 0,
                        "visual_regressions.retry.rerun_passed": 0,
                        "visual_regressions.retry.rerun_failed": 0,
                        "visual_regressions.retry.skipped": skipped,
                    }
                )
                return result

            rerun_report = self.build_visual_regression_runs_report()
            rerun = rerun_report.runs[0] if rerun_report.runs else None
            rerun_passed = 0
            rerun_failed = 0
            if rerun is not None:
                selected_set = set(selected_sample_ids)
                for case in rerun.cases:
                    if case.sample_id not in selected_set:
                        continue
                    if case.passed:
                        rerun_passed += 1
                    else:
                        rerun_failed += 1

            result = VisualRegressionRetryResult(
                attempted=attempted,
                rerun_passed=rerun_passed,
                rerun_failed=rerun_failed,
                skipped=skipped,
                categories=sorted(categories),
                run_id=rerun.run_id if rerun is not None else None,
                notes=[
                    f"Selected {attempted} visual regression cases for retry.",
                    f"Re-run runId={rerun.run_id if rerun is not None else 'n/a'}",
                ],
            )
            self._audit(
                "workspace",
                "",
                "visual_regressions.retry",
                {
                    "actor": "operator",
                    "spanId": new_id("span"),
                    "attempted": result.attempted,
                    "rerunPassed": result.rerun_passed,
                    "rerunFailed": result.rerun_failed,
                    "skipped": result.skipped,
                    "categories": result.categories,
                    "projectIds": sorted(target_project_ids)
                    if target_project_ids
                    else [str(item.project_id) for item in latest.cases if str(item.project_id or "").strip()],
                    "runId": result.run_id,
                    "notes": result.notes[:5],
                },
            )
            set_span_attributes(
                {
                    "visual_regressions.retry.attempted": result.attempted,
                    "visual_regressions.retry.rerun_passed": result.rerun_passed,
                    "visual_regressions.retry.rerun_failed": result.rerun_failed,
                    "visual_regressions.retry.skipped": result.skipped,
                }
            )
            return result

    def get_visual_regression_retry_history(
        self,
        limit: int = 10,
        *,
        project_id: Optional[str] = None,
    ) -> VisualRegressionRetryHistoryReport:
        normalized_project_id = (project_id or "").strip() or None
        with self.database.session() as session:
            rows = session.scalars(
                select(AuditRow).where(AuditRow.action == "visual_regressions.retry").order_by(AuditRow.created_at.desc())
            ).all()
        entries: list[VisualRegressionRetryHistoryEntry] = []
        for row in rows[: max(1, limit)]:
            payload = row.payload_json or {}
            payload_project_ids = [str(item) for item in payload.get("projectIds", []) if str(item).strip()]
            if normalized_project_id is not None and normalized_project_id not in payload_project_ids:
                continue
            entries.append(
                VisualRegressionRetryHistoryEntry(
                    audit_id=row.id,
                    actor=row.actor,
                    created_at=row.created_at,
                    attempted=int(payload.get("attempted", 0)),
                    rerun_passed=int(payload.get("rerunPassed", 0)),
                    rerun_failed=int(payload.get("rerunFailed", 0)),
                    skipped=int(payload.get("skipped", 0)),
                    categories=[str(item) for item in payload.get("categories", [])],
                    project_id=(payload_project_ids[0] if payload_project_ids else None),
                    project_ids=payload_project_ids,
                    run_id=str(payload.get("runId") or "") or None,
                    notes=[str(item) for item in payload.get("notes", [])],
                    span_id=str(payload.get("spanId") or "") or None,
                )
            )
            if len(entries) >= max(1, int(limit)):
                break
        return VisualRegressionRetryHistoryReport(project_id=normalized_project_id, entries=entries)

    def get_visual_regression_run_history(
        self,
        limit: int = 20,
        *,
        project_id: Optional[str] = None,
        strict_mode: Optional[bool] = None,
    ) -> VisualRegressionRunHistoryReport:
        normalized_project_id = (project_id or "").strip() or None
        with self.database.session() as session:
            rows = session.scalars(
                select(AuditRow).where(AuditRow.action == "visual_regressions.run.executed").order_by(AuditRow.created_at.desc())
            ).all()
        entries: list[VisualRegressionRunHistoryEntry] = []
        for row in rows[: max(1, limit)]:
            payload = row.payload_json or {}
            payload_project_ids = [str(item) for item in payload.get("projectIds", []) if str(item).strip()]
            if normalized_project_id is not None and normalized_project_id not in payload_project_ids:
                continue
            payload_strict_mode = bool(payload.get("strictMode", False))
            if strict_mode is not None and payload_strict_mode != strict_mode:
                continue
            entries.append(
                VisualRegressionRunHistoryEntry(
                    audit_id=row.id,
                    actor=row.actor,
                    created_at=row.created_at,
                    strict_mode=payload_strict_mode,
                    project_id=(payload_project_ids[0] if payload_project_ids else None),
                    project_ids=payload_project_ids,
                    max_cases=int(payload.get("maxCases", 0)),
                    run_count=int(payload.get("runCount", 0)),
                    case_count=int(payload.get("caseCount", 0)),
                    run_ids=[str(item) for item in payload.get("runIds", []) if str(item).strip()],
                    notes=[str(item) for item in payload.get("notes", []) if str(item).strip()],
                )
            )
            if len(entries) >= max(1, int(limit)):
                break
        return VisualRegressionRunHistoryReport(
            project_id=normalized_project_id,
            strict_mode=strict_mode,
            entries=entries,
        )

    def build_visual_regression_remediation_report(self, project_id: Optional[str] = None) -> VisualRegressionRemediationReport:
        normalized_project_id = str(project_id or "").strip() or None
        runs = self.build_visual_regression_runs_report(project_id=normalized_project_id)
        latest = runs.runs[0] if runs.runs else None
        if latest is None:
            return VisualRegressionRemediationReport(
                report_id=new_id("visual-remediate"),
                project_id=normalized_project_id,
                item_count=0,
                items=[],
                notes=["No visual regression run available."],
            )

        buckets: dict[str, dict[str, Any]] = {}
        for case in latest.cases:
            if case.passed and not case.visual_farm_strict_blocked:
                continue
            failure_code = str(case.provider_failure_code or "").strip()
            if not failure_code:
                if case.visual_farm_strict_blocked:
                    failure_code = "VISUAL_REGRESSION_STRICT_BLOCKED"
                elif case.provider_status == "fallback":
                    failure_code = "VISUAL_FARM_FALLBACK"
                elif case.provider_status == "not_configured":
                    failure_code = "VISUAL_FARM_NOT_CONFIGURED"
                elif case.provider_status == "failed":
                    failure_code = "VISUAL_FARM_FAILED"
                else:
                    failure_code = "VISUAL_REGRESSION_FAILED"
            normalized = failure_code.upper()
            category = self._failure_category(normalized)
            bucket = buckets.setdefault(
                normalized,
                {
                    "category": category,
                    "projectIds": set(),
                    "count": 0,
                    "strictBlocked": False,
                },
            )
            if case.project_id:
                bucket["projectIds"].add(case.project_id)
            bucket["count"] += 1
            bucket["strictBlocked"] = bool(bucket["strictBlocked"] or case.visual_farm_strict_blocked)

        items: list[VisualRegressionRemediationItem] = []
        for failure_code, bucket in buckets.items():
            category = str(bucket["category"])
            is_blocking = bool(bucket["strictBlocked"] or category in {"auth", "config", "permission"})
            priority: Literal["p0", "p1", "p2", "p3"]
            action: str
            rationale: str
            quick_action_path: str
            quick_action_label: str
            if category in {"auth", "config", "permission"}:
                priority = "p0"
                action = "修复视觉农场凭据/权限配置并重新执行视觉回归。"
                rationale = "认证与配置问题会导致视觉证据不可用，严格模式下会阻断发布。"
                quick_action_path = "/settings?focus=visual-farm"
                quick_action_label = "修复视觉农场配置"
            elif category in {"network", "rate_limit", "unavailable"}:
                priority = "p1"
                action = "按网络/限流场景发起批量重试，并观察失败是否收敛。"
                rationale = "网络与限流类问题通常是可恢复故障，优先执行重试。"
                quick_action_path = "/quality?focus=visual-regressions"
                quick_action_label = "批量重试视觉回归"
            elif category == "validation":
                priority = "p1"
                action = "检查视觉任务输入参数与页面基线数据，修正后重跑。"
                rationale = "参数或数据格式错误会导致回归任务稳定失败。"
                quick_action_path = "/quality?focus=visual-regressions"
                quick_action_label = "检查回归参数"
            else:
                priority = "p2"
                action = "人工复核失败样本并执行定向重试。"
                rationale = "未知失败需要先定位再执行自动化恢复。"
                quick_action_path = "/quality?focus=visual-regressions"
                quick_action_label = "查看失败样本"
            retry_template = VisualRegressionRetryRequest(
                categories=[category], retryable_only=not is_blocking, max_cases=max(1, int(bucket["count"]))
            )
            project_ids = sorted(str(item) for item in bucket["projectIds"] if str(item))
            items.append(
                VisualRegressionRemediationItem(
                    remediation_id=new_id("visual-remediate"),
                    category=category,  # type: ignore[arg-type]
                    failure_code=failure_code,
                    priority=priority,
                    action=action,
                    rationale=rationale,
                    blocking=is_blocking,
                    affected_cases=int(bucket["count"]),
                    affected_projects=len(project_ids),
                    project_ids=project_ids,
                    quick_action_path=quick_action_path,
                    quick_action_label=quick_action_label,
                    retry_request_template=retry_template,
                )
            )

        items.sort(key=lambda item: (item.priority, -item.affected_cases, item.failure_code))
        return VisualRegressionRemediationReport(
            report_id=new_id("visual-remediate-report"),
            project_id=normalized_project_id,
            item_count=len(items),
            items=items,
            notes=[
                "每条 remediation 都包含可直接提交给 /api/visual-regressions/retry 的参数模板。",
                "阻断类问题建议先修配置再重试，避免重复失败。",
            ],
        )

